//! kotoba-shell — Tauri-shaped app shell planning over kotoba capabilities.
//!
//! This crate is the first executable slice of `docs/ADR-kotoba-shell-aiueos-safe-kotoba.md`.
//! It gives the shell line something concrete and testable: parse an EDN app
//! manifest, admit safe Kotoba components through the deny-by-default Kotoba
//! compiler profile, and generate native shell artifacts from the same
//! capability plan.

use std::collections::{BTreeMap, BTreeSet};
use std::fs::{File, OpenOptions};
use std::io::Write;
use std::path::{Path, PathBuf};
use std::process::{Command, Stdio};
use std::time::{Duration, Instant, SystemTime, UNIX_EPOCH};

use anyhow::{anyhow, bail, Context, Result};
use kotoba_edn::{EdnValue, Keyword};
use serde::{Deserialize, Serialize};
use sha2::{Digest, Sha256};

const SAFE_KOTOBA_ADMISSION_GATE: &str = "selfhost/kotoba";
const LEGACY_SAFE_KOTOBA_ADMISSION_GATE: &str = "selfhost/kotoba-clj";

fn is_safe_kotoba_admission_gate(value: &str) -> bool {
    value == SAFE_KOTOBA_ADMISSION_GATE || value == LEGACY_SAFE_KOTOBA_ADMISSION_GATE
}

fn safe_kotoba_admission_gate_expected() -> String {
    format!("{SAFE_KOTOBA_ADMISSION_GATE} (legacy {LEGACY_SAFE_KOTOBA_ADMISSION_GATE})")
}

