pub fn evidence_edn_string<T: Serialize>(report: &T) -> Result<String> {
    let json = serde_json::to_value(report)?;
    Ok(kotoba_edn::to_string_pretty(&json_to_edn(&json)))
}

fn json_to_edn(value: &serde_json::Value) -> EdnValue {
    match value {
        serde_json::Value::Null => EdnValue::Nil,
        serde_json::Value::Bool(value) => EdnValue::Bool(*value),
        serde_json::Value::Number(value) => {
            if let Some(int) = value.as_i64() {
                EdnValue::Integer(int)
            } else if let Some(uint) = value.as_u64() {
                i64::try_from(uint)
                    .map(EdnValue::Integer)
                    .unwrap_or_else(|_| EdnValue::BigInt(uint.to_string()))
            } else {
                EdnValue::float(value.as_f64().unwrap_or_default())
            }
        }
        serde_json::Value::String(value) => EdnValue::String(value.clone()),
        serde_json::Value::Array(values) => {
            EdnValue::Vector(values.iter().map(json_to_edn).collect())
        }
        serde_json::Value::Object(values) => EdnValue::Map(
            values
                .iter()
                .map(|(key, value)| (EdnValue::Keyword(Keyword::parse(key)), json_to_edn(value)))
                .collect(),
        ),
    }
}

fn edn_to_json(value: &EdnValue) -> serde_json::Value {
    match value {
        EdnValue::Nil => serde_json::Value::Null,
        EdnValue::Bool(value) => serde_json::Value::Bool(*value),
        EdnValue::Integer(value) => serde_json::Value::Number((*value).into()),
        EdnValue::BigInt(value) | EdnValue::BigDec(value) => {
            serde_json::Value::String(value.clone())
        }
        EdnValue::Float(value) => serde_json::Number::from_f64(value.0)
            .map(serde_json::Value::Number)
            .unwrap_or(serde_json::Value::Null),
        EdnValue::Char(value) => serde_json::Value::String(value.to_string()),
        EdnValue::String(value) => serde_json::Value::String(value.clone()),
        EdnValue::Symbol(value) => serde_json::Value::String(value.to_qualified()),
        EdnValue::Keyword(value) => serde_json::Value::String(value.to_qualified()),
        EdnValue::List(values) | EdnValue::Vector(values) => {
            serde_json::Value::Array(values.iter().map(edn_to_json).collect())
        }
        EdnValue::Set(values) => serde_json::Value::Array(values.iter().map(edn_to_json).collect()),
        EdnValue::Map(values) => serde_json::Value::Object(
            values
                .iter()
                .map(|(key, value)| (edn_map_key(key), edn_to_json(value)))
                .collect(),
        ),
        EdnValue::Tagged { tag, value } => serde_json::json!({
            "tag": tag.to_qualified(),
            "value": edn_to_json(value)
        }),
    }
}

fn edn_map_key(value: &EdnValue) -> String {
    match value {
        EdnValue::Keyword(value) => value.to_qualified(),
        EdnValue::Symbol(value) => value.to_qualified(),
        EdnValue::String(value) => value.clone(),
        other => kotoba_edn::to_string(other),
    }
}

