pub fn coverage_report() -> String {
    let assessment = coverage_assessment();
    let mut out = String::new();
    out.push_str("kotoba-shell coverage against Tauri v2 baseline\n\n");
    out.push_str(&format!("Maturity: {}\n", assessment.maturity));
    out.push_str(&format!(
        "Estimated functional coverage: {}%\n",
        assessment.functional_coverage_percent
    ));
    out.push_str(&format!(
        "Estimated release maturity: {}%\n\n",
        assessment.release_maturity_percent
    ));
    out.push_str("Categories:\n");
    for category in &assessment.categories {
        out.push_str(&format!(
            "  [{mark}] {}: functionality {}%, maturity {}%\n",
            category.label,
            category.score_percent,
            category.maturity_percent,
            mark = coverage_status_mark(&category.status)
        ));
        for evidence in &category.evidence {
            out.push_str(&format!("      ok: {evidence}\n"));
        }
        for gap in &category.gaps {
            out.push_str(&format!("      gap: {gap}\n"));
        }
    }
    out.push_str("\nImplemented:\n");
    for item in &assessment.implemented {
        out.push_str(&format!("  [x] {item}\n"));
    }
    out.push_str("\nPartial:\n");
    for item in &assessment.partial {
        out.push_str(&format!("  [~] {item}\n"));
    }
    out.push_str("\nMissing:\n");
    for item in &assessment.missing {
        out.push_str(&format!("  [ ] {item}\n"));
    }
    out.push_str("\nNext coverage steps:\n");
    for item in &assessment.next_steps {
        out.push_str(&format!("  - {item}\n"));
    }
    out
}

pub fn coverage_check(
    min_functional_coverage_percent: u8,
    min_release_maturity_percent: u8,
) -> CoverageCheckReport {
    let assessment = coverage_assessment();
    let mut checks = Vec::new();
    let mut missing = Vec::new();
    if assessment.functional_coverage_percent >= min_functional_coverage_percent {
        checks.push(format!(
            "functional-coverage:{}>= {}",
            assessment.functional_coverage_percent, min_functional_coverage_percent
        ));
    } else {
        missing.push(format!(
            "functional coverage {}% is below required {}%",
            assessment.functional_coverage_percent, min_functional_coverage_percent
        ));
    }
    if assessment.release_maturity_percent >= min_release_maturity_percent {
        checks.push(format!(
            "release-maturity:{}>= {}",
            assessment.release_maturity_percent, min_release_maturity_percent
        ));
    } else {
        missing.push(format!(
            "release maturity {}% is below required {}%",
            assessment.release_maturity_percent, min_release_maturity_percent
        ));
    }
    let status = if missing.is_empty() {
        SdkCheckStatus::Passed
    } else {
        SdkCheckStatus::Failed
    };
    let detail = if missing.is_empty() {
        format!(
            "coverage thresholds satisfied: functional {}% >= {}%, release maturity {}% >= {}%",
            assessment.functional_coverage_percent,
            min_functional_coverage_percent,
            assessment.release_maturity_percent,
            min_release_maturity_percent
        )
    } else {
        format!(
            "coverage thresholds failed: {} unsatisfied requirement(s)",
            missing.len()
        )
    };
    CoverageCheckReport {
        schema: "kotoba-shell.coverage-check.v0".to_string(),
        status,
        min_functional_coverage_percent,
        min_release_maturity_percent,
        functional_coverage_percent: assessment.functional_coverage_percent,
        release_maturity_percent: assessment.release_maturity_percent,
        checks,
        missing,
        detail,
        assessment,
    }
}

fn coverage_category(
    id: &str,
    label: &str,
    score_percent: u8,
    maturity_percent: u8,
    status: CoverageStatus,
    evidence: &[&str],
    gaps: &[&str],
) -> CoverageCategory {
    CoverageCategory {
        id: id.to_string(),
        label: label.to_string(),
        score_percent,
        maturity_percent,
        status,
        evidence: evidence.iter().map(|item| item.to_string()).collect(),
        gaps: gaps.iter().map(|item| item.to_string()).collect(),
    }
}

fn coverage_status_mark(status: &CoverageStatus) -> &'static str {
    match status {
        CoverageStatus::Implemented => "x",
        CoverageStatus::Partial => "~",
        CoverageStatus::Missing => " ",
    }
}

fn weighted_average(
    categories: &[CoverageCategory],
    value: impl Fn(&CoverageCategory) -> u8,
) -> u8 {
    if categories.is_empty() {
        return 0;
    }
    let sum = categories
        .iter()
        .map(|category| value(category) as u32)
        .sum::<u32>();
    (sum / categories.len() as u32) as u8
}

pub fn broker_check_plan(
    plan: &ShellPlan,
    target: Target,
    command: Option<&str>,
) -> Result<BrokerCheckReport> {
    let capabilities = target_capabilities(plan, target);
    let providers = provider_catalog_json(&capabilities);
    let mut checks = Vec::new();
    checks.push("broker.verify:safe-kotoba-admission-before-provider-link".to_string());
    checks.push("broker.dispatch:capability-command".to_string());
    checks.push("broker.audit:append-only-command-log".to_string());
    for component in &plan.components {
        if component.safe && component.status != ComponentStatus::Admitted {
            bail!(
                "safe component `{}` was not admitted before provider link",
                component.id
            );
        }
        if component.safe {
            checks.push(format!("component:{}:safe-admitted", component.id));
        }
    }
    for provider in &providers {
        let provider_id = provider
            .get("id")
            .and_then(|v| v.as_str())
            .ok_or_else(|| anyhow!("provider catalog entry missing id"))?;
        let capability = provider
            .get("capability")
            .and_then(|v| v.as_str())
            .ok_or_else(|| anyhow!("provider catalog entry missing capability"))?;
        let commands = provider
            .get("commands")
            .and_then(|v| v.as_array())
            .ok_or_else(|| anyhow!("provider catalog entry missing commands"))?;
        for command in commands.iter().filter_map(|v| v.as_str()) {
            checks.push(format!(
                "provider:{provider_id}:command:{command}:capability:{capability}"
            ));
        }
    }
    let dry_run = command
        .map(|command| broker_dry_run(plan, target, command, &providers))
        .transpose()?;
    let status = if dry_run.as_ref().is_some_and(|r| !r.allowed) {
        SdkCheckStatus::Failed
    } else {
        SdkCheckStatus::Passed
    };
    let detail = if dry_run.is_some() {
        "aiueos shell broker admission and dry dispatch evaluated".to_string()
    } else {
        "aiueos shell broker admission evaluated".to_string()
    };
    Ok(BrokerCheckReport {
        target,
        app_id: plan.app_id.clone(),
        status,
        checks,
        dry_run,
        detail,
    })
}

fn broker_dry_run(
    plan: &ShellPlan,
    target: Target,
    command: &str,
    providers: &[serde_json::Value],
) -> Result<BrokerDryRun> {
    for provider in providers {
        let commands = provider
            .get("commands")
            .and_then(|v| v.as_array())
            .ok_or_else(|| anyhow!("provider catalog entry missing commands"))?;
        if commands
            .iter()
            .filter_map(|v| v.as_str())
            .any(|c| c == command)
        {
            let provider_id = provider
                .get("id")
                .and_then(|v| v.as_str())
                .map(str::to_string);
            let capability = provider
                .get("capability")
                .and_then(|v| v.as_str())
                .map(str::to_string);
            return Ok(BrokerDryRun {
                command: command.to_string(),
                allowed: true,
                provider: provider_id.clone(),
                capability: capability.clone(),
                audit_event: broker_audit_event(
                    plan,
                    target,
                    command,
                    true,
                    provider_id.as_deref(),
                    capability.as_deref(),
                    None,
                ),
            });
        }
    }
    Ok(BrokerDryRun {
        command: command.to_string(),
        allowed: false,
        provider: None,
        capability: None,
        audit_event: broker_audit_event(
            plan,
            target,
            command,
            false,
            None,
            None,
            Some("command is not granted by aiueos shell surface"),
        ),
    })
}

fn broker_audit_event(
    plan: &ShellPlan,
    target: Target,
    command: &str,
    ok: bool,
    provider: Option<&str>,
    capability: Option<&str>,
    error: Option<&str>,
) -> serde_json::Value {
    serde_json::json!({
        "schema": "aiueos.shell.audit.v0",
        "phase": "broker-dry-run",
        "app": plan.app_id,
        "target": target.as_str(),
        "command": command,
        "ok": ok,
        "provider": provider,
        "capability": capability,
        "error": error,
    })
}

pub fn append_broker_audit(path: impl AsRef<Path>, event: &serde_json::Value) -> Result<()> {
    let path = path.as_ref();
    if let Some(parent) = path.parent() {
        std::fs::create_dir_all(parent).with_context(|| format!("create {}", parent.display()))?;
    }
    let mut file = OpenOptions::new()
        .create(true)
        .append(true)
        .open(path)
        .with_context(|| format!("open broker audit log {}", path.display()))?;
    serde_json::to_writer(&mut file, event)
        .with_context(|| format!("write broker audit event {}", path.display()))?;
    file.write_all(b"\n")
        .with_context(|| format!("write broker audit newline {}", path.display()))?;
    Ok(())
}

pub fn ledger_replay_check(
    target: Target,
    source: impl AsRef<Path>,
    replica: impl AsRef<Path>,
) -> Result<LedgerReplayCheckReport> {
    let source = source.as_ref();
    let replica = replica.as_ref();
    let mut checks = Vec::new();
    let mut missing = Vec::new();
    let text = match std::fs::read_to_string(source) {
        Ok(text) => {
            checks.push(format!("source:{}", source.display()));
            text
        }
        Err(err) => {
            missing.push(format!("source ledger is unreadable: {err}"));
            String::new()
        }
    };
    let mut event_count = 0usize;
    let mut replay_lines = Vec::new();
    for (index, line) in text.lines().enumerate() {
        let trimmed = line.trim();
        if trimmed.is_empty() {
            continue;
        }
        match serde_json::from_str::<serde_json::Value>(trimmed) {
            Ok(value) => {
                let schema = value.get("schema").and_then(|v| v.as_str()).unwrap_or("");
                if schema == "aiueos.shell.ledger.event.v0"
                    || schema == "aiueos.shell.audit.v0"
                    || schema == "kotoba-shell.updater-stage.v0"
                {
                    checks.push(format!("event:{index}:schema:{schema}"));
                } else {
                    missing.push(format!("event {index} has unsupported schema `{schema}`"));
                }
                replay_lines.push(serde_json::to_string(&value)?);
                event_count += 1;
            }
            Err(err) => missing.push(format!("event {index} is not valid JSON: {err}")),
        }
    }
    if event_count == 0 {
        missing.push("ledger replay requires at least one event".to_string());
    } else {
        checks.push(format!("event-count:{event_count}"));
    }
    if let Some(parent) = replica.parent() {
        std::fs::create_dir_all(parent).with_context(|| format!("create {}", parent.display()))?;
    }
    let replay_text = if replay_lines.is_empty() {
        String::new()
    } else {
        format!("{}\n", replay_lines.join("\n"))
    };
    std::fs::write(replica, &replay_text)
        .with_context(|| format!("write {}", replica.display()))?;
    checks.push(format!("replica:{}", replica.display()));
    let source_sha256 = sha256_bytes_hex(replay_text.as_bytes());
    let replica_sha256 = sha256_hex(replica)?;
    if source_sha256 == replica_sha256 {
        checks.push(format!("sha256:{source_sha256}"));
    } else {
        missing.push(format!(
            "replica sha256 {replica_sha256} does not match source {source_sha256}"
        ));
    }
    let status = if missing.is_empty() {
        SdkCheckStatus::Passed
    } else {
        SdkCheckStatus::Failed
    };
    let detail = if missing.is_empty() {
        format!("ledger replay replicated {event_count} append-only event(s)")
    } else {
        format!(
            "ledger replay has {} unsatisfied requirement(s)",
            missing.len()
        )
    };
    Ok(LedgerReplayCheckReport {
        schema: "kotoba-shell.ledger-replay-check.v0".to_string(),
        target,
        source: source.to_path_buf(),
        replica: replica.to_path_buf(),
        status,
        event_count,
        source_sha256,
        replica_sha256,
        checks,
        missing,
        detail,
    })
}

pub fn ledger_remote_check(
    target: Target,
    source: impl AsRef<Path>,
    endpoint: &str,
    hosted: bool,
    probe: bool,
    timeout: Duration,
) -> Result<LedgerRemoteCheckReport> {
    let source = source.as_ref();
    let replay = ledger_replay_check(
        target,
        source,
        std::env::temp_dir().join(format!(
            "kotoba-ledger-remote-{}-{}.jsonl",
            std::process::id(),
            SystemTime::now()
                .duration_since(UNIX_EPOCH)
                .unwrap_or_default()
                .as_nanos()
        )),
    )?;
    let _ = std::fs::remove_file(&replay.replica);
    let mut checks = replay.checks;
    let mut missing = replay.missing;
    let endpoint = endpoint.trim().to_string();
    if endpoint.is_empty() {
        missing.push("ledger remote endpoint is required".to_string());
    } else if hosted {
        match validate_hosted_adapter_url(&endpoint) {
            Ok(detail) => checks.push(format!("ledger:hosted:{detail}")),
            Err(err) => missing.push(format!("ledger hosted endpoint is invalid: {err}")),
        }
    } else if endpoint.starts_with("https://") || endpoint.starts_with("http://") {
        checks.push("ledger:endpoint:url".to_string());
    } else {
        missing.push("ledger endpoint must be http(s) URL".to_string());
    }
    if probe && !endpoint.is_empty() {
        match probe_adapter_endpoint(&endpoint, timeout) {
            Ok(detail) => checks.push(format!("ledger:probe:{detail}")),
            Err(err) => missing.push(format!("ledger endpoint probe failed: {err}")),
        }
    }
    let status = if missing.is_empty() {
        SdkCheckStatus::Passed
    } else {
        SdkCheckStatus::Failed
    };
    let detail = if missing.is_empty() {
        format!(
            "ledger remote endpoint is ready for {} event(s)",
            replay.event_count
        )
    } else {
        format!(
            "ledger remote check has {} unsatisfied requirement(s)",
            missing.len()
        )
    };
    Ok(LedgerRemoteCheckReport {
        schema: "kotoba-shell.ledger-remote-check.v0".to_string(),
        target,
        source: source.to_path_buf(),
        endpoint,
        status,
        event_count: replay.event_count,
        source_sha256: replay.source_sha256,
        checks,
        missing,
        detail,
    })
}

pub fn supervisor_check_plan(
    plan: &ShellPlan,
    target: Target,
    dry_run_request: Option<ComponentDryRunRequest>,
) -> Result<SupervisorCheckReport> {
    let capabilities = target_capabilities(plan, target);
    let providers = provider_catalog_json(&capabilities);
    let provider_commands = providers
        .iter()
        .flat_map(|provider| {
            provider
                .get("commands")
                .and_then(|v| v.as_array())
                .into_iter()
                .flatten()
                .filter_map(|v| v.as_str())
                .map(str::to_string)
                .collect::<Vec<_>>()
        })
        .collect::<BTreeSet<_>>();

    let mut checks = Vec::new();
    checks.push("supervisor.graph:manifest-components-loaded".to_string());
    checks.push("supervisor.broker:target-provider-surface-loaded".to_string());
    checks.push("supervisor.audit:component-start-plan".to_string());

    let mut components = Vec::new();
    for component in &plan.components {
        if component.safe {
            if component.status != ComponentStatus::Admitted {
                bail!(
                    "supervisor cannot start safe component `{}` before admission",
                    component.id
                );
            }
            if component.policy_edn.is_none() {
                bail!(
                    "safe component `{}` is missing minimal policy evidence",
                    component.id
                );
            }
            if component.wasm_bytes.unwrap_or_default() == 0 {
                bail!(
                    "safe component `{}` has no compiled wasm evidence",
                    component.id
                );
            }
            checks.push(format!("component:{}:safe-admitted", component.id));
            checks.push(format!("component:{}:policy-minimal", component.id));
            checks.push(format!("component:{}:wasm-compiled", component.id));
        } else {
            checks.push(format!("component:{}:host-declared", component.id));
        }
        for export in &component.exports {
            checks.push(format!("component:{}:export:{export}", component.id));
        }
        for import in &component.imports {
            if provider_commands.contains(import) || capabilities.iter().any(|c| c == import) {
                checks.push(format!("component:{}:import:{import}:linked", component.id));
            } else {
                bail!(
                    "component `{}` imports `{import}`, but target {} does not expose it",
                    component.id,
                    target.as_str()
                );
            }
        }
        components.push(ComponentSupervisorReport {
            id: component.id.clone(),
            safe: component.safe,
            status: component.status.clone(),
            source: component.source.clone(),
            wasm_bytes: component.wasm_bytes,
            exports: component.exports.clone(),
            imports: component.imports.clone(),
            capability_surface: component.capability_surface.clone(),
            inferred_effects: component.inferred_effects.clone(),
        });
    }

    let dry_run = dry_run_request
        .map(|request| supervisor_dry_run(plan, target, request))
        .transpose()?;
    let status = match dry_run.as_ref().map(|d| &d.status) {
        Some(SdkCheckStatus::Failed) => SdkCheckStatus::Failed,
        Some(SdkCheckStatus::Skipped) => SdkCheckStatus::Skipped,
        _ => SdkCheckStatus::Passed,
    };
    let detail = match &dry_run {
        Some(dry_run) => format!(
            "aiueos component supervisor plan verified; dry-run {}.{} is {:?}",
            dry_run.component, dry_run.function, dry_run.status
        ),
        None => "aiueos component supervisor plan verified".to_string(),
    };
    Ok(SupervisorCheckReport {
        schema: "kotoba-shell.supervisor-check.v0".to_string(),
        target,
        app_id: plan.app_id.clone(),
        status,
        checks,
        components,
        dry_run,
        detail,
    })
}

fn supervisor_dry_run(
    plan: &ShellPlan,
    target: Target,
    request: ComponentDryRunRequest,
) -> Result<ComponentDryRunReport> {
    let component = match &request.component {
        Some(id) => plan
            .components
            .iter()
            .find(|component| &component.id == id)
            .ok_or_else(|| anyhow!("component `{id}` not found"))?,
        None => plan
            .components
            .iter()
            .find(|component| component.safe)
            .ok_or_else(|| anyhow!("no safe component available for supervisor dry-run"))?,
    };
    if !component.safe {
        return Ok(ComponentDryRunReport {
            component: component.id.clone(),
            function: request.function.unwrap_or_else(|| "run".to_string()),
            args: request.args,
            status: SdkCheckStatus::Skipped,
            result: None,
            host_events: Vec::new(),
            wasm_source: "none".to_string(),
            admission_gate: None,
            analyzer_abi: None,
            analyzer_component_sha256: None,
            artifact_sha256: None,
            source_sha256: None,
            policy_sha256: None,
            detail: "host-declared component requires native host runtime".to_string(),
        });
    }
    let resolved_wasm = resolve_dry_run_wasm(component, &request)?;
    let shell_host_surface = component.capability_surface.iter().all(|iface| {
        iface == "kotoba:kais/auth@0.1.0"
            || iface == "kotoba:kais/kqe@0.1.0"
            || iface == "kotoba:kais/llm@0.1.0"
    });
    if component.imports.is_empty()
        && !component.capability_surface.is_empty()
        && shell_host_surface
    {
        let function = request
            .function
            .or_else(|| component.exports.first().cloned())
            .unwrap_or_else(|| "run".to_string());
        if !component.exports.is_empty()
            && !component.exports.iter().any(|export| export == &function)
        {
            bail!(
                "component `{}` does not declare export `{function}`",
                component.id
            );
        }
        let live_adapters = request
            .host_adapter_manifest
            .as_deref()
            .map(|path| {
                load_supervisor_live_adapters(
                    target,
                    path,
                    Duration::from_secs(request.adapter_timeout_seconds.max(1)),
                )
            })
            .transpose()?;
        let (result, host_events) = run_with_supervisor_hosts(
            &resolved_wasm.wasm,
            &function,
            &request.args,
            request.fuel,
            live_adapters,
            &request.auth_grants,
            &request.kqe_snapshot,
            request.llm_echo,
            &request.llm_responses,
        )
        .with_context(|| format!("supervisor host-bound dry-run {}.{function}", component.id))?;
        return Ok(ComponentDryRunReport {
            component: component.id.clone(),
            function,
            args: request.args,
            status: SdkCheckStatus::Passed,
            result: Some(result),
            host_events,
            wasm_source: resolved_wasm.source.clone(),
            admission_gate: resolved_wasm.admission_gate.clone(),
            analyzer_abi: resolved_wasm.analyzer_abi.clone(),
            analyzer_component_sha256: resolved_wasm.analyzer_component_sha256.clone(),
            artifact_sha256: resolved_wasm.artifact_sha256.clone(),
            source_sha256: resolved_wasm.source_sha256.clone(),
            policy_sha256: resolved_wasm.policy_sha256.clone(),
            detail: if request.host_adapter_manifest.is_some() {
                format!("safe Kotoba component executed from {} with live production auth/kqe/llm host adapters under wasmtime fuel", resolved_wasm.source)
            } else {
                format!("safe Kotoba component executed from {} with auth/kqe/llm host bindings under wasmtime fuel", resolved_wasm.source)
            },
        });
    }
    if !component.capability_surface.is_empty() || !component.imports.is_empty() {
        return Ok(ComponentDryRunReport {
            component: component.id.clone(),
            function: request
                .function
                .or_else(|| component.exports.first().cloned())
                .unwrap_or_else(|| "run".to_string()),
            args: request.args,
            status: SdkCheckStatus::Skipped,
            result: None,
            host_events: Vec::new(),
            wasm_source: "none".to_string(),
            admission_gate: None,
            analyzer_abi: None,
            analyzer_component_sha256: None,
            artifact_sha256: None,
            source_sha256: None,
            policy_sha256: None,
            detail: format!(
                "component requires unsupported host capability binding on target {}",
                target.as_str()
            ),
        });
    }
    let function = request
        .function
        .or_else(|| component.exports.first().cloned())
        .unwrap_or_else(|| "run".to_string());
    if !component.exports.is_empty() && !component.exports.iter().any(|export| export == &function)
    {
        bail!(
            "component `{}` does not declare export `{function}`",
            component.id
        );
    }
    let result =
        kotoba_clj::run::run_with_fuel(&resolved_wasm.wasm, &function, &request.args, request.fuel)
            .map_err(|e| anyhow!("supervisor dry-run {}.{}: {e}", component.id, function))?;
    Ok(ComponentDryRunReport {
        component: component.id.clone(),
        function,
        args: request.args,
        status: SdkCheckStatus::Passed,
        result: Some(result),
        host_events: Vec::new(),
        wasm_source: resolved_wasm.source.clone(),
        admission_gate: resolved_wasm.admission_gate,
        analyzer_abi: resolved_wasm.analyzer_abi,
        analyzer_component_sha256: resolved_wasm.analyzer_component_sha256,
        artifact_sha256: resolved_wasm.artifact_sha256,
        source_sha256: resolved_wasm.source_sha256,
        policy_sha256: resolved_wasm.policy_sha256,
        detail: format!(
            "pure safe Kotoba component executed from {} under wasmtime fuel",
            resolved_wasm.source
        ),
    })
}

struct ResolvedDryRunWasm {
    wasm: Vec<u8>,
    source: String,
    admission_gate: Option<String>,
    analyzer_abi: Option<String>,
    analyzer_component_sha256: Option<String>,
    artifact_sha256: Option<String>,
    source_sha256: Option<String>,
    policy_sha256: Option<String>,
}

fn resolve_dry_run_wasm(
    component: &ComponentPlan,
    request: &ComponentDryRunRequest,
) -> Result<ResolvedDryRunWasm> {
    if let Some(manifest) = &request.kototama_app_components_manifest {
        let report = kototama_app_components_check_manifest(manifest)
            .with_context(|| format!("verify kototama app components {}", manifest.display()))?;
        if report.status != SdkCheckStatus::Passed {
            bail!(
                "kototama app components manifest {} is {:?}: {}",
                manifest.display(),
                report.status,
                report.detail
            );
        }
        let entry = report
            .components
            .iter()
            .find(|entry| entry.id == component.id)
            .ok_or_else(|| {
                anyhow!(
                    "kototama app components manifest {} has no component `{}`",
                    manifest.display(),
                    component.id
                )
            })?;
        let wasm = std::fs::read(&entry.artifact)
            .with_context(|| format!("read kototama artifact {}", entry.artifact.display()))?;
        return Ok(ResolvedDryRunWasm {
            wasm,
            source: format!("kototama artifact {}", entry.artifact.display()),
            admission_gate: Some(entry.admission_gate.clone()),
            analyzer_abi: Some(entry.analyzer_abi.clone()),
            analyzer_component_sha256: Some(report.analyzer_component_sha256.clone()),
            artifact_sha256: Some(entry.sha256.clone()),
            source_sha256: Some(entry.source_sha256.clone()),
            policy_sha256: Some(entry.policy_sha256.clone()),
        });
    }
    let body = std::fs::read_to_string(&component.source)
        .with_context(|| format!("read safe component {}", component.source.display()))?;
    let policy = kotoba_clj::minimal_policy(&body)
        .map_err(|e| anyhow!("infer minimal policy for {}: {e}", component.id))?;
    let policy_edn = policy.to_edn();
    let wasm = kotoba_clj::compile_safe_kotoba_with_prelude(&body, &policy)
        .map_err(|e| anyhow!("safe compile for supervisor {}: {e}", component.id))?;
    let artifact_sha256 = sha256_bytes_hex(&wasm);
    let source_sha256 = sha256_bytes_hex(body.as_bytes());
    let policy_sha256 = sha256_bytes_hex(policy_edn.as_bytes());
    Ok(ResolvedDryRunWasm {
        wasm,
        source: format!("source compile {}", component.source.display()),
        admission_gate: Some(SAFE_KOTOBA_ADMISSION_GATE.to_string()),
        analyzer_abi: Some(kotoba_clj::selfhost::SAFE_ANALYZER_ABI.to_string()),
        analyzer_component_sha256: Some(sha256_bytes_hex(
            &kotoba_clj::selfhost::analyzer_component()
                .map_err(|err| anyhow!("compile kototama selfhost analyzer component: {err}"))?,
        )),
        artifact_sha256: Some(artifact_sha256),
        source_sha256: Some(source_sha256),
        policy_sha256: Some(policy_sha256),
    })
}

fn run_with_supervisor_hosts(
    wasm: &[u8],
    function: &str,
    args: &[i64],
    fuel: u64,
    live_adapters: Option<SupervisorLiveAdapters>,
    auth_grants: &[String],
    kqe_snapshot: &[ComponentKqeQuad],
    llm_echo: bool,
    llm_responses: &[ComponentLlmResponse],
) -> Result<(i64, Vec<ComponentHostEvent>)> {
    let mut config = wasmtime::Config::new();
    config.consume_fuel(true);
    let engine = wasmtime::Engine::new(&config)?;
    let module = wasmtime::Module::new(&engine, wasm)?;
    let mut linker = wasmtime::Linker::new(&engine);
    let grants = auth_grants
        .iter()
        .filter_map(|grant| grant.split_once(':'))
        .map(|(resource, ability)| (resource.to_string(), ability.to_string()))
        .collect::<BTreeSet<_>>();
    let llm_responses = llm_responses
        .iter()
        .map(|response| (response.model.clone(), response.response.clone()))
        .collect::<BTreeMap<_, _>>();
    let mut store = wasmtime::Store::new(
        &engine,
        SupervisorHostState {
            auth_grants: grants,
            kqe_snapshot: kqe_snapshot.to_vec(),
            llm_echo,
            llm_responses,
            live_adapters,
            host_events: Vec::new(),
        },
    );
    store.set_fuel(fuel)?;
    let auth = wasmtime::Func::wrap(
        &mut store,
        move |mut caller: wasmtime::Caller<'_, SupervisorHostState>,
              resource_ptr: i32,
              resource_len: i32,
              ability_ptr: i32,
              ability_len: i32|
              -> i32 {
            let resource = read_guest_string(&mut caller, resource_ptr, resource_len);
            let ability = read_guest_string(&mut caller, ability_ptr, ability_len);
            match (resource, ability) {
                (Some(resource), Some(ability)) => {
                    if let Some(adapters) = caller.data().live_adapters.clone() {
                        let response = invoke_live_adapter_json(
                            "auth",
                            &adapters,
                            serde_json::json!({
                                "schema": "kotoba-shell.adapter-call.v0",
                                "operation": "auth.has-capability",
                                "resource": resource,
                                "ability": ability
                            }),
                        );
                        match response.and_then(|json| live_response_bool(&json, "allowed")) {
                            Ok(allowed) => {
                                caller.data_mut().host_events.push(ComponentHostEvent {
                                    provider: "kotoba:kais/auth@0.1.0".to_string(),
                                    operation: "has-capability".to_string(),
                                    graph: "live-adapter".to_string(),
                                    subject: resource,
                                    predicate: ability,
                                    object: allowed.to_string(),
                                });
                                return allowed as i32;
                            }
                            Err(err) => {
                                caller.data_mut().host_events.push(ComponentHostEvent {
                                    provider: "kotoba:kais/auth@0.1.0".to_string(),
                                    operation: "has-capability".to_string(),
                                    graph: "live-adapter".to_string(),
                                    subject: resource,
                                    predicate: ability,
                                    object: format!("err:{err}"),
                                });
                                return 0;
                            }
                        }
                    }
                    caller.data().auth_grants.contains(&(resource, ability)) as i32
                }
                _ => 0,
            }
        },
    );
    linker.define(&mut store, "kotoba:kais/auth@0.1.0", "has-capability", auth)?;
    let infer = wasmtime::Func::wrap(
        &mut store,
        |mut caller: wasmtime::Caller<'_, SupervisorHostState>,
         model_ptr: i32,
         model_len: i32,
         prompt_ptr: i32,
         prompt_len: i32,
         result_area: i32| {
            let model = read_guest_string(&mut caller, model_ptr, model_len).unwrap_or_default();
            let prompt = read_guest_string(&mut caller, prompt_ptr, prompt_len).unwrap_or_default();
            if let Some(adapters) = caller.data().live_adapters.clone() {
                let response = invoke_live_adapter_json(
                    "llm",
                    &adapters,
                    serde_json::json!({
                        "schema": "kotoba-shell.adapter-call.v0",
                        "operation": "llm.infer",
                        "model": model,
                        "prompt": prompt
                    }),
                );
                match response.and_then(|json| live_response_string(&json, "output")) {
                    Ok(response) => {
                        write_guest_u8(&mut caller, result_area, 0, 0);
                        if let Some(ptr) = write_guest_bytes(&mut caller, response.as_bytes()) {
                            write_guest_i32(&mut caller, result_area, 4, ptr);
                            write_guest_i32(&mut caller, result_area, 8, response.len() as i32);
                        } else {
                            write_guest_i32(&mut caller, result_area, 4, 0);
                            write_guest_i32(&mut caller, result_area, 8, 0);
                        }
                        caller.data_mut().host_events.push(ComponentHostEvent {
                            provider: "kotoba:kais/llm@0.1.0".to_string(),
                            operation: "infer".to_string(),
                            graph: "live-adapter".to_string(),
                            subject: model,
                            predicate: "ok".to_string(),
                            object: response,
                        });
                    }
                    Err(err) => {
                        write_guest_u8(&mut caller, result_area, 0, 1);
                        write_guest_i32(&mut caller, result_area, 4, 0);
                        write_guest_i32(&mut caller, result_area, 8, 0);
                        caller.data_mut().host_events.push(ComponentHostEvent {
                            provider: "kotoba:kais/llm@0.1.0".to_string(),
                            operation: "infer".to_string(),
                            graph: "live-adapter".to_string(),
                            subject: model,
                            predicate: "err".to_string(),
                            object: err.to_string(),
                        });
                    }
                }
                return;
            }
            let response = caller
                .data()
                .llm_responses
                .get(&model)
                .cloned()
                .or_else(|| caller.data().llm_echo.then(|| format!("echo:{prompt}")));
            match response {
                Some(response) => {
                    write_guest_u8(&mut caller, result_area, 0, 0);
                    if let Some(ptr) = write_guest_bytes(&mut caller, response.as_bytes()) {
                        write_guest_i32(&mut caller, result_area, 4, ptr);
                        write_guest_i32(&mut caller, result_area, 8, response.len() as i32);
                    } else {
                        write_guest_i32(&mut caller, result_area, 4, 0);
                        write_guest_i32(&mut caller, result_area, 8, 0);
                    }
                    caller.data_mut().host_events.push(ComponentHostEvent {
                        provider: "kotoba:kais/llm@0.1.0".to_string(),
                        operation: "infer".to_string(),
                        graph: model,
                        subject: prompt,
                        predicate: "ok".to_string(),
                        object: response,
                    });
                }
                None => {
                    write_guest_u8(&mut caller, result_area, 0, 1);
                    write_guest_i32(&mut caller, result_area, 4, 0);
                    write_guest_i32(&mut caller, result_area, 8, 0);
                    caller.data_mut().host_events.push(ComponentHostEvent {
                        provider: "kotoba:kais/llm@0.1.0".to_string(),
                        operation: "infer".to_string(),
                        graph: model,
                        subject: prompt,
                        predicate: "err".to_string(),
                        object: "no llm dry-run response configured".to_string(),
                    });
                }
            }
        },
    );
    linker.define(&mut store, "kotoba:kais/llm@0.1.0", "infer", infer)?;
    let assert_quad = wasmtime::Func::wrap(
        &mut store,
        |mut caller: wasmtime::Caller<'_, SupervisorHostState>,
         graph_ptr: i32,
         graph_len: i32,
         subject_ptr: i32,
         subject_len: i32,
         predicate_ptr: i32,
         predicate_len: i32,
         object_ptr: i32,
         object_len: i32,
         result_area: i32| {
            record_kqe_mutation(
                &mut caller,
                "assert-quad",
                graph_ptr,
                graph_len,
                subject_ptr,
                subject_len,
                predicate_ptr,
                predicate_len,
                object_ptr,
                object_len,
                result_area,
            );
        },
    );
    linker.define(
        &mut store,
        "kotoba:kais/kqe@0.1.0",
        "assert-quad",
        assert_quad,
    )?;
    let retract_quad = wasmtime::Func::wrap(
        &mut store,
        |mut caller: wasmtime::Caller<'_, SupervisorHostState>,
         graph_ptr: i32,
         graph_len: i32,
         subject_ptr: i32,
         subject_len: i32,
         predicate_ptr: i32,
         predicate_len: i32,
         object_ptr: i32,
         object_len: i32,
         result_area: i32| {
            record_kqe_mutation(
                &mut caller,
                "retract-quad",
                graph_ptr,
                graph_len,
                subject_ptr,
                subject_len,
                predicate_ptr,
                predicate_len,
                object_ptr,
                object_len,
                result_area,
            );
        },
    );
    linker.define(
        &mut store,
        "kotoba:kais/kqe@0.1.0",
        "retract-quad",
        retract_quad,
    )?;
    let get_objects = wasmtime::Func::wrap(
        &mut store,
        |mut caller: wasmtime::Caller<'_, SupervisorHostState>,
         graph_ptr: i32,
         graph_len: i32,
         subject_ptr: i32,
         subject_len: i32,
         predicate_ptr: i32,
         predicate_len: i32,
         result_area: i32| {
            let graph = read_guest_string(&mut caller, graph_ptr, graph_len).unwrap_or_default();
            let subject =
                read_guest_string(&mut caller, subject_ptr, subject_len).unwrap_or_default();
            let predicate =
                read_guest_string(&mut caller, predicate_ptr, predicate_len).unwrap_or_default();
            if let Some(adapters) = caller.data().live_adapters.clone() {
                let response = invoke_live_adapter_json(
                    "kqe",
                    &adapters,
                    serde_json::json!({
                        "schema": "kotoba-shell.adapter-call.v0",
                        "operation": "kqe.get-objects",
                        "graph": graph,
                        "subject": subject,
                        "predicate": predicate
                    }),
                );
                match response.and_then(|json| live_response_string_array(&json, "objects")) {
                    Ok(objects) => {
                        caller.data_mut().host_events.push(ComponentHostEvent {
                            provider: "kotoba:kais/kqe@0.1.0".to_string(),
                            operation: "get-objects".to_string(),
                            graph,
                            subject,
                            predicate,
                            object: format!("{} live object(s)", objects.len()),
                        });
                        write_guest_object_list(&mut caller, result_area, &objects);
                    }
                    Err(err) => {
                        caller.data_mut().host_events.push(ComponentHostEvent {
                            provider: "kotoba:kais/kqe@0.1.0".to_string(),
                            operation: "get-objects".to_string(),
                            graph,
                            subject,
                            predicate,
                            object: format!("err:{err}"),
                        });
                        write_guest_object_list(&mut caller, result_area, &[]);
                    }
                }
                return;
            }
            let objects = caller
                .data()
                .kqe_snapshot
                .iter()
                .filter(|quad| {
                    quad.graph == graph && quad.subject == subject && quad.predicate == predicate
                })
                .map(|quad| quad.object.clone())
                .collect::<Vec<_>>();
            caller.data_mut().host_events.push(ComponentHostEvent {
                provider: "kotoba:kais/kqe@0.1.0".to_string(),
                operation: "get-objects".to_string(),
                graph,
                subject,
                predicate,
                object: format!("{} object(s)", objects.len()),
            });
            write_guest_object_list(&mut caller, result_area, &objects);
        },
    );
    linker.define(
        &mut store,
        "kotoba:kais/kqe@0.1.0",
        "get-objects",
        get_objects,
    )?;
    let query = wasmtime::Func::wrap(
        &mut store,
        |mut caller: wasmtime::Caller<'_, SupervisorHostState>,
         filter_ptr: i32,
         filter_len: i32,
         result_area: i32| {
            let filter = read_guest_string(&mut caller, filter_ptr, filter_len).unwrap_or_default();
            if let Some(adapters) = caller.data().live_adapters.clone() {
                let response = invoke_live_adapter_json(
                    "kqe",
                    &adapters,
                    serde_json::json!({
                        "schema": "kotoba-shell.adapter-call.v0",
                        "operation": "kqe.query",
                        "filter": filter
                    }),
                );
                match response.and_then(|json| live_response_quads(&json)) {
                    Ok(quads) => {
                        caller.data_mut().host_events.push(ComponentHostEvent {
                            provider: "kotoba:kais/kqe@0.1.0".to_string(),
                            operation: "query".to_string(),
                            graph: "live-adapter".to_string(),
                            subject: "*".to_string(),
                            predicate: filter,
                            object: format!("{} live quad(s)", quads.len()),
                        });
                        write_guest_u8(&mut caller, result_area, 0, 0);
                        write_guest_quad_list(&mut caller, result_area, &quads);
                    }
                    Err(err) => {
                        caller.data_mut().host_events.push(ComponentHostEvent {
                            provider: "kotoba:kais/kqe@0.1.0".to_string(),
                            operation: "query".to_string(),
                            graph: "live-adapter".to_string(),
                            subject: "*".to_string(),
                            predicate: filter,
                            object: format!("err:{err}"),
                        });
                        write_guest_u8(&mut caller, result_area, 0, 1);
                        write_guest_i32(&mut caller, result_area, 4, 0);
                        write_guest_i32(&mut caller, result_area, 8, 0);
                    }
                }
                return;
            }
            let quads = caller.data().kqe_snapshot.clone();
            caller.data_mut().host_events.push(ComponentHostEvent {
                provider: "kotoba:kais/kqe@0.1.0".to_string(),
                operation: "query".to_string(),
                graph: "*".to_string(),
                subject: "*".to_string(),
                predicate: filter,
                object: format!("{} quad(s)", quads.len()),
            });
            write_guest_u8(&mut caller, result_area, 0, 0);
            write_guest_quad_list(&mut caller, result_area, &quads);
        },
    );
    linker.define(&mut store, "kotoba:kais/kqe@0.1.0", "query", query)?;
    let instance = linker.instantiate(&mut store, &module)?;
    let f = instance
        .get_func(&mut store, function)
        .ok_or_else(|| anyhow!("module has no exported function `{function}`"))?;
    let params = args
        .iter()
        .map(|arg| wasmtime::Val::I64(*arg))
        .collect::<Vec<_>>();
    let mut results = vec![wasmtime::Val::I64(0)];
    f.call(&mut store, &params, &mut results)?;
    match results.first() {
        Some(wasmtime::Val::I64(v)) => Ok((*v, store.data().host_events.clone())),
        other => bail!("unexpected result kind: {other:?}"),
    }
}

fn read_guest_string(
    caller: &mut wasmtime::Caller<'_, SupervisorHostState>,
    ptr: i32,
    len: i32,
) -> Option<String> {
    let memory = caller
        .get_export("memory")
        .and_then(wasmtime::Extern::into_memory)?;
    let ptr = usize::try_from(ptr).ok()?;
    let len = usize::try_from(len).ok()?;
    let end = ptr.checked_add(len)?;
    let data = memory.data(&caller);
    let bytes = data.get(ptr..end)?;
    std::str::from_utf8(bytes).ok().map(str::to_string)
}

#[allow(clippy::too_many_arguments)]
fn record_kqe_mutation(
    caller: &mut wasmtime::Caller<'_, SupervisorHostState>,
    operation: &str,
    graph_ptr: i32,
    graph_len: i32,
    subject_ptr: i32,
    subject_len: i32,
    predicate_ptr: i32,
    predicate_len: i32,
    object_ptr: i32,
    object_len: i32,
    result_area: i32,
) {
    let graph = read_guest_string(caller, graph_ptr, graph_len).unwrap_or_default();
    let subject = read_guest_string(caller, subject_ptr, subject_len).unwrap_or_default();
    let predicate = read_guest_string(caller, predicate_ptr, predicate_len).unwrap_or_default();
    let object = read_guest_string(caller, object_ptr, object_len).unwrap_or_default();
    if let Some(adapters) = caller.data().live_adapters.clone() {
        let response = invoke_live_adapter_json(
            "kqe",
            &adapters,
            serde_json::json!({
                "schema": "kotoba-shell.adapter-call.v0",
                "operation": format!("kqe.{operation}"),
                "graph": graph,
                "subject": subject,
                "predicate": predicate,
                "object": object
            }),
        );
        match response.and_then(|json| live_response_bool(&json, "ok")) {
            Ok(true) => {
                caller.data_mut().host_events.push(ComponentHostEvent {
                    provider: "kotoba:kais/kqe@0.1.0".to_string(),
                    operation: operation.to_string(),
                    graph,
                    subject,
                    predicate,
                    object,
                });
                write_guest_u8(caller, result_area, 0, 0);
                write_guest_i32(caller, result_area, 4, 0);
                write_guest_i32(caller, result_area, 8, 0);
            }
            Ok(false) => {
                caller.data_mut().host_events.push(ComponentHostEvent {
                    provider: "kotoba:kais/kqe@0.1.0".to_string(),
                    operation: operation.to_string(),
                    graph,
                    subject,
                    predicate,
                    object: "err:adapter returned ok=false".to_string(),
                });
                write_guest_u8(caller, result_area, 0, 1);
                write_guest_i32(caller, result_area, 4, 0);
                write_guest_i32(caller, result_area, 8, 0);
            }
            Err(err) => {
                caller.data_mut().host_events.push(ComponentHostEvent {
                    provider: "kotoba:kais/kqe@0.1.0".to_string(),
                    operation: operation.to_string(),
                    graph,
                    subject,
                    predicate,
                    object: format!("err:{err}"),
                });
                write_guest_u8(caller, result_area, 0, 1);
                write_guest_i32(caller, result_area, 4, 0);
                write_guest_i32(caller, result_area, 8, 0);
            }
        }
        return;
    }
    caller.data_mut().host_events.push(ComponentHostEvent {
        provider: "kotoba:kais/kqe@0.1.0".to_string(),
        operation: operation.to_string(),
        graph,
        subject,
        predicate,
        object,
    });
    write_guest_u8(caller, result_area, 0, 0);
    write_guest_i32(caller, result_area, 4, 0);
    write_guest_i32(caller, result_area, 8, 0);
}

fn write_guest_u8(
    caller: &mut wasmtime::Caller<'_, SupervisorHostState>,
    ptr: i32,
    offset: usize,
    value: u8,
) {
    if let Some(memory) = caller
        .get_export("memory")
        .and_then(wasmtime::Extern::into_memory)
    {
        if let Some(slot) = usize::try_from(ptr)
            .ok()
            .and_then(|ptr| ptr.checked_add(offset))
            .and_then(|index| memory.data_mut(caller).get_mut(index))
        {
            *slot = value;
        }
    }
}

fn write_guest_i32(
    caller: &mut wasmtime::Caller<'_, SupervisorHostState>,
    ptr: i32,
    offset: usize,
    value: i32,
) {
    if let Some(memory) = caller
        .get_export("memory")
        .and_then(wasmtime::Extern::into_memory)
    {
        if let Some(start) = usize::try_from(ptr)
            .ok()
            .and_then(|ptr| ptr.checked_add(offset))
        {
            let data = memory.data_mut(caller);
            if let Some(slot) = data.get_mut(start..start + 4) {
                slot.copy_from_slice(&value.to_le_bytes());
            }
        }
    }
}

fn write_guest_object_list(
    caller: &mut wasmtime::Caller<'_, SupervisorHostState>,
    result_area: i32,
    objects: &[String],
) {
    let Some(list_ptr) = guest_alloc(caller, 4, objects.len().saturating_mul(8)) else {
        write_guest_i32(caller, result_area, 0, 0);
        write_guest_i32(caller, result_area, 4, 0);
        return;
    };
    for (index, object) in objects.iter().enumerate() {
        if let Some(object_ptr) = write_guest_bytes(caller, object.as_bytes()) {
            let entry = list_ptr + (index as i32 * 8);
            write_guest_i32(caller, entry, 0, object_ptr);
            write_guest_i32(caller, entry, 4, object.len() as i32);
        }
    }
    write_guest_i32(caller, result_area, 0, list_ptr);
    write_guest_i32(caller, result_area, 4, objects.len() as i32);
}

fn write_guest_quad_list(
    caller: &mut wasmtime::Caller<'_, SupervisorHostState>,
    result_area: i32,
    quads: &[ComponentKqeQuad],
) {
    let Some(list_ptr) = guest_alloc(caller, 4, quads.len().saturating_mul(32)) else {
        write_guest_i32(caller, result_area, 4, 0);
        write_guest_i32(caller, result_area, 8, 0);
        return;
    };
    for (index, quad) in quads.iter().enumerate() {
        let entry = list_ptr + (index as i32 * 32);
        for (field, value) in [&quad.graph, &quad.subject, &quad.predicate, &quad.object]
            .iter()
            .enumerate()
        {
            if let Some(ptr) = write_guest_bytes(caller, value.as_bytes()) {
                let field_entry = entry + (field as i32 * 8);
                write_guest_i32(caller, field_entry, 0, ptr);
                write_guest_i32(caller, field_entry, 4, value.len() as i32);
            }
        }
    }
    write_guest_i32(caller, result_area, 4, list_ptr);
    write_guest_i32(caller, result_area, 8, quads.len() as i32);
}

fn write_guest_bytes(
    caller: &mut wasmtime::Caller<'_, SupervisorHostState>,
    bytes: &[u8],
) -> Option<i32> {
    let ptr = guest_alloc(caller, 1, bytes.len())?;
    let memory = caller
        .get_export("memory")
        .and_then(wasmtime::Extern::into_memory)?;
    let start = usize::try_from(ptr).ok()?;
    let end = start.checked_add(bytes.len())?;
    memory
        .data_mut(caller)
        .get_mut(start..end)?
        .copy_from_slice(bytes);
    Some(ptr)
}

fn guest_alloc(
    caller: &mut wasmtime::Caller<'_, SupervisorHostState>,
    align: usize,
    size: usize,
) -> Option<i32> {
    if size == 0 {
        return Some(0);
    }
    let realloc = caller
        .get_export("cabi_realloc")
        .and_then(wasmtime::Extern::into_func)?;
    let mut results = [wasmtime::Val::I32(0)];
    realloc
        .call(
            caller,
            &[
                wasmtime::Val::I32(0),
                wasmtime::Val::I32(0),
                wasmtime::Val::I32(i32::try_from(align).ok()?),
                wasmtime::Val::I32(i32::try_from(size).ok()?),
            ],
            &mut results,
        )
        .ok()?;
    match results[0] {
        wasmtime::Val::I32(ptr) => Some(ptr),
        _ => None,
    }
}

pub fn build_target(plan: &ShellPlan, target: Target) -> Result<BuildArtifact> {
    match target {
        Target::Macos => build_macos_app(plan, Path::new("target/kotoba-shell/build")),
        Target::Ios => build_ios_scaffold(plan, Path::new("target/kotoba-shell/build")),
        Target::Android => build_android_scaffold(plan, Path::new("target/kotoba-shell/build")),
        Target::Windows => build_windows_scaffold(plan, Path::new("target/kotoba-shell/build")),
    }
}

pub fn export_release_artifacts(
    plan: &ShellPlan,
    target: Target,
    out_root: impl AsRef<Path>,
) -> Result<ExportArtifact> {
    let dir = out_root
        .as_ref()
        .join(target.as_str())
        .join(safe_path_segment(&plan.app_name));
    if dir.exists() {
        std::fs::remove_dir_all(&dir).with_context(|| format!("clear {}", dir.display()))?;
    }
    std::fs::create_dir_all(&dir).with_context(|| format!("create {}", dir.display()))?;
    write_shell_metadata(plan, target, &dir)?;
    write_kototama_component_metadata(&dir)?;
    write_kototama_app_components(plan, &dir)?;
    std::fs::write(
        dir.join("kotoba-shell-release-checklist.md"),
        release_checklist(plan, target),
    )
    .with_context(|| {
        format!(
            "write {}",
            dir.join("kotoba-shell-release-checklist.md").display()
        )
    })?;
    std::fs::write(
        dir.join("kotoba-shell-updater-manifest.json"),
        updater_manifest_json(plan, target)?,
    )
    .with_context(|| {
        format!(
            "write {}",
            dir.join("kotoba-shell-updater-manifest.json").display()
        )
    })?;
    std::fs::write(
        dir.join("kotoba-shell-updater-channel.json"),
        updater_channel_json(plan, target)?,
    )
    .with_context(|| {
        format!(
            "write {}",
            dir.join("kotoba-shell-updater-channel.json").display()
        )
    })?;
    std::fs::write(
        dir.join("kotoba-shell-updater-ui.json"),
        updater_ui_json(plan, target)?,
    )
    .with_context(|| {
        format!(
            "write {}",
            dir.join("kotoba-shell-updater-ui.json").display()
        )
    })?;
    std::fs::write(
        dir.join("kotoba-shell-signing-plan.json"),
        signing_plan_json(plan, target)?,
    )
    .with_context(|| {
        format!(
            "write {}",
            dir.join("kotoba-shell-signing-plan.json").display()
        )
    })?;
    let evidence_profile = evidence_profile_json(plan, target)?;
    std::fs::write(
        dir.join("kotoba-shell-evidence-profile.json"),
        &evidence_profile,
    )
    .with_context(|| {
        format!(
            "write {}",
            dir.join("kotoba-shell-evidence-profile.json").display()
        )
    })?;
    let evidence_profile_json: serde_json::Value = serde_json::from_str(&evidence_profile)?;
    std::fs::write(
        dir.join("kotoba-shell-evidence-profile.edn"),
        evidence_edn_string(&evidence_profile_json)?,
    )
    .with_context(|| {
        format!(
            "write {}",
            dir.join("kotoba-shell-evidence-profile.edn").display()
        )
    })?;
    if matches!(target, Target::Macos | Target::Windows) {
        std::fs::write(
            dir.join("aiueos-portable-plan.json"),
            aiueos_portable_plan_json(plan, target)?,
        )
        .with_context(|| format!("write {}", dir.join("aiueos-portable-plan.json").display()))?;
        let core_script = dir.join("build-aiueos-core.bb");
        std::fs::write(
            &core_script,
            aiueos_portable_build_script(plan, target, false),
        )
        .with_context(|| format!("write {}", core_script.display()))?;
        make_executable(&core_script)?;
        let runner_script = dir.join("build-aiueos-runner.bb");
        std::fs::write(
            &runner_script,
            aiueos_portable_build_script(plan, target, true),
        )
        .with_context(|| format!("write {}", runner_script.display()))?;
        make_executable(&runner_script)?;
    }
    match target {
        Target::Macos => {
            let notarize_script = dir.join("notarize-macos.sh");
            std::fs::write(&notarize_script, macos_notarize_script(plan))
                .with_context(|| format!("write {}", notarize_script.display()))?;
            make_executable(&notarize_script)?;
            let sign_script = dir.join("sign-macos.sh");
            std::fs::write(&sign_script, macos_sign_script(plan))
                .with_context(|| format!("write {}", sign_script.display()))?;
            make_executable(&sign_script)?;
            std::fs::write(
                dir.join("app-store-connect-macos.json"),
                apple_store_metadata_json(plan, Target::Macos)?,
            )
            .with_context(|| {
                format!(
                    "write {}",
                    dir.join("app-store-connect-macos.json").display()
                )
            })?;
        }
        Target::Ios => {
            std::fs::write(
                dir.join("xcode-export-options.plist"),
                ios_export_options_plist(),
            )
            .with_context(|| {
                format!("write {}", dir.join("xcode-export-options.plist").display())
            })?;
            let sign_script = dir.join("sign-ios.sh");
            std::fs::write(&sign_script, ios_sign_script(plan))
                .with_context(|| format!("write {}", sign_script.display()))?;
            make_executable(&sign_script)?;
            let submit_script = dir.join("submit-ios.sh");
            std::fs::write(&submit_script, ios_submit_script(plan))
                .with_context(|| format!("write {}", submit_script.display()))?;
            make_executable(&submit_script)?;
            std::fs::write(
                dir.join("app-store-connect-ios.json"),
                apple_store_metadata_json(plan, Target::Ios)?,
            )
            .with_context(|| {
                format!("write {}", dir.join("app-store-connect-ios.json").display())
            })?;
        }
        Target::Android => {
            std::fs::write(dir.join("play-store-review.md"), android_store_review(plan))
                .with_context(|| format!("write {}", dir.join("play-store-review.md").display()))?;
            let sign_script = dir.join("sign-android.sh");
            std::fs::write(&sign_script, android_sign_script(plan))
                .with_context(|| format!("write {}", sign_script.display()))?;
            make_executable(&sign_script)?;
            let submit_script = dir.join("submit-android.sh");
            std::fs::write(&submit_script, android_submit_script(plan))
                .with_context(|| format!("write {}", submit_script.display()))?;
            make_executable(&submit_script)?;
            std::fs::write(
                dir.join("play-store-data-safety.json"),
                android_data_safety_json(plan)?,
            )
            .with_context(|| {
                format!(
                    "write {}",
                    dir.join("play-store-data-safety.json").display()
                )
            })?;
        }
        Target::Windows => {
            std::fs::write(
                dir.join("windows-security-review.md"),
                windows_security_review(plan),
            )
            .with_context(|| {
                format!("write {}", dir.join("windows-security-review.md").display())
            })?;
            let sign_script = dir.join("sign-windows.sh");
            std::fs::write(&sign_script, windows_sign_script(plan))
                .with_context(|| format!("write {}", sign_script.display()))?;
            make_executable(&sign_script)?;
            let reputation_script = dir.join("smartscreen-windows.sh");
            std::fs::write(&reputation_script, windows_smartscreen_script(plan))
                .with_context(|| format!("write {}", reputation_script.display()))?;
            make_executable(&reputation_script)?;
        }
    }
    Ok(ExportArtifact {
        target,
        release_manifest: dir.join("kotoba-shell-release.json"),
        dir,
    })
}

pub fn release_check_artifacts(
    target: Target,
    release_dir: impl AsRef<Path>,
) -> Result<ReleaseCheckReport> {
    let dir = release_dir.as_ref();
    let mut checks = Vec::new();
    let mut missing = Vec::new();
    for (file, markers) in common_release_files(target) {
        require_file(dir, file, &markers, &mut checks)?;
    }
    for (file, markers) in target_release_files(target) {
        require_file(dir, file, &markers, &mut checks)?;
    }
    for script in target_release_scripts(target) {
        require_executable_file(dir, script, &mut checks)?;
    }
    validate_release_contract_oracle_if_present(target, dir, &mut checks)?;
    for env in target_release_env(target) {
        if std::env::var_os(env).is_some() {
            checks.push(format!("env:{env}"));
        } else {
            missing.push(env.to_string());
        }
    }
    let status = if missing.is_empty() {
        SdkCheckStatus::Passed
    } else {
        SdkCheckStatus::Skipped
    };
    let detail = if missing.is_empty() {
        "release artifacts and credential environment are present".to_string()
    } else {
        format!(
            "release artifacts are present; credential-backed signing/upload skipped because {} env var(s) are missing",
            missing.len()
        )
    };
    Ok(ReleaseCheckReport {
        schema: "kotoba-shell.release-check.v0".to_string(),
        target,
        dir: dir.to_path_buf(),
        status,
        checks,
        missing_credentials: missing,
        detail,
    })
}

fn validate_release_contract_oracle_if_present(
    target: Target,
    release_dir: &Path,
    checks: &mut Vec<String>,
) -> Result<()> {
    let release_json = read_evidence_json(&release_dir.join("kotoba-shell-release.json"))?;
    let permissions_json = read_evidence_json(&release_dir.join("kotoba-shell-permissions.json"))?;
    let evidence_profile_json =
        read_evidence_json(&release_dir.join("kotoba-shell-evidence-profile.json"))?;
    let common_expected = vec![
        (
            "release-schema-digest".to_string(),
            release_json
                .get("schema")
                .and_then(|value| value.as_str())
                .map(kototama_component_symbol_digest)
                .unwrap_or(0),
        ),
        ("release-check-schema-digest".to_string(), 7_401),
        (
            "permissions-schema-digest".to_string(),
            permissions_json
                .get("schema")
                .and_then(|value| value.as_str())
                .map(kototama_component_symbol_digest)
                .unwrap_or(0),
        ),
        (
            "evidence-profile-schema-digest".to_string(),
            evidence_profile_json
                .get("schema")
                .and_then(|value| value.as_str())
                .map(kototama_component_symbol_digest)
                .unwrap_or(0),
        ),
        (
            "common-release-file-count".to_string(),
            common_release_files(target).len() as i64,
        ),
    ];
    validate_store_contract_oracle_if_present(
        release_dir,
        "kototama-release-contract.edn",
        "kotoba-clj/selfhost/release_contract.kotoba",
        "release-contract-oracle",
        &common_expected,
        checks,
    )?;
    let target_name = target.as_str();
    let target_expected = vec![
        (
            format!("{target_name}-target-file-count"),
            target_release_files(target).len() as i64,
        ),
        (
            format!("{target_name}-script-count"),
            target_release_scripts(target).len() as i64,
        ),
        (
            format!("{target_name}-env-count"),
            target_release_env(target).len() as i64,
        ),
    ];
    validate_store_contract_oracle_if_present(
        release_dir,
        "kototama-release-target-contract.edn",
        "kotoba-clj/selfhost/release_target_contract.kotoba",
        "release-target-contract-oracle",
        &target_expected,
        checks,
    )
}

pub fn signing_check_artifacts(
    target: Target,
    release_dir: impl AsRef<Path>,
    execute: bool,
    artifact_or_project: Option<&Path>,
    output: Option<&Path>,
    timeout: Duration,
) -> Result<SigningCheckReport> {
    let dir = release_dir.as_ref();
    let release = release_check_artifacts(target, dir)?;
    let mut checks = release.checks;
    let missing = release.missing_credentials;
    let script = target_signing_script(target);
    require_executable_file(dir, script, &mut checks)?;
    require_file(
        dir,
        "kotoba-shell-signing-plan.json",
        &[
            "\"schema\": \"kotoba-shell.signing-plan.v0\"",
            "\"artifacts\"",
            "\"environment\"",
        ],
        &mut checks,
    )?;
    validate_signing_contract_oracle_if_present(target, dir, &mut checks)?;
    if !execute {
        let status = if missing.is_empty() {
            SdkCheckStatus::Passed
        } else {
            SdkCheckStatus::Skipped
        };
        let detail = if missing.is_empty() {
            "credential-backed signing execution is ready; use --execute to run the target signing helper".to_string()
        } else {
            format!(
                "signing execution skipped because {} credential env var(s) are missing",
                missing.len()
            )
        };
        return Ok(SigningCheckReport {
            schema: "kotoba-shell.signing-check.v0".to_string(),
            target,
            dir: dir.to_path_buf(),
            status,
            checks,
            missing_credentials: missing,
            command: Vec::new(),
            detail,
            stdout: String::new(),
            stderr: String::new(),
        });
    }
    if !missing.is_empty() {
        return Ok(SigningCheckReport {
            schema: "kotoba-shell.signing-check.v0".to_string(),
            target,
            dir: dir.to_path_buf(),
            status: SdkCheckStatus::Skipped,
            checks,
            missing_credentials: missing,
            command: Vec::new(),
            detail: "credential-backed signing execution skipped because credential env vars are missing".to_string(),
            stdout: String::new(),
            stderr: String::new(),
        });
    }
    if timeout.is_zero() {
        return Ok(SigningCheckReport {
            schema: "kotoba-shell.signing-check.v0".to_string(),
            target,
            dir: dir.to_path_buf(),
            status: SdkCheckStatus::Skipped,
            checks,
            missing_credentials: missing,
            command: Vec::new(),
            detail: "signing execution dry-run requested with zero timeout".to_string(),
            stdout: String::new(),
            stderr: String::new(),
        });
    }
    let args = signing_script_args(target, dir, artifact_or_project, output);
    run_signing_command(target, dir, script, &args, timeout, checks, missing)
}

pub fn submission_check_artifacts(
    target: Target,
    release_dir: impl AsRef<Path>,
    execute: bool,
    artifact: Option<&Path>,
    output: Option<&Path>,
    timeout: Duration,
) -> Result<SubmissionCheckReport> {
    let dir = release_dir.as_ref();
    let mut checks = Vec::new();
    let mut missing = Vec::new();
    for (file, markers) in target_submission_files(target) {
        require_file(dir, file, &markers, &mut checks)?;
    }
    if let Some(script) = target_submission_script(target) {
        require_executable_file(dir, script, &mut checks)?;
    }
    for env in target_submission_env(target) {
        if std::env::var_os(env).is_some() {
            checks.push(format!("env:{env}"));
        } else {
            missing.push(env.to_string());
        }
    }
    validate_submission_contract_oracle_if_present(target, dir, &mut checks)?;
    if !execute {
        let status = if missing.is_empty() {
            SdkCheckStatus::Passed
        } else {
            SdkCheckStatus::Skipped
        };
        let detail = if missing.is_empty() {
            "store/notarization submission metadata and credential environment are ready; use --execute to run supported submission helpers".to_string()
        } else {
            format!(
                "submission execution skipped because {} credential env var(s) are missing",
                missing.len()
            )
        };
        return Ok(SubmissionCheckReport {
            schema: "kotoba-shell.submission-check.v0".to_string(),
            target,
            dir: dir.to_path_buf(),
            status,
            checks,
            missing_credentials: missing,
            command: Vec::new(),
            detail,
            stdout: String::new(),
            stderr: String::new(),
        });
    }
    if !missing.is_empty() {
        return Ok(SubmissionCheckReport {
            schema: "kotoba-shell.submission-check.v0".to_string(),
            target,
            dir: dir.to_path_buf(),
            status: SdkCheckStatus::Skipped,
            checks,
            missing_credentials: missing,
            command: Vec::new(),
            detail: "submission execution skipped because credential env vars are missing"
                .to_string(),
            stdout: String::new(),
            stderr: String::new(),
        });
    }
    if timeout.is_zero() {
        return Ok(SubmissionCheckReport {
            schema: "kotoba-shell.submission-check.v0".to_string(),
            target,
            dir: dir.to_path_buf(),
            status: SdkCheckStatus::Skipped,
            checks,
            missing_credentials: missing,
            command: Vec::new(),
            detail: "submission execution dry-run requested with zero timeout".to_string(),
            stdout: String::new(),
            stderr: String::new(),
        });
    }
    let Some(script) = target_submission_script(target) else {
        return Ok(SubmissionCheckReport {
            schema: "kotoba-shell.submission-check.v0".to_string(),
            target,
            dir: dir.to_path_buf(),
            status: SdkCheckStatus::Skipped,
            checks,
            missing_credentials: missing,
            command: Vec::new(),
            detail: "no store upload helper is configured for this target".to_string(),
            stdout: String::new(),
            stderr: String::new(),
        });
    };
    let args = submission_script_args(target, artifact, output);
    run_submission_command(target, dir, script, &args, timeout, checks, missing)
}

fn validate_signing_contract_oracle_if_present(
    target: Target,
    release_dir: &Path,
    checks: &mut Vec<String>,
) -> Result<()> {
    let signing_plan = read_evidence_json(&release_dir.join("kotoba-shell-signing-plan.json"))?;
    let artifact_field_count = signing_plan
        .get("artifacts")
        .and_then(|value| value.as_object())
        .map(|values| values.len() as i64)
        .unwrap_or(0);
    let gate_count = signing_plan
        .get("gates")
        .and_then(|value| value.as_array())
        .map(|values| values.len() as i64)
        .unwrap_or(0);
    let schema_digest = signing_plan
        .get("schema")
        .and_then(|value| value.as_str())
        .map(kototama_component_symbol_digest)
        .unwrap_or(0);
    let version_digest = signing_plan
        .get("version")
        .and_then(|value| value.as_str())
        .map(kototama_component_symbol_digest)
        .unwrap_or(0);
    let target_name = target.as_str();
    let signing_script_digest = kototama_component_symbol_digest(target_signing_script(target));
    validate_store_contract_oracle_if_present(
        release_dir,
        "kototama-signing-contract.edn",
        "kotoba-clj/selfhost/signing_contract.kotoba",
        "signing-contract-oracle",
        &[
            ("signing-schema-digest".to_string(), schema_digest),
            ("version-digest".to_string(), version_digest),
            ("signing-gate-count".to_string(), gate_count),
            (
                format!("{target_name}-signing-script-digest"),
                signing_script_digest,
            ),
            (
                format!("{target_name}-env-count"),
                target_release_env(target).len() as i64,
            ),
            (
                format!("{target_name}-artifact-field-count"),
                artifact_field_count,
            ),
        ],
        checks,
    )
}

fn validate_submission_contract_oracle_if_present(
    target: Target,
    release_dir: &Path,
    checks: &mut Vec<String>,
) -> Result<()> {
    let target_name = target.as_str();
    let script = target_submission_script(target).ok_or_else(|| {
        anyhow!(
            "submission script is not configured for {}",
            target.as_str()
        )
    })?;
    let mut expected = vec![
        (
            format!("{target_name}-submission-script-digest"),
            kototama_component_symbol_digest(script),
        ),
        (
            format!("{target_name}-submission-file-count"),
            target_submission_files(target).len() as i64,
        ),
        (
            format!("{target_name}-env-count"),
            target_submission_env(target).len() as i64,
        ),
    ];
    match target {
        Target::Macos => {
            let json = read_evidence_json(&release_dir.join("app-store-connect-macos.json"))?;
            expected.push((
                "apple-store-schema-digest".to_string(),
                json.get("schema")
                    .and_then(|value| value.as_str())
                    .map(kototama_component_symbol_digest)
                    .unwrap_or(0),
            ));
        }
        Target::Ios => {
            let json = read_evidence_json(&release_dir.join("app-store-connect-ios.json"))?;
            expected.push((
                "apple-store-schema-digest".to_string(),
                json.get("schema")
                    .and_then(|value| value.as_str())
                    .map(kototama_component_symbol_digest)
                    .unwrap_or(0),
            ));
        }
        Target::Android => {
            let json = read_evidence_json(&release_dir.join("play-store-data-safety.json"))?;
            expected.push((
                "play-store-data-safety-schema-digest".to_string(),
                json.get("schema")
                    .and_then(|value| value.as_str())
                    .map(kototama_component_symbol_digest)
                    .unwrap_or(0),
            ));
        }
        Target::Windows => {}
    }
    validate_store_contract_oracle_if_present(
        release_dir,
        "kototama-submission-contract.edn",
        "kotoba-clj/selfhost/submission_contract.kotoba",
        "submission-contract-oracle",
        &expected,
        checks,
    )
}

fn validate_store_contract_oracle_if_present(
    release_dir: &Path,
    oracle_manifest_name: &str,
    expected_source: &str,
    oracle_prefix: &str,
    expected_exports: &[(String, i64)],
    checks: &mut Vec<String>,
) -> Result<()> {
    let oracle_manifest = release_dir.join(oracle_manifest_name);
    if !oracle_manifest.exists() {
        return Ok(());
    }
    let mut missing = Vec::new();
    let oracle_wasm = read_kototama_component_manifest_wasm(
        &oracle_manifest,
        expected_source,
        checks,
        &mut missing,
    )?;
    if !missing.is_empty() {
        bail!(
            "{} cannot be verified: {}",
            oracle_manifest.display(),
            missing.join(", ")
        );
    }
    checks.push(format!("{oracle_prefix}:bundled-component"));
    checks.push(format!(
        "{oracle_prefix}:wasm-sha256:{}",
        sha256_bytes_hex(&oracle_wasm)
    ));
    for (function, expected) in expected_exports {
        let actual = kotoba_clj::run::run_with_fuel(&oracle_wasm, function, &[], 1_000_000)
            .map_err(|err| anyhow!("run {oracle_prefix} Kotoba oracle `{function}`: {err}"))?;
        if actual == *expected {
            checks.push(format!("{oracle_prefix}:{function}:{actual}"));
        } else {
            bail!("{oracle_prefix} `{function}` returned {actual}, expected {expected}");
        }
    }
    Ok(())
}

fn validate_runtime_contract_oracle_if_present(
    anchor: &Path,
    checks: &mut Vec<String>,
    expected_exports: &[(String, i64)],
) -> Result<()> {
    let dir = anchor.parent().unwrap_or_else(|| Path::new("."));
    validate_store_contract_oracle_if_present(
        dir,
        "kototama-runtime-contract.edn",
        "kotoba-clj/selfhost/runtime_contract.kotoba",
        "runtime-contract-oracle",
        expected_exports,
        checks,
    )
}

fn validate_runtime_contract_oracle_in_project_if_present(
    project_dir: &Path,
    checks: &mut Vec<String>,
    expected_exports: &[(String, i64)],
) -> Result<()> {
    for dir in [
        project_dir.to_path_buf(),
        project_dir.join("Resources"),
        project_dir.join("app/src/main/assets"),
        project_dir.join("app"),
        project_dir.join("Contents/Resources"),
    ] {
        if dir.join("kototama-runtime-contract.edn").exists() {
            return validate_store_contract_oracle_if_present(
                &dir,
                "kototama-runtime-contract.edn",
                "kotoba-clj/selfhost/runtime_contract.kotoba",
                "runtime-contract-oracle",
                expected_exports,
                checks,
            );
        }
    }
    Ok(())
}

fn append_bundled_runtime_contract_oracle_checks(
    checks: &mut Vec<String>,
    expected_exports: &[(String, i64)],
) -> Result<()> {
    let oracle_wasm = kotoba_clj::selfhost::runtime_contract_oracle_wasm()
        .map_err(|err| anyhow!("compile bundled runtime contract oracle: {err}"))?;
    checks.push("component:compiled-from:kotoba-clj/selfhost/runtime_contract.kotoba".to_string());
    checks.push("component:sha256".to_string());
    checks.push("runtime-contract-oracle:bundled-component".to_string());
    checks.push(format!(
        "runtime-contract-oracle:wasm-sha256:{}",
        sha256_bytes_hex(&oracle_wasm)
    ));
    for (function, expected) in expected_exports {
        let actual = kotoba_clj::run::run_with_fuel(&oracle_wasm, function, &[], 1_000_000)
            .map_err(|err| anyhow!("run runtime contract Kotoba oracle `{function}`: {err}"))?;
        if actual == *expected {
            checks.push(format!("runtime-contract-oracle:{function}:{actual}"));
        } else {
            bail!("runtime contract `{function}` returned {actual}, expected {expected}");
        }
    }
    Ok(())
}

