fn validate_native_host_contract_oracle_if_present(
    target: Target,
    project_dir: &Path,
    checks: &mut Vec<String>,
) -> Result<()> {
    for dir in [
        project_dir.to_path_buf(),
        project_dir.join("Resources"),
        project_dir.join("app/src/main/assets"),
        project_dir.join("app"),
        project_dir.join("Contents/Resources"),
    ] {
        if dir.join("kototama-native-host-contract.edn").exists() {
            return validate_store_contract_oracle_if_present(
                &dir,
                "kototama-native-host-contract.edn",
                "kotoba-clj/selfhost/native_host_contract.kotoba",
                "native-host-contract-oracle",
                &native_host_contract_expected_exports(target),
                checks,
            );
        }
    }
    Ok(())
}

fn find_native_host_contract_dir(project_dir: &Path) -> Option<PathBuf> {
    [
        project_dir.to_path_buf(),
        project_dir.join("Resources"),
        project_dir.join("app/src/main/assets"),
        project_dir.join("app"),
        project_dir.join("Contents/Resources"),
    ]
    .into_iter()
    .find(|dir| dir.join("kototama-native-host-contract.edn").exists())
}

pub fn native_host_contract_check(
    target: Target,
    project_dir: impl AsRef<Path>,
) -> Result<NativeHostContractCheckReport> {
    let project_dir = project_dir.as_ref();
    let mut checks = Vec::new();
    let mut missing = Vec::new();
    let Some(contract_dir) = find_native_host_contract_dir(project_dir) else {
        missing.push(format!(
            "native host contract manifest is missing under {}",
            project_dir.display()
        ));
        return Ok(NativeHostContractCheckReport {
            schema: "kotoba-shell.native-host-contract-check.v0".to_string(),
            target,
            dir: project_dir.to_path_buf(),
            status: SdkCheckStatus::Failed,
            checks,
            missing,
            detail: "native host contract evidence is missing".to_string(),
        });
    };
    match validate_store_contract_oracle_if_present(
        &contract_dir,
        "kototama-native-host-contract.edn",
        "kotoba-clj/selfhost/native_host_contract.kotoba",
        "native-host-contract-oracle",
        &native_host_contract_expected_exports(target),
        &mut checks,
    ) {
        Ok(()) => {}
        Err(err) => missing.push(err.to_string()),
    }
    let status = if missing.is_empty() {
        SdkCheckStatus::Passed
    } else {
        SdkCheckStatus::Failed
    };
    let detail = if missing.is_empty() {
        format!(
            "{} native host bridge contract is backed by a bundled Kotoba oracle",
            target.as_str()
        )
    } else {
        format!(
            "native host bridge contract has {} unsatisfied requirement(s)",
            missing.len()
        )
    };
    Ok(NativeHostContractCheckReport {
        schema: "kotoba-shell.native-host-contract-check.v0".to_string(),
        target,
        dir: contract_dir,
        status,
        checks,
        missing,
        detail,
    })
}

fn append_project_check_contracts_if_present(
    schema: &str,
    target: Target,
    project_dir: &Path,
    checks: &mut Vec<String>,
) -> Result<()> {
    match schema {
        "kotoba-shell.sdk-check.v0" => {
            validate_sdk_contract_oracle_if_present(target, project_dir, checks)
        }
        "kotoba-shell.runtime-check.v0" => validate_runtime_contract_oracle_in_project_if_present(
            project_dir,
            checks,
            &runtime_check_contract_expected_exports(target),
        ),
        _ => Ok(()),
    }
}

