fn validate_kototama_app_components_evidence_contract(
    path: &Path,
    checks: &mut Vec<String>,
    missing: &mut Vec<String>,
) -> Result<()> {
    let json = read_evidence_json(path)?;
    let evidence_checks = evidence_checks_array(&json);
    for required in [
        "app-components-contract-oracle:bundled-component",
        "component:compiled-from:kotoba-clj/selfhost/app_components_contract.kotoba",
        "component:sha256",
        "app-components-contract-oracle:schema-digest:27569",
        "app-components-contract-oracle:admission-gate-digest:42448",
        "app-components-contract-oracle:analyzer-abi-digest:58866",
        "app-components-contract-oracle:contract-modulus:65521",
        "app-components-contract-oracle:required-manifest-field-count:8",
        "app-components-contract-oracle:required-component-field-count:12",
    ] {
        if evidence_checks.iter().any(|check| check == required) {
            checks.push(format!("required:kototama-app-components:{required}"));
        } else {
            missing.push(format!("{} evidence is missing {required}", path.display()));
        }
    }
    if evidence_checks
        .iter()
        .any(|check| check.starts_with("app-components-contract-oracle:wasm-sha256:"))
    {
        checks.push(
            "required:kototama-app-components:app-components-contract-oracle:wasm-sha256"
                .to_string(),
        );
    } else {
        missing.push(format!(
            "{} evidence is missing app-components-contract-oracle:wasm-sha256",
            path.display()
        ));
    }
    match json.get("admission_gate").and_then(|value| value.as_str()) {
        Some(actual) if is_safe_kotoba_admission_gate(actual) => {
            checks.push("required:kototama-app-components:admission_gate".to_string())
        }
        Some(actual) => missing.push(format!(
            "{} admission_gate is {actual}, expected {}",
            path.display(),
            safe_kotoba_admission_gate_expected()
        )),
        None => missing.push(format!(
            "{} is missing admission_gate {}",
            path.display(),
            safe_kotoba_admission_gate_expected()
        )),
    }
    match json.get("analyzer_abi").and_then(|value| value.as_str()) {
        Some(abi) if abi == kotoba_clj::selfhost::SAFE_ANALYZER_ABI => checks.push(format!(
            "required:kototama-app-components:analyzer_abi:{abi}"
        )),
        Some(actual) => missing.push(format!(
            "{} analyzer_abi is {actual}, expected {}",
            path.display(),
            kotoba_clj::selfhost::SAFE_ANALYZER_ABI
        )),
        None => missing.push(format!(
            "{} is missing analyzer_abi {}",
            path.display(),
            kotoba_clj::selfhost::SAFE_ANALYZER_ABI
        )),
    }
    match json
        .get("analyzer_component_sha256")
        .and_then(|value| value.as_str())
    {
        Some(value) if is_sha256_hex(value) => {
            checks.push("required:kototama-app-components:analyzer_component_sha256".to_string())
        }
        Some(actual) => missing.push(format!(
            "{} analyzer_component_sha256 is {actual}, expected 64 lowercase hex chars",
            path.display()
        )),
        None => missing.push(format!(
            "{} is missing analyzer_component_sha256",
            path.display()
        )),
    }
    let components = match json.get("components").and_then(|value| value.as_array()) {
        Some(components) if !components.is_empty() => {
            checks.push(format!(
                "required:kototama-app-components:components:{}",
                components.len()
            ));
            components
        }
        Some(_) => {
            missing.push(format!("{} has no component entries", path.display()));
            return Ok(());
        }
        None => {
            missing.push(format!("{} is missing components array", path.display()));
            return Ok(());
        }
    };
    match json.get("component_count").and_then(|value| value.as_u64()) {
        Some(count) if count as usize == components.len() => {
            checks.push("required:kototama-app-components:component_count".to_string())
        }
        Some(count) => missing.push(format!(
            "{} component_count is {count}, expected {}",
            path.display(),
            components.len()
        )),
        None => missing.push(format!("{} is missing component_count", path.display())),
    }
    match json
        .get("component_contract_digest")
        .and_then(|value| value.as_i64())
    {
        Some(value) if (0..65_521).contains(&value) => checks.push(format!(
            "required:kototama-app-components:component_contract_digest:{value}"
        )),
        Some(value) => missing.push(format!(
            "{} component_contract_digest is {value}, expected 0..65520",
            path.display()
        )),
        None => missing.push(format!(
            "{} is missing component_contract_digest",
            path.display()
        )),
    }
    for component in components {
        let id = component
            .get("id")
            .and_then(|value| value.as_str())
            .unwrap_or("<unknown>");
        match component
            .get("admission_gate")
            .and_then(|value| value.as_str())
        {
            Some(actual) if is_safe_kotoba_admission_gate(actual) => checks.push(format!(
                "required:kototama-app-components:{id}:admission_gate"
            )),
            Some(actual) => missing.push(format!(
                "{} component `{id}` admission_gate is {actual}, expected {}",
                path.display(),
                safe_kotoba_admission_gate_expected()
            )),
            None => missing.push(format!(
                "{} component `{id}` is missing admission_gate {}",
                path.display(),
                safe_kotoba_admission_gate_expected()
            )),
        }
        match component
            .get("analyzer_abi")
            .and_then(|value| value.as_str())
        {
            Some(abi) if abi == kotoba_clj::selfhost::SAFE_ANALYZER_ABI => checks.push(format!(
                "required:kototama-app-components:{id}:analyzer_abi:{abi}"
            )),
            Some(actual) => missing.push(format!(
                "{} component `{id}` analyzer_abi is {actual}, expected {}",
                path.display(),
                kotoba_clj::selfhost::SAFE_ANALYZER_ABI
            )),
            None => missing.push(format!(
                "{} component `{id}` is missing analyzer_abi {}",
                path.display(),
                kotoba_clj::selfhost::SAFE_ANALYZER_ABI
            )),
        }
        match component.get("sha256").and_then(|value| value.as_str()) {
            Some(value) if is_sha256_hex(value) => {
                checks.push(format!("required:kototama-app-components:{id}:sha256"))
            }
            Some(actual) => missing.push(format!(
                "{} component `{id}` sha256 is {actual}, expected 64 lowercase hex chars",
                path.display()
            )),
            None => missing.push(format!(
                "{} component `{id}` is missing sha256",
                path.display()
            )),
        }
        match component
            .get("source_sha256")
            .and_then(|value| value.as_str())
        {
            Some(value) if is_sha256_hex(value) => checks.push(format!(
                "required:kototama-app-components:{id}:source_sha256"
            )),
            Some(actual) => missing.push(format!(
                "{} component `{id}` source_sha256 is {actual}, expected 64 lowercase hex chars",
                path.display()
            )),
            None => missing.push(format!(
                "{} component `{id}` is missing source_sha256",
                path.display()
            )),
        }
        match component
            .get("policy_sha256")
            .and_then(|value| value.as_str())
        {
            Some(value) if is_sha256_hex(value) => checks.push(format!(
                "required:kototama-app-components:{id}:policy_sha256"
            )),
            Some(actual) => missing.push(format!(
                "{} component `{id}` policy_sha256 is {actual}, expected 64 lowercase hex chars",
                path.display()
            )),
            None => missing.push(format!(
                "{} component `{id}` is missing policy_sha256",
                path.display()
            )),
        }
    }
    Ok(())
}

