pub fn windows_runtime_contract_check(
    project_dir: impl AsRef<Path>,
) -> Result<WindowsRuntimeContractCheckReport> {
    let project_dir = project_dir.as_ref();
    let mut checks = Vec::new();
    let mut missing = Vec::new();

    match verify_windows_project(project_dir) {
        Ok(report) => {
            checks.push("windows:project-verified".to_string());
            checks.extend(
                report
                    .checks
                    .into_iter()
                    .map(|check| format!("windows:verify:{check}")),
            );
        }
        Err(err) => missing.push(format!("windows project verification failed: {err}")),
    }

    for (marker, rel, needles) in [
        (
            "windows:run-script:dotnet-run",
            "run.ps1",
            &["dotnet run", "kotoba-shell-windows.csproj"][..],
        ),
        (
            "windows:csproj:webview2",
            "kotoba-shell-windows.csproj",
            &["Microsoft.Web.WebView2", "net8.0-windows"][..],
        ),
        (
            "windows:host:webmessage",
            "src/MainWindow.xaml.cs",
            &["WebMessageReceived", "PostWebMessageAsJson"][..],
        ),
        (
            "windows:bridge:window.kotobaShell",
            "src/MainWindow.xaml.cs",
            &["window.kotobaShell", "chrome.webview.postMessage"][..],
        ),
        (
            "windows:ready-marker:KOTOBA_SHELL_READY",
            "src/MainWindow.xaml.cs",
            &["KOTOBA_SHELL_READY windows"][..],
        ),
        (
            "windows:surface-ready-marker:KOTOBA_SHELL_SURFACE_READY",
            "src/MainWindow.xaml.cs",
            &["KOTOBA_SHELL_SURFACE_READY windows"][..],
        ),
        (
            "windows:lifecycle-markers",
            "src/MainWindow.xaml.cs",
            &[
                "KOTOBA_SHELL_LIFECYCLE windows foreground",
                "KOTOBA_SHELL_LIFECYCLE windows background",
                "KOTOBA_SHELL_LIFECYCLE windows terminate",
            ][..],
        ),
        (
            "windows:updater-bridge",
            "src/MainWindow.xaml.cs",
            &[
                "updater.check",
                "updater.download",
                "updater.install",
                "WriteUpdaterReceipt",
            ][..],
        ),
        (
            "windows:ledger-append-bridge",
            "src/MainWindow.xaml.cs",
            &["ledger/append", "AppendLedger", "AllowLedgerAppend"][..],
        ),
    ] {
        let mut local_checks = Vec::new();
        match require_file(project_dir, rel, needles, &mut local_checks) {
            Ok(()) => checks.push(marker.to_string()),
            Err(err) => missing.push(format!("{marker} failed: {err}")),
        }
    }

    let status = if missing.is_empty() {
        SdkCheckStatus::Passed
    } else {
        SdkCheckStatus::Failed
    };
    let detail = if missing.is_empty() {
        "Windows WebView2 host runtime contract is release-ready for runner execution".to_string()
    } else {
        format!(
            "Windows runtime contract has {} unsatisfied requirement(s)",
            missing.len()
        )
    };
    Ok(WindowsRuntimeContractCheckReport {
        schema: "kotoba-shell.windows-runtime-contract-check.v0".to_string(),
        target: Target::Windows,
        project_dir: project_dir.to_path_buf(),
        status,
        checks,
        missing,
        detail,
    })
}

fn require_file(root: &Path, rel: &str, needles: &[&str], checks: &mut Vec<String>) -> Result<()> {
    require_file_at(&root.join(rel), needles, checks)
}

fn require_executable_file(root: &Path, rel: &str, checks: &mut Vec<String>) -> Result<()> {
    let path = root.join(rel);
    let metadata =
        std::fs::metadata(&path).with_context(|| format!("metadata {}", path.display()))?;
    if !metadata.is_file() {
        bail!("{} is not a file", path.display());
    }
    #[cfg(unix)]
    {
        use std::os::unix::fs::PermissionsExt;
        if metadata.permissions().mode() & 0o111 == 0 {
            bail!("{} is not executable", path.display());
        }
    }
    checks.push(path.display().to_string());
    Ok(())
}

