fn plugin_bundle_manifest_json(plan: &ShellPlan, target: Target, out_dir: &Path) -> Result<String> {
    let artifact_rel = "plugins/external-example-echo/plugin.wasm";
    let signature_rel = "plugins/external-example-echo/plugin.wasm.sig";
    let artifact_sha = sha256_hex(&out_dir.join(artifact_rel))?;
    let sample = serde_json::json!({
        "schema": "kotoba-shell.external-plugin.v0",
        "id": "external/example-echo",
        "version": "0.1.0",
        "abiVersion": "kotoba-shell-plugin-abi-0",
        "targets": [target.as_str()],
        "capability": "example/echo",
        "commands": ["example/echo"],
        "permission": {
            "mode": "deny-by-default-capability-grant",
            "source": "app.kotoba.edn",
            "capability": "example/echo"
        },
        "artifact": {
            "fileName": artifact_rel,
            "sha256": artifact_sha,
            "signature": "development-placeholder-signature",
            "signatureFile": signature_rel
        },
        "bridge": {
            "dispatch": "window.kotobaShell.invoke",
            "audit": "append-only-command-log"
        }
    });
    let manifest = serde_json::json!({
        "schema": "kotoba-shell.plugin-bundles.v0",
        "appId": plan.app_id,
        "appName": plan.app_name,
        "target": target.as_str(),
        "loader": {
            "enabled": true,
            "mode": "manifest-gated",
            "abiVersion": "kotoba-shell-plugin-abi-0",
            "pluginManifestSchema": "kotoba-shell.external-plugin.v0",
            "requireSignature": true,
            "requireSha256": true,
            "allowedHostImports": ["env.kotoba_host_audit"],
            "permissionModel": "deny-by-default-capability-grant",
            "execution": "wasmtime-fuel-with-allowlisted-host-imports"
        },
        "bundles": [sample]
    });
    serde_json::to_string_pretty(&manifest).map_err(Into::into)
}

fn write_plugin_bundle_artifacts(out_dir: &Path) -> Result<()> {
    let plugin_dir = out_dir.join("plugins/external-example-echo");
    std::fs::create_dir_all(&plugin_dir)
        .with_context(|| format!("create {}", plugin_dir.display()))?;
    let wasm = plugin_dir.join("plugin.wasm");
    std::fs::write(&wasm, plugin_sample_wasm_bytes())
        .with_context(|| format!("write {}", wasm.display()))?;
    let signature = plugin_dir.join("plugin.wasm.sig");
    std::fs::write(&signature, b"development-placeholder-signature\n")
        .with_context(|| format!("write {}", signature.display()))?;
    Ok(())
}

