pub fn plugin_sdk_check_manifest(
    target: Target,
    manifest: impl AsRef<Path>,
) -> Result<PluginSdkCheckReport> {
    let manifest = manifest.as_ref();
    let json = read_evidence_json(manifest)?;
    let mut checks = Vec::new();
    let mut missing = Vec::new();
    match require_json_string(&json, "schema", "kotoba-shell.plugin-sdk.v0", &mut checks) {
        Ok(()) => {}
        Err(err) => missing.push(err.to_string()),
    }
    match require_json_string(&json, "target", target.as_str(), &mut checks) {
        Ok(()) => {}
        Err(err) => missing.push(err.to_string()),
    }
    let required_plugin_field_count = json
        .get("requiredPluginFields")
        .and_then(|value| value.as_array())
        .map(|values| values.len() as i64)
        .unwrap_or(0);
    validate_plugin_contract_oracle_if_present(
        manifest,
        &mut checks,
        &mut missing,
        &[
            (
                "sdk-schema-digest",
                json.get("schema")
                    .and_then(|value| value.as_str())
                    .map(kototama_component_symbol_digest)
                    .unwrap_or(0),
            ),
            (
                "external-plugin-schema-digest",
                json.pointer("/samplePlugin/schema")
                    .and_then(|value| value.as_str())
                    .map(kototama_component_symbol_digest)
                    .unwrap_or(0),
            ),
            (
                "plugin-abi-digest",
                json.get("abiVersion")
                    .and_then(|value| value.as_str())
                    .map(kototama_component_symbol_digest)
                    .unwrap_or(0),
            ),
            (
                "permission-mode-digest",
                json.pointer("/samplePlugin/permission/mode")
                    .and_then(|value| value.as_str())
                    .map(kototama_component_symbol_digest)
                    .unwrap_or(0),
            ),
            ("required-plugin-field-count", required_plugin_field_count),
        ],
    )?;
    require_nested_json_string(&json, "abiVersion", &mut checks, &mut missing);
    require_nested_json_string(&json, "pluginManifestSchema", &mut checks, &mut missing);
    require_json_object(&json, "host", &mut checks, &mut missing);
    if let Some(values) = json
        .pointer("/host/wasmImports")
        .and_then(|value| value.as_array())
    {
        if values
            .iter()
            .any(|value| value.as_str() == Some("env.kotoba_host_audit"))
        {
            checks.push("host:wasmImports:env.kotoba_host_audit".to_string());
        } else {
            missing.push("host.wasmImports must include env.kotoba_host_audit".to_string());
        }
    } else {
        missing.push("host.wasmImports is missing".to_string());
    }
    require_json_array_non_empty(&json, "requiredPluginFields", &mut checks, &mut missing);
    require_json_object(&json, "samplePlugin", &mut checks, &mut missing);
    require_json_object(&json, "compatibility", &mut checks, &mut missing);
    if let Some(sample) = json.get("samplePlugin") {
        match sample.get("schema").and_then(|value| value.as_str()) {
            Some("kotoba-shell.external-plugin.v0") => {
                checks.push("samplePlugin:schema:kotoba-shell.external-plugin.v0".to_string())
            }
            Some(schema) => missing.push(format!(
                "samplePlugin schema is {schema}, expected kotoba-shell.external-plugin.v0"
            )),
            None => missing.push("samplePlugin.schema is missing".to_string()),
        }
        for key in ["id", "version", "capability", "permission"] {
            if sample.get(key).is_some() {
                checks.push(format!("samplePlugin:{key}"));
            } else {
                missing.push(format!("samplePlugin.{key} is missing"));
            }
        }
        match sample.get("commands").and_then(|value| value.as_array()) {
            Some(commands) if !commands.is_empty() => {
                checks.push(format!("samplePlugin:commands:{}", commands.len()))
            }
            Some(_) => missing.push("samplePlugin.commands is empty".to_string()),
            None => missing.push("samplePlugin.commands is missing".to_string()),
        }
    }
    let abi_version = json
        .get("abiVersion")
        .and_then(|value| value.as_str())
        .unwrap_or_default()
        .to_string();
    let status = if missing.is_empty() {
        SdkCheckStatus::Passed
    } else {
        SdkCheckStatus::Failed
    };
    let detail = if missing.is_empty() {
        format!("plugin SDK contract is compatible with {abi_version}")
    } else {
        format!(
            "plugin SDK contract has {} unsatisfied requirement(s)",
            missing.len()
        )
    };
    Ok(PluginSdkCheckReport {
        schema: "kotoba-shell.plugin-sdk-check.v0".to_string(),
        target,
        manifest: manifest.to_path_buf(),
        status,
        abi_version,
        checks,
        missing,
        detail,
    })
}

pub fn plugin_load_check_manifest(
    target: Target,
    manifest: impl AsRef<Path>,
) -> Result<PluginLoadCheckReport> {
    let manifest = manifest.as_ref();
    let json = read_evidence_json(manifest)?;
    let mut checks = Vec::new();
    let mut missing = Vec::new();
    match require_json_string(
        &json,
        "schema",
        "kotoba-shell.plugin-bundles.v0",
        &mut checks,
    ) {
        Ok(()) => {}
        Err(err) => missing.push(err.to_string()),
    }
    match require_json_string(&json, "target", target.as_str(), &mut checks) {
        Ok(()) => {}
        Err(err) => missing.push(err.to_string()),
    }
    let loader_boolean_count = [
        "/loader/enabled",
        "/loader/requireSignature",
        "/loader/requireSha256",
    ]
    .iter()
    .filter(|pointer| json.pointer(pointer).and_then(|value| value.as_bool()) == Some(true))
    .count() as i64;
    validate_plugin_contract_oracle_if_present(
        manifest,
        &mut checks,
        &mut missing,
        &[
            (
                "bundle-schema-digest",
                json.get("schema")
                    .and_then(|value| value.as_str())
                    .map(kototama_component_symbol_digest)
                    .unwrap_or(0),
            ),
            (
                "external-plugin-schema-digest",
                json.pointer("/bundles/0/schema")
                    .and_then(|value| value.as_str())
                    .map(kototama_component_symbol_digest)
                    .unwrap_or(0),
            ),
            (
                "plugin-abi-digest",
                json.pointer("/loader/abiVersion")
                    .and_then(|value| value.as_str())
                    .map(kototama_component_symbol_digest)
                    .unwrap_or(0),
            ),
            (
                "permission-mode-digest",
                json.pointer("/bundles/0/permission/mode")
                    .and_then(|value| value.as_str())
                    .map(kototama_component_symbol_digest)
                    .unwrap_or(0),
            ),
            (
                "audit-import-digest",
                json.pointer("/loader/allowedHostImports/0")
                    .and_then(|value| value.as_str())
                    .map(kototama_component_symbol_digest)
                    .unwrap_or(0),
            ),
            (
                "loader-mode-digest",
                json.pointer("/loader/mode")
                    .and_then(|value| value.as_str())
                    .map(kototama_component_symbol_digest)
                    .unwrap_or(0),
            ),
            ("required-loader-boolean-count", loader_boolean_count),
        ],
    )?;
    require_json_object(&json, "loader", &mut checks, &mut missing);
    require_json_array_non_empty(&json, "bundles", &mut checks, &mut missing);
    for pointer in [
        "/loader/enabled",
        "/loader/requireSignature",
        "/loader/requireSha256",
    ] {
        match json.pointer(pointer).and_then(|value| value.as_bool()) {
            Some(true) => checks.push(format!("{pointer}:true")),
            Some(false) => missing.push(format!("{pointer} must be true")),
            None => missing.push(format!("{pointer} is missing or not a boolean")),
        }
    }
    for (pointer, expected) in [
        ("/loader/mode", "manifest-gated"),
        ("/loader/abiVersion", "kotoba-shell-plugin-abi-0"),
        (
            "/loader/pluginManifestSchema",
            "kotoba-shell.external-plugin.v0",
        ),
        (
            "/loader/permissionModel",
            "deny-by-default-capability-grant",
        ),
    ] {
        match json.pointer(pointer).and_then(|value| value.as_str()) {
            Some(value) if value == expected => checks.push(format!("{pointer}:{expected}")),
            Some(value) => missing.push(format!("{pointer} must be {expected}, got {value}")),
            None => missing.push(format!("{pointer} is missing")),
        }
    }
    let allowed_host_imports = match json
        .pointer("/loader/allowedHostImports")
        .and_then(|value| value.as_array())
    {
        Some(values) if !values.is_empty() => {
            let imports = values
                .iter()
                .filter_map(|value| value.as_str())
                .map(str::to_string)
                .collect::<BTreeSet<_>>();
            if imports.contains("env.kotoba_host_audit") {
                checks.push("/loader/allowedHostImports:env.kotoba_host_audit".to_string());
            } else {
                missing.push(
                    "/loader/allowedHostImports must include env.kotoba_host_audit".to_string(),
                );
            }
            imports
        }
        Some(_) => {
            missing.push("/loader/allowedHostImports is empty".to_string());
            BTreeSet::new()
        }
        None => {
            missing.push("/loader/allowedHostImports is missing".to_string());
            BTreeSet::new()
        }
    };

    let mut bundles = Vec::new();
    let mut commands = BTreeSet::new();
    if let Some(items) = json.get("bundles").and_then(|value| value.as_array()) {
        for (index, bundle) in items.iter().enumerate() {
            let label = format!("bundles[{index}]");
            match bundle.get("schema").and_then(|value| value.as_str()) {
                Some("kotoba-shell.external-plugin.v0") => {
                    checks.push(format!("{label}:schema:kotoba-shell.external-plugin.v0"))
                }
                Some(schema) => missing.push(format!(
                    "{label}.schema is {schema}, expected kotoba-shell.external-plugin.v0"
                )),
                None => missing.push(format!("{label}.schema is missing")),
            }
            match bundle.get("id").and_then(|value| value.as_str()) {
                Some(id) if !id.is_empty() => {
                    bundles.push(id.to_string());
                    checks.push(format!("{label}:id:{id}"));
                }
                _ => missing.push(format!("{label}.id is missing")),
            }
            match bundle.get("abiVersion").and_then(|value| value.as_str()) {
                Some("kotoba-shell-plugin-abi-0") => checks.push(format!("{label}:abi")),
                Some(value) => missing.push(format!("{label}.abiVersion is unsupported: {value}")),
                None => missing.push(format!("{label}.abiVersion is missing")),
            }
            require_json_string_array_contains(
                bundle,
                "targets",
                target.as_str(),
                &mut checks,
                &mut missing,
            );
            let mut bundle_commands = Vec::new();
            match bundle.get("commands").and_then(|value| value.as_array()) {
                Some(values) if !values.is_empty() => {
                    for command in values.iter().filter_map(|value| value.as_str()) {
                        if command.contains('/') {
                            commands.insert(command.to_string());
                            bundle_commands.push(command.to_string());
                            checks.push(format!("{label}:command:{command}"));
                        } else {
                            missing.push(format!(
                                "{label}.commands entry `{command}` is not namespaced"
                            ));
                        }
                    }
                }
                Some(_) => missing.push(format!("{label}.commands is empty")),
                None => missing.push(format!("{label}.commands is missing")),
            }
            match bundle
                .pointer("/permission/mode")
                .and_then(|value| value.as_str())
            {
                Some("deny-by-default-capability-grant") => {
                    checks.push(format!("{label}:permission:deny-by-default"))
                }
                Some(value) => {
                    missing.push(format!("{label}.permission.mode is unsupported: {value}"))
                }
                None => missing.push(format!("{label}.permission.mode is missing")),
            }
            for pointer in ["/artifact/fileName", "/artifact/signature"] {
                match bundle.pointer(pointer).and_then(|value| value.as_str()) {
                    Some(value) if !value.is_empty() => {
                        checks.push(format!("{label}{pointer}:present"))
                    }
                    Some(_) => missing.push(format!("{label}{pointer} is empty")),
                    None => missing.push(format!("{label}{pointer} is missing")),
                }
            }
            let artifact_path = bundle
                .pointer("/artifact/fileName")
                .and_then(|value| value.as_str())
                .map(|file| resolve_manifest_relative(manifest, file));
            match bundle
                .pointer("/artifact/sha256")
                .and_then(|value| value.as_str())
            {
                Some(value) if is_sha256_hex(value) => match &artifact_path {
                    Some(path) if path.is_file() => {
                        let actual = sha256_hex(path)?;
                        if actual == value {
                            checks.push(format!("{label}:artifact:sha256"));
                            checks.push(format!("{label}:artifact:file:{}", path.display()));
                            match plugin_sandbox_instantiate(
                                path,
                                &bundle_commands,
                                &allowed_host_imports,
                            ) {
                                Ok(sandbox_checks) => checks.extend(
                                    sandbox_checks
                                        .into_iter()
                                        .map(|check| format!("{label}:{check}")),
                                ),
                                Err(err) => {
                                    missing.push(format!("{label}.artifact sandbox failed: {err}"))
                                }
                            }
                        } else {
                            missing.push(format!(
                                "{label}.artifact.sha256 mismatch: expected {value}, got {actual}"
                            ));
                        }
                    }
                    Some(path) => missing.push(format!(
                        "{label}.artifact file is missing: {}",
                        path.display()
                    )),
                    None => missing.push(format!("{label}.artifact.fileName is missing")),
                },
                Some(_) => missing.push(format!(
                    "{label}.artifact.sha256 must be 64 lowercase hex chars"
                )),
                None => missing.push(format!("{label}.artifact.sha256 is missing")),
            }
            match bundle
                .pointer("/artifact/signatureFile")
                .and_then(|value| value.as_str())
            {
                Some(file) if !file.is_empty() => {
                    let signature_path = resolve_manifest_relative(manifest, file);
                    match std::fs::read_to_string(&signature_path) {
                        Ok(text) if !text.trim().is_empty() => {
                            checks.push(format!("{label}:artifact:signatureFile"))
                        }
                        Ok(_) => missing.push(format!(
                            "{label}.artifact.signatureFile is empty: {}",
                            signature_path.display()
                        )),
                        Err(_) => missing.push(format!(
                            "{label}.artifact.signatureFile is missing: {}",
                            signature_path.display()
                        )),
                    }
                }
                Some(_) => missing.push(format!("{label}.artifact.signatureFile is empty")),
                None => missing.push(format!("{label}.artifact.signatureFile is missing")),
            }
        }
    }
    let status = if missing.is_empty() {
        SdkCheckStatus::Passed
    } else {
        SdkCheckStatus::Failed
    };
    let detail = if missing.is_empty() {
        format!(
            "external plugin bundle loader is manifest-gated for {} bundle(s)",
            bundles.len()
        )
    } else {
        format!(
            "external plugin bundle loader has {} unsatisfied requirement(s)",
            missing.len()
        )
    };
    Ok(PluginLoadCheckReport {
        schema: "kotoba-shell.plugin-load-check.v0".to_string(),
        target,
        manifest: manifest.to_path_buf(),
        status,
        bundles,
        commands: commands.into_iter().collect(),
        checks,
        missing,
        detail,
    })
}

#[derive(Default)]
struct PluginHostState {
    audit_calls: Vec<i64>,
}

fn plugin_sandbox_instantiate(
    path: &Path,
    commands: &[String],
    allowed_host_imports: &BTreeSet<String>,
) -> Result<Vec<String>> {
    let bytes = std::fs::read(path).with_context(|| format!("read {}", path.display()))?;
    let mut config = wasmtime::Config::new();
    config.consume_fuel(true);
    let engine = wasmtime::Engine::new(&config)?;
    let module = wasmtime::Module::new(&engine, &bytes)
        .with_context(|| format!("compile plugin wasm {}", path.display()))?;
    let imports = module
        .imports()
        .map(|import| format!("{}.{}", import.module(), import.name()))
        .collect::<Vec<_>>();
    let import_count = imports.len();
    for import in &imports {
        if !allowed_host_imports.contains(import) {
            bail!("plugin wasm import {import} is not allowed by the current sandbox ABI");
        }
    }
    let mut linker = wasmtime::Linker::new(&engine);
    linker.func_wrap(
        "env",
        "kotoba_host_audit",
        |mut caller: wasmtime::Caller<'_, PluginHostState>, value: i64| -> i64 {
            caller.data_mut().audit_calls.push(value);
            value
        },
    )?;
    let mut store = wasmtime::Store::new(&engine, PluginHostState::default());
    store.set_fuel(10_000)?;
    let instance = linker
        .instantiate(&mut store, &module)
        .with_context(|| format!("instantiate plugin wasm {}", path.display()))?;
    let export_count = module.exports().count();
    let mut checks = vec![
        "sandbox:wasmtime-compile".to_string(),
        "sandbox:wasmtime-instantiate".to_string(),
        "sandbox:fuel:10000".to_string(),
        format!("sandbox:imports:{import_count}"),
        format!("sandbox:exports:{export_count}"),
    ];
    for import in imports {
        checks.push(format!("sandbox:host-import:{import}"));
    }
    for command in commands {
        let export = plugin_command_export(command);
        let entrypoint = instance
            .get_typed_func::<i64, i64>(&mut store, &export)
            .with_context(|| format!("load plugin command export {export} for {command}"))?;
        let result = entrypoint
            .call(&mut store, 41)
            .with_context(|| format!("invoke plugin command export {export} for {command}"))?;
        if result != 41 {
            bail!("plugin command export {export} returned {result}, expected 41");
        }
        checks.push(format!("sandbox:command:{command}"));
        checks.push(format!("sandbox:export:{export}"));
        checks.push(format!("sandbox:invoke:{export}:41"));
    }
    let audit_calls = store.data().audit_calls.len();
    if audit_calls < commands.len() {
        bail!(
            "plugin host audit import was called {audit_calls} time(s), expected at least {}",
            commands.len()
        );
    }
    checks.push(format!("sandbox:host-audit-calls:{audit_calls}"));
    Ok(checks)
}

fn plugin_command_export(command: &str) -> String {
    command
        .chars()
        .map(|ch| match ch {
            'a'..='z' | 'A'..='Z' | '0'..='9' => ch,
            _ => '_',
        })
        .collect()
}

fn validate_plugin_contract_oracle_if_present(
    manifest: &Path,
    checks: &mut Vec<String>,
    missing: &mut Vec<String>,
    expected_exports: &[(&str, i64)],
) -> Result<()> {
    let Some(root) = manifest.parent() else {
        return Ok(());
    };
    let oracle_manifest = root.join("kototama-plugin-contract.edn");
    if !oracle_manifest.exists() {
        return Ok(());
    }
    let oracle_wasm = match read_kototama_component_manifest_wasm(
        &oracle_manifest,
        "kotoba-clj/selfhost/plugin_contract.kotoba",
        checks,
        missing,
    ) {
        Ok(wasm) => wasm,
        Err(err) => {
            missing.push(format!("plugin contract oracle cannot be verified: {err}"));
            return Ok(());
        }
    };
    checks.push("plugin-contract-oracle:bundled-component".to_string());
    checks.push(format!(
        "plugin-contract-oracle:wasm-sha256:{}",
        sha256_bytes_hex(&oracle_wasm)
    ));
    for (function, expected) in expected_exports {
        let actual = kotoba_clj::run::run_with_fuel(&oracle_wasm, function, &[], 1_000_000)
            .map_err(|err| anyhow!("run plugin contract Kotoba oracle `{function}`: {err}"))?;
        if actual == *expected {
            checks.push(format!("plugin-contract-oracle:{function}:{actual}"));
        } else {
            missing.push(format!(
                "plugin contract oracle `{function}` returned {actual}, expected {expected}"
            ));
        }
    }
    Ok(())
}

fn validate_compatibility_contract_oracle_if_present(
    manifest: &Path,
    checks: &mut Vec<String>,
    missing: &mut Vec<String>,
    expected_exports: &[(&str, i64)],
) -> Result<()> {
    let Some(root) = manifest.parent() else {
        return Ok(());
    };
    let oracle_manifest = root.join("kototama-compatibility-contract.edn");
    if !oracle_manifest.exists() {
        return Ok(());
    }
    let oracle_wasm = match read_kototama_component_manifest_wasm(
        &oracle_manifest,
        "kotoba-clj/selfhost/compatibility_contract.kotoba",
        checks,
        missing,
    ) {
        Ok(wasm) => wasm,
        Err(err) => {
            missing.push(format!(
                "compatibility contract oracle cannot be verified: {err}"
            ));
            return Ok(());
        }
    };
    checks.push("compatibility-contract-oracle:bundled-component".to_string());
    checks.push(format!(
        "compatibility-contract-oracle:wasm-sha256:{}",
        sha256_bytes_hex(&oracle_wasm)
    ));
    for (function, expected) in expected_exports {
        let actual = kotoba_clj::run::run_with_fuel(&oracle_wasm, function, &[], 1_000_000)
            .map_err(|err| {
                anyhow!("run compatibility contract Kotoba oracle `{function}`: {err}")
            })?;
        if actual == *expected {
            checks.push(format!("compatibility-contract-oracle:{function}:{actual}"));
        } else {
            missing.push(format!(
                "compatibility contract oracle `{function}` returned {actual}, expected {expected}"
            ));
        }
    }
    Ok(())
}

fn compatibility_policy_json(plan: &ShellPlan, target: Target) -> Result<String> {
    let manifest = serde_json::json!({
        "schema": "kotoba-shell.compatibility.v0",
        "appId": plan.app_id,
        "appName": plan.app_name,
        "target": target.as_str(),
        "policyVersion": "0.1.0",
        "stability": "alpha",
        "channels": ["dev", "internal", "stable"],
        "abi": {
            "plugin": "kotoba-shell-plugin-abi-0",
            "shellBridge": "window.kotobaShell.invoke",
            "messageEvent": "kotoba-shell-message",
            "safeCljPolicy": "deny-by-default"
        },
        "schemaCompatibility": {
            "evidence": "same-major-required",
            "releaseMetadata": "same-major-required",
            "pluginManifest": "same-major-required",
            "aiueosSurface": "same-major-required"
        },
        "deprecationPolicy": {
            "minimumNoticeDays": 90,
            "removalRequiresMajor": true,
            "releaseNotesRequired": true
        },
        "migrationPolicy": {
            "manifestMigrationRequired": true,
            "evidenceProfileMigrationRequired": true,
            "backwardCompatibilityTestsRequired": true
        },
        "knownSchemas": [
            "kotoba-shell.release.v0",
            "kotoba-shell.permissions.v0",
            "kotoba-shell.plugins.v0",
            "kotoba-shell.plugin-sdk.v0",
            "kotoba-shell.plugin-bundles.v0",
            "kotoba-shell.app-surface.v0",
            "aiueos.shell.surface.v0"
        ]
    });
    serde_json::to_string_pretty(&manifest).map_err(Into::into)
}

pub fn compatibility_check_manifest(
    target: Target,
    manifest: impl AsRef<Path>,
) -> Result<CompatibilityCheckReport> {
    let manifest = manifest.as_ref();
    let json = read_evidence_json(manifest)?;
    let mut checks = Vec::new();
    let mut missing = Vec::new();
    match require_json_string(
        &json,
        "schema",
        "kotoba-shell.compatibility.v0",
        &mut checks,
    ) {
        Ok(()) => {}
        Err(err) => missing.push(err.to_string()),
    }
    match require_json_string(&json, "target", target.as_str(), &mut checks) {
        Ok(()) => {}
        Err(err) => missing.push(err.to_string()),
    }
    let policy_boolean_count = [
        "/deprecationPolicy/removalRequiresMajor",
        "/deprecationPolicy/releaseNotesRequired",
        "/migrationPolicy/manifestMigrationRequired",
        "/migrationPolicy/evidenceProfileMigrationRequired",
        "/migrationPolicy/backwardCompatibilityTestsRequired",
    ]
    .iter()
    .filter(|pointer| json.pointer(pointer).and_then(|value| value.as_bool()) == Some(true))
    .count() as i64;
    let known_schema_count = json
        .get("knownSchemas")
        .and_then(|value| value.as_array())
        .map(|values| values.len() as i64)
        .unwrap_or(0);
    let minimum_notice_days = json
        .pointer("/deprecationPolicy/minimumNoticeDays")
        .and_then(|value| value.as_u64())
        .unwrap_or_default() as i64;
    validate_compatibility_contract_oracle_if_present(
        manifest,
        &mut checks,
        &mut missing,
        &[
            (
                "schema-digest",
                json.get("schema")
                    .and_then(|value| value.as_str())
                    .map(kototama_component_symbol_digest)
                    .unwrap_or(0),
            ),
            (
                "policy-version-digest",
                json.get("policyVersion")
                    .and_then(|value| value.as_str())
                    .map(kototama_component_symbol_digest)
                    .unwrap_or(0),
            ),
            (
                "stability-digest",
                json.get("stability")
                    .and_then(|value| value.as_str())
                    .map(kototama_component_symbol_digest)
                    .unwrap_or(0),
            ),
            (
                "plugin-abi-digest",
                json.pointer("/abi/plugin")
                    .and_then(|value| value.as_str())
                    .map(kototama_component_symbol_digest)
                    .unwrap_or(0),
            ),
            (
                "shell-bridge-digest",
                json.pointer("/abi/shellBridge")
                    .and_then(|value| value.as_str())
                    .map(kototama_component_symbol_digest)
                    .unwrap_or(0),
            ),
            (
                "message-event-digest",
                json.pointer("/abi/messageEvent")
                    .and_then(|value| value.as_str())
                    .map(kototama_component_symbol_digest)
                    .unwrap_or(0),
            ),
            (
                "schema-compatibility-digest",
                json.pointer("/schemaCompatibility/evidence")
                    .and_then(|value| value.as_str())
                    .map(kototama_component_symbol_digest)
                    .unwrap_or(0),
            ),
            ("minimum-notice-days", minimum_notice_days),
            ("required-policy-boolean-count", policy_boolean_count),
            ("known-schema-count", known_schema_count),
        ],
    )?;
    require_nested_json_string(&json, "policyVersion", &mut checks, &mut missing);
    require_nested_json_string(&json, "stability", &mut checks, &mut missing);
    require_json_array_non_empty(&json, "channels", &mut checks, &mut missing);
    require_json_object(&json, "abi", &mut checks, &mut missing);
    require_json_object(&json, "schemaCompatibility", &mut checks, &mut missing);
    require_json_object(&json, "deprecationPolicy", &mut checks, &mut missing);
    require_json_object(&json, "migrationPolicy", &mut checks, &mut missing);
    require_json_array_non_empty(&json, "knownSchemas", &mut checks, &mut missing);
    let notice_days = json
        .pointer("/deprecationPolicy/minimumNoticeDays")
        .and_then(|value| value.as_u64())
        .unwrap_or_default();
    if notice_days >= 90 {
        checks.push(format!("deprecationPolicy:minimumNoticeDays:{notice_days}"));
    } else {
        missing.push("deprecationPolicy.minimumNoticeDays must be >= 90".to_string());
    }
    for pointer in [
        "/deprecationPolicy/removalRequiresMajor",
        "/deprecationPolicy/releaseNotesRequired",
        "/migrationPolicy/manifestMigrationRequired",
        "/migrationPolicy/evidenceProfileMigrationRequired",
        "/migrationPolicy/backwardCompatibilityTestsRequired",
    ] {
        match json.pointer(pointer).and_then(|value| value.as_bool()) {
            Some(true) => checks.push(format!("{pointer}:true")),
            Some(false) => missing.push(format!("{pointer} must be true")),
            None => missing.push(format!("{pointer} is missing or not a boolean")),
        }
    }
    let policy_version = json
        .get("policyVersion")
        .and_then(|value| value.as_str())
        .unwrap_or_default()
        .to_string();
    let status = if missing.is_empty() {
        SdkCheckStatus::Passed
    } else {
        SdkCheckStatus::Failed
    };
    let detail = if missing.is_empty() {
        format!("compatibility policy {policy_version} is release-ready")
    } else {
        format!(
            "compatibility policy has {} unsatisfied requirement(s)",
            missing.len()
        )
    };
    Ok(CompatibilityCheckReport {
        schema: "kotoba-shell.compatibility-check.v0".to_string(),
        target,
        manifest: manifest.to_path_buf(),
        status,
        policy_version,
        checks,
        missing,
        detail,
    })
}

pub fn compatibility_migration_check(
    target: Target,
    previous: impl AsRef<Path>,
    current: impl AsRef<Path>,
) -> Result<CompatibilityMigrationCheckReport> {
    let previous = previous.as_ref();
    let current = current.as_ref();
    let previous_json = read_evidence_json(previous)?;
    let current_json = read_evidence_json(current)?;
    let previous_check = compatibility_check_manifest(target, previous)?;
    let current_check = compatibility_check_manifest(target, current)?;
    let mut checks = Vec::new();
    let mut missing = Vec::new();

    if previous_check.status == SdkCheckStatus::Passed {
        checks.push("previous:compatibility-check:Passed".to_string());
    } else {
        missing.push(format!(
            "previous compatibility policy is not release-ready: {}",
            previous_check.detail
        ));
    }
    if current_check.status == SdkCheckStatus::Passed {
        checks.push("current:compatibility-check:Passed".to_string());
    } else {
        missing.push(format!(
            "current compatibility policy is not release-ready: {}",
            current_check.detail
        ));
    }

    let previous_policy_version = previous_check.policy_version;
    let current_policy_version = current_check.policy_version;
    if same_major_version(&previous_policy_version, &current_policy_version) {
        checks.push(format!(
            "policyVersion:same-major:{previous_policy_version}->{current_policy_version}"
        ));
    } else {
        missing.push(format!(
            "policyVersion must keep the same major for migration evidence: {previous_policy_version}->{current_policy_version}"
        ));
    }

    for pointer in ["/abi/plugin", "/abi/shellBridge", "/abi/messageEvent"] {
        match (previous_json.pointer(pointer), current_json.pointer(pointer)) {
            (Some(previous_value), Some(current_value)) if previous_value == current_value => {
                checks.push(format!("{pointer}:unchanged"))
            }
            (Some(previous_value), Some(current_value)) => missing.push(format!(
                "{pointer} changed from {previous_value} to {current_value}; major migration evidence is required"
            )),
            _ => missing.push(format!("{pointer} must exist in both compatibility manifests")),
        }
    }

    require_string_array_subset(
        &previous_json,
        &current_json,
        "channels",
        &mut checks,
        &mut missing,
    )?;
    require_string_array_subset(
        &previous_json,
        &current_json,
        "knownSchemas",
        &mut checks,
        &mut missing,
    )?;
    for pointer in [
        "/migrationPolicy/manifestMigrationRequired",
        "/migrationPolicy/evidenceProfileMigrationRequired",
        "/migrationPolicy/backwardCompatibilityTestsRequired",
    ] {
        match current_json
            .pointer(pointer)
            .and_then(|value| value.as_bool())
        {
            Some(true) => checks.push(format!("current:{pointer}:true")),
            Some(false) => missing.push(format!("current {pointer} must be true")),
            None => missing.push(format!("current {pointer} is missing or not a boolean")),
        }
    }

    let previous_sha256 = sha256_hex(previous)?;
    let current_sha256 = sha256_hex(current)?;
    checks.push(format!("previous:sha256:{previous_sha256}"));
    checks.push(format!("current:sha256:{current_sha256}"));

    let status = if missing.is_empty() {
        SdkCheckStatus::Passed
    } else {
        SdkCheckStatus::Failed
    };
    let detail = if missing.is_empty() {
        format!("compatibility migration {previous_policy_version}->{current_policy_version} is release-ready")
    } else {
        format!(
            "compatibility migration has {} unsatisfied requirement(s)",
            missing.len()
        )
    };
    Ok(CompatibilityMigrationCheckReport {
        schema: "kotoba-shell.compatibility-migration-check.v0".to_string(),
        target,
        previous: previous.to_path_buf(),
        current: current.to_path_buf(),
        status,
        previous_policy_version,
        current_policy_version,
        previous_sha256,
        current_sha256,
        checks,
        missing,
        detail,
    })
}

fn same_major_version(previous: &str, current: &str) -> bool {
    previous.split('.').next() == current.split('.').next()
}

fn require_string_array_subset(
    previous: &serde_json::Value,
    current: &serde_json::Value,
    key: &str,
    checks: &mut Vec<String>,
    missing: &mut Vec<String>,
) -> Result<()> {
    let previous_values = json_string_array(previous, key)?;
    let current_values = json_string_array(current, key)?;
    let current_set: BTreeSet<_> = current_values.iter().collect();
    for value in &previous_values {
        if current_set.contains(value) {
            checks.push(format!("{key}:preserved:{value}"));
        } else {
            missing.push(format!(
                "{key} entry `{value}` from previous policy is missing"
            ));
        }
    }
    Ok(())
}

pub fn plugin_check_manifest(
    target: Target,
    manifest: impl AsRef<Path>,
) -> Result<PluginCheckReport> {
    let manifest = manifest.as_ref();
    let json = read_evidence_json(manifest)?;
    let mut checks = Vec::new();
    let mut missing = Vec::new();
    match require_json_string(&json, "schema", "kotoba-shell.plugins.v0", &mut checks) {
        Ok(()) => {}
        Err(err) => missing.push(err.to_string()),
    }
    match require_json_string(&json, "target", target.as_str(), &mut checks) {
        Ok(()) => {}
        Err(err) => missing.push(err.to_string()),
    }
    validate_plugin_contract_oracle_if_present(
        manifest,
        &mut checks,
        &mut missing,
        &[
            (
                "registry-schema-digest",
                json.get("schema")
                    .and_then(|value| value.as_str())
                    .map(kototama_component_symbol_digest)
                    .unwrap_or(0),
            ),
            (
                "permission-mode-digest",
                json.pointer("/plugins/0/permission/mode")
                    .and_then(|value| value.as_str())
                    .map(kototama_component_symbol_digest)
                    .unwrap_or(0),
            ),
        ],
    )?;
    require_json_object(&json, "registry", &mut checks, &mut missing);
    require_json_array_non_empty(&json, "plugins", &mut checks, &mut missing);
    let mut plugins = Vec::new();
    let mut commands = BTreeSet::new();
    if let Some(items) = json.get("plugins").and_then(|value| value.as_array()) {
        for (index, plugin) in items.iter().enumerate() {
            let label = format!("plugins[{index}]");
            match plugin.get("id").and_then(|value| value.as_str()) {
                Some(id) if !id.is_empty() => {
                    plugins.push(id.to_string());
                    checks.push(format!("{label}:id:{id}"));
                }
                _ => missing.push(format!("{label}.id is missing")),
            }
            match plugin.get("capability").and_then(|value| value.as_str()) {
                Some(capability) if !capability.is_empty() => {
                    checks.push(format!("{label}:capability:{capability}"));
                }
                _ => missing.push(format!("{label}.capability is missing")),
            }
            match plugin.get("commands").and_then(|value| value.as_array()) {
                Some(values) if !values.is_empty() => {
                    for value in values {
                        if let Some(command) = value.as_str() {
                            commands.insert(command.to_string());
                        }
                    }
                    checks.push(format!("{label}:commands:{}", values.len()));
                }
                Some(_) => missing.push(format!("{label}.commands is empty")),
                None => missing.push(format!("{label}.commands is missing")),
            }
            let has_target = plugin
                .get("targets")
                .and_then(|value| value.as_array())
                .map(|targets| {
                    targets
                        .iter()
                        .any(|value| value.as_str() == Some(target.as_str()))
                })
                .unwrap_or(false);
            if has_target {
                checks.push(format!("{label}:target:{}", target.as_str()));
            } else {
                missing.push(format!("{label}.targets is missing {}", target.as_str()));
            }
            if plugin
                .get("permission")
                .and_then(|value| value.as_object())
                .is_some()
            {
                checks.push(format!("{label}:permission"));
            } else {
                missing.push(format!("{label}.permission is missing"));
            }
        }
    }
    let status = if missing.is_empty() {
        SdkCheckStatus::Passed
    } else {
        SdkCheckStatus::Failed
    };
    let detail = if missing.is_empty() {
        format!(
            "plugin contract covers {} plugin(s) and {} command(s)",
            plugins.len(),
            commands.len()
        )
    } else {
        format!(
            "plugin contract has {} unsatisfied requirement(s)",
            missing.len()
        )
    };
    Ok(PluginCheckReport {
        schema: "kotoba-shell.plugin-check.v0".to_string(),
        target,
        manifest: manifest.to_path_buf(),
        status,
        plugins,
        commands: commands.into_iter().collect(),
        checks,
        missing,
        detail,
    })
}

fn app_surface_manifest_json(plan: &ShellPlan, target: Target) -> Result<String> {
    let capabilities = target_capabilities(plan, target);
    let has_notifications = capabilities
        .iter()
        .any(|c| c == "notify/show" || c == "notify/push");
    let has_clipboard = capabilities.iter().any(|c| is_clipboard_capability(c));
    let tray_status = match target {
        Target::Macos => "native-runner",
        Target::Windows => "planned-native",
        Target::Ios | Target::Android => "not-applicable-mobile",
    };
    let menu_status = match target {
        Target::Macos => "native-runner",
        Target::Windows => "planned-native",
        Target::Ios | Target::Android => "system-managed-mobile",
    };
    let manifest = serde_json::json!({
        "schema": "kotoba-shell.app-surface.v0",
        "appId": plan.app_id,
        "appName": plan.app_name,
        "target": target.as_str(),
        "webview": {
            "engine": match target {
                Target::Macos | Target::Ios => "wkwebview",
                Target::Android => "android-webview",
                Target::Windows => "webview2-scaffold",
            },
            "entry": plan.ui_entry,
            "dist": plan.ui_dist.as_ref().map(|p| p.display().to_string()),
            "index": plan.ui_index,
            "bridge": "window.kotobaShell.invoke",
            "readyEvent": "KOTOBA_SHELL_READY"
        },
        "windows": [{
            "id": "main",
            "title": plan.app_name,
            "kind": "primary",
            "resizable": true,
            "fullscreen": false,
            "decorations": true,
            "closePolicy": "quit-last-window"
        }],
        "menu": {
            "status": menu_status,
            "items": [
                {"id": "app.about", "label": "About"},
                {"id": "app.quit", "label": "Quit"},
                {"id": "edit.copy", "label": "Copy", "requiresCapability": has_clipboard},
                {"id": "edit.paste", "label": "Paste", "requiresCapability": has_clipboard}
            ]
        },
        "tray": {
            "status": tray_status,
            "items": [
                {"id": "tray.show", "label": "Show"},
                {"id": "tray.quit", "label": "Quit"}
            ]
        },
        "lifecycle": {
            "events": ["launch", "ready", "foreground", "background", "terminate"],
            "status": if target == Target::Macos { "native-runner" } else { "contract-only" },
            "audit": "append-only-command-log"
        },
        "nativeImplementation": {
            "menu": target == Target::Macos,
            "tray": target == Target::Macos,
            "webview2Host": target == Target::Windows,
            "lifecycleMarkers": matches!(target, Target::Macos | Target::Windows)
        },
        "capabilityBindings": {
            "notifications": has_notifications,
            "clipboard": has_clipboard,
            "providers": provider_catalog_json(&capabilities)
        }
    });
    serde_json::to_string_pretty(&manifest).map_err(Into::into)
}

pub fn app_surface_check_manifest(
    target: Target,
    manifest: impl AsRef<Path>,
) -> Result<AppSurfaceCheckReport> {
    app_surface_check_manifest_with_oracle(target, manifest, None)
}

pub fn app_surface_check_manifest_with_oracle(
    target: Target,
    manifest: impl AsRef<Path>,
    provider_oracle_manifest: Option<&Path>,
) -> Result<AppSurfaceCheckReport> {
    let manifest = manifest.as_ref();
    let json = read_evidence_json(manifest)?;
    let mut checks = Vec::new();
    let mut missing = Vec::new();
    validate_provider_surface_policy_oracle(provider_oracle_manifest, &mut checks, &mut missing)?;
    match require_json_string(&json, "schema", "kotoba-shell.app-surface.v0", &mut checks) {
        Ok(()) => {}
        Err(err) => missing.push(err.to_string()),
    }
    match require_json_string(&json, "target", target.as_str(), &mut checks) {
        Ok(()) => {}
        Err(err) => missing.push(err.to_string()),
    }
    require_json_array_non_empty(&json, "windows", &mut checks, &mut missing);
    require_json_array_non_empty(&json, "/lifecycle/events", &mut checks, &mut missing);
    require_json_object(&json, "webview", &mut checks, &mut missing);
    require_json_object(&json, "menu", &mut checks, &mut missing);
    require_json_object(&json, "tray", &mut checks, &mut missing);
    require_json_object(&json, "nativeImplementation", &mut checks, &mut missing);
    require_nested_json_string(&json, "/webview/bridge", &mut checks, &mut missing);
    require_nested_json_string(&json, "/webview/readyEvent", &mut checks, &mut missing);
    let status = if missing.is_empty() {
        SdkCheckStatus::Passed
    } else {
        SdkCheckStatus::Failed
    };
    let detail = if missing.is_empty() {
        "app surface contract covers webview, window, menu, tray, lifecycle, and bridge".to_string()
    } else {
        format!(
            "app surface contract has {} unsatisfied requirement(s)",
            missing.len()
        )
    };
    Ok(AppSurfaceCheckReport {
        schema: "kotoba-shell.app-surface-check.v0".to_string(),
        target,
        manifest: manifest.to_path_buf(),
        status,
        checks,
        missing,
        detail,
    })
}

pub fn app_surface_parity_check_manifests(
    manifests: &[PathBuf],
    required_targets: &[Target],
) -> Result<AppSurfaceParityCheckReport> {
    app_surface_parity_check_manifests_with_oracle(manifests, required_targets, None)
}

pub fn app_surface_parity_check_manifests_with_oracle(
    manifests: &[PathBuf],
    required_targets: &[Target],
    provider_oracle_manifest: Option<&Path>,
) -> Result<AppSurfaceParityCheckReport> {
    let mut checks = Vec::new();
    let mut missing = Vec::new();
    let mut seen_targets = BTreeSet::new();
    let mut targets = Vec::new();
    let mut reference_bridge: Option<String> = None;
    let mut reference_commands: Option<BTreeSet<String>> = None;

    if manifests.len() < 2 {
        missing.push("at least two app surface manifests are required".to_string());
    }
    validate_provider_surface_policy_oracle(provider_oracle_manifest, &mut checks, &mut missing)?;

    for manifest in manifests {
        let json = read_evidence_json(manifest)?;
        match require_json_string(&json, "schema", "kotoba-shell.app-surface.v0", &mut checks) {
            Ok(()) => {}
            Err(err) => missing.push(format!("{}: {err}", manifest.display())),
        }
        let target = match json.get("target").and_then(|value| value.as_str()) {
            Some(value) => match Target::parse(value) {
                Ok(target) => target,
                Err(err) => {
                    missing.push(format!("{}: target is invalid: {err}", manifest.display()));
                    continue;
                }
            },
            None => {
                missing.push(format!("{}: target is missing", manifest.display()));
                continue;
            }
        };
        if !seen_targets.insert(target) {
            missing.push(format!("duplicate app surface target: {}", target.as_str()));
        }
        targets.push(target);
        checks.push(format!(
            "surface:{}:{}",
            target.as_str(),
            manifest.display()
        ));

        let bridge = json
            .pointer("/webview/bridge")
            .and_then(|value| value.as_str())
            .unwrap_or_default()
            .to_string();
        if bridge.is_empty() {
            missing.push(format!("{}: webview.bridge is missing", target.as_str()));
        } else if let Some(reference) = &reference_bridge {
            if &bridge == reference {
                checks.push(format!("bridge:{}:{bridge}", target.as_str()));
            } else {
                missing.push(format!(
                    "{} bridge differs: expected {reference}, got {bridge}",
                    target.as_str()
                ));
            }
        } else {
            checks.push(format!("bridge:{}:{bridge}", target.as_str()));
            reference_bridge = Some(bridge);
        }

        let commands = app_surface_provider_commands(&json);
        if commands.is_empty() {
            missing.push(format!("{} provider command set is empty", target.as_str()));
        } else if let Some(reference) = &reference_commands {
            if &commands == reference {
                checks.push(format!("commands:{}:{}", target.as_str(), commands.len()));
            } else {
                let missing_commands = reference.difference(&commands).cloned().collect::<Vec<_>>();
                let extra_commands = commands.difference(reference).cloned().collect::<Vec<_>>();
                missing.push(format!(
                    "{} command set differs: missing {:?}, extra {:?}",
                    target.as_str(),
                    missing_commands,
                    extra_commands
                ));
            }
        } else {
            checks.push(format!("commands:{}:{}", target.as_str(), commands.len()));
            reference_commands = Some(commands);
        }
    }
    for required in required_targets {
        if seen_targets.contains(required) {
            checks.push(format!("required-target:{}", required.as_str()));
        } else {
            missing.push(format!(
                "required app surface target is missing: {}",
                required.as_str()
            ));
        }
    }

    let commands = reference_commands
        .unwrap_or_default()
        .into_iter()
        .collect::<Vec<_>>();
    let bridge = reference_bridge.unwrap_or_default();
    let status = if missing.is_empty() {
        SdkCheckStatus::Passed
    } else {
        SdkCheckStatus::Failed
    };
    let detail = if missing.is_empty() {
        format!(
            "app surface bridge and provider command set match across {} target(s)",
            targets.len()
        )
    } else {
        format!(
            "app surface parity has {} unsatisfied requirement(s)",
            missing.len()
        )
    };
    Ok(AppSurfaceParityCheckReport {
        schema: "kotoba-shell.app-surface-parity-check.v0".to_string(),
        status,
        manifests: manifests.to_vec(),
        required_targets: required_targets.to_vec(),
        targets,
        bridge,
        commands,
        checks,
        missing,
        detail,
    })
}

fn app_surface_provider_commands(json: &serde_json::Value) -> BTreeSet<String> {
    json.pointer("/capabilityBindings/providers")
        .and_then(|value| value.as_array())
        .into_iter()
        .flatten()
        .flat_map(|provider| {
            provider
                .get("commands")
                .and_then(|value| value.as_array())
                .into_iter()
                .flatten()
                .filter_map(|value| value.as_str())
                .filter(|command| app_surface_portable_command(command))
                .map(str::to_string)
        })
        .collect()
}

fn app_surface_portable_command(command: &str) -> bool {
    !matches!(command, "fs/read-text" | "fs/write-text" | "fs/append-text")
}

fn adapter_smoke_payload_value(id: &str) -> serde_json::Value {
    match id {
        "auth" => serde_json::json!({
            "schema": "kotoba-shell.adapter-smoke.v0",
            "operation": "auth.has-capability",
            "resource": "graph/x",
            "ability": "read"
        }),
        "kqe" => serde_json::json!({
            "schema": "kotoba-shell.adapter-smoke.v0",
            "operation": "kqe.query",
            "filter": ""
        }),
        "llm" => serde_json::json!({
            "schema": "kotoba-shell.adapter-smoke.v0",
            "operation": "llm.infer",
            "model": "modelA",
            "prompt": "ping"
        }),
        _ => serde_json::json!({
            "schema": "kotoba-shell.adapter-smoke.v0",
            "operation": "unknown"
        }),
    }
}

fn adapter_smoke_response_contract_value(id: &str) -> serde_json::Value {
    match id {
        "auth" => serde_json::json!({
            "allowed": "boolean"
        }),
        "kqe" => serde_json::json!({
            "quads": "array"
        }),
        "llm" => serde_json::json!({
            "output": "string"
        }),
        _ => serde_json::json!({}),
    }
}

fn component_host_surfaces(plan: &ShellPlan) -> BTreeSet<String> {
    plan.components
        .iter()
        .flat_map(|component| component.capability_surface.iter().cloned())
        .collect()
}

fn aiueos_shell_surface_json(plan: &ShellPlan, target: Target) -> Result<String> {
    let capabilities = target_capabilities(plan, target);
    let surface = serde_json::json!({
        "schema": "aiueos.shell.surface.v0",
        "surface": "shell",
        "appId": plan.app_id,
        "appName": plan.app_name,
        "target": target.as_str(),
        "broker": {
            "verify": "safe-kotoba-admission-before-provider-link",
            "dispatch": "capability-command",
            "audit": "append-only-command-log"
        },
        "componentSupervisor": {
            "verify": "safe-kotoba-admission-policy-and-provider-link",
            "pureDryRun": "wasmtime-fuel"
        },
        "audit": {
            "schema": "aiueos.shell.audit.v0",
            "events": ["request", "reply"],
            "fields": ["ts", "app", "command", "requestId", "ok", "phase", "value", "error"],
            "macosDevPath": format!("Application Support/kotoba-shell-dev/{}/audit/commands.jsonl", plan.app_id)
        },
        "providers": provider_catalog_json(&capabilities),
        "components": plan.components.iter().map(|c| {
            serde_json::json!({
                "id": c.id,
                "safe": c.safe,
                "status": format!("{:?}", c.status),
                "policyEdn": c.policy_edn,
                "exports": c.exports,
                "imports": c.imports,
                "capabilitySurface": c.capability_surface,
                "inferredEffects": c.inferred_effects,
            })
        }).collect::<Vec<_>>(),
    });
    serde_json::to_string_pretty(&surface).map_err(Into::into)
}

fn aiueos_shell_surface_edn(plan: &ShellPlan, target: Target) -> String {
    let capabilities = target_capabilities(plan, target);
    let providers = provider_catalog_json(&capabilities)
        .into_iter()
        .filter_map(|p| {
            let id = p.get("id")?.as_str()?;
            let capability = p.get("capability")?.as_str()?;
            let commands = p
                .get("commands")?
                .as_array()?
                .iter()
                .filter_map(|c| c.as_str())
                .map(|c| format!(":{}", c.replace('/', "/")))
                .collect::<Vec<_>>()
                .join(" ");
            Some(format!(
                "{{:id :{} :capability :{} :commands #{{{}}}}}",
                id, capability, commands
            ))
        })
        .collect::<Vec<_>>()
        .join("\n  ");
    format!(
        "{{:schema :aiueos.shell/surface.v0\n :aiueos/surface :shell\n :app/id {:?}\n :app/name {:?}\n :target :{}\n :broker {{:verify :safe-kotoba-admission-before-provider-link\n          :dispatch :capability-command\n          :audit :append-only-command-log}}\n :component-supervisor {{:verify :safe-kotoba-admission-policy-and-provider-link\n                        :pure-dry-run :wasmtime-fuel}}\n :audit {{:schema :aiueos.shell/audit.v0\n         :events [:request :reply]\n         :macos-dev-path {:?}}}\n :providers [{}]}}\n",
        plan.app_id,
        plan.app_name,
        target.as_str(),
        format!(
            "Application Support/kotoba-shell-dev/{}/audit/commands.jsonl",
            plan.app_id
        ),
        providers
    )
}

fn aiueos_provider_catalog_json_string() -> Result<String> {
    let edn = kotoba_edn::parse(kotoba_clj::selfhost::AIUEOS_PROVIDER_CATALOG_SPEC)
        .context("parse Kotoba selfhost aiueos provider catalog spec")?;
    serde_json::to_string_pretty(&edn_to_json(&edn)).map_err(Into::into)
}

fn provider_catalog_json(capabilities: &[String]) -> Vec<serde_json::Value> {
    provider_catalog_json_from_selfhost(capabilities)
        .expect("aiueos provider catalog selfhost EDN seed is valid")
}

fn provider_catalog_json_from_selfhost(capabilities: &[String]) -> Result<Vec<serde_json::Value>> {
    let edn = kotoba_edn::parse(kotoba_clj::selfhost::AIUEOS_PROVIDER_CATALOG_SPEC)
        .context("parse Kotoba selfhost aiueos provider catalog spec")?;
    let json = edn_to_json(&edn);
    require_json_string(
        &json,
        "schema",
        "aiueos.provider-catalog.v0",
        &mut Vec::new(),
    )?;
    let providers = json
        .get("providers")
        .and_then(|value| value.as_array())
        .ok_or_else(|| anyhow!("aiueos provider catalog is missing providers"))?;
    providers
        .iter()
        .filter(|provider| provider_matches_any_capability(provider, capabilities))
        .map(provider_catalog_entry_json)
        .collect()
}

fn provider_catalog_entry_json(provider: &serde_json::Value) -> Result<serde_json::Value> {
    let id = provider
        .get("id")
        .and_then(|value| value.as_str())
        .ok_or_else(|| anyhow!("aiueos provider catalog entry is missing id"))?;
    let capability = provider
        .get("capability")
        .and_then(|value| value.as_str())
        .ok_or_else(|| anyhow!("aiueos provider catalog entry `{id}` is missing capability"))?;
    let status = provider
        .get("status")
        .and_then(|value| value.as_str())
        .ok_or_else(|| anyhow!("aiueos provider catalog entry `{id}` is missing status"))?;
    let commands = provider
        .get("commands")
        .and_then(|value| value.as_array())
        .ok_or_else(|| anyhow!("aiueos provider catalog entry `{id}` is missing commands"))?
        .iter()
        .map(|value| {
            value.as_str().map(str::to_string).ok_or_else(|| {
                anyhow!("aiueos provider catalog entry `{id}` has non-string command")
            })
        })
        .collect::<Result<Vec<_>>>()?;
    Ok(serde_json::json!({
        "id": id,
        "capability": capability,
        "commands": commands,
        "status": status
    }))
}

fn provider_matches_any_capability(provider: &serde_json::Value, capabilities: &[String]) -> bool {
    provider
        .get("matches")
        .and_then(|value| value.as_array())
        .into_iter()
        .flatten()
        .filter_map(|value| value.as_str())
        .any(|pattern| {
            capabilities
                .iter()
                .any(|capability| provider_match_pattern_matches(pattern, capability))
        })
}

fn provider_match_pattern_matches(pattern: &str, capability: &str) -> bool {
    if let Some(prefix) = pattern.strip_suffix("/*") {
        capability.starts_with(&format!("{prefix}/"))
    } else {
        capability == pattern
    }
}

fn apple_entitlements_plist(plan: &ShellPlan, target: Target) -> String {
    let caps = target_capabilities(plan, target);
    let network = caps.iter().any(|c| is_network_capability(c));
    let user_files = caps
        .iter()
        .any(|c| c.starts_with("fs/user") || c.starts_with("fs/external"));
    let push = caps.iter().any(|c| c == "notify/push");
    let mut entries = String::new();
    entries.push_str("  <key>com.apple.security.app-sandbox</key>\n  <true/>\n");
    if network {
        entries.push_str("  <key>com.apple.security.network.client</key>\n  <true/>\n");
    }
    if user_files {
        entries.push_str(
            "  <key>com.apple.security.files.user-selected.read-write</key>\n  <true/>\n",
        );
    }
    if target == Target::Ios && push {
        entries.push_str("  <key>aps-environment</key>\n  <string>development</string>\n");
    }
    format!(
        r#"<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "https://www.apple.com/DTDs/PropertyList-1.0.dtd">
<plist version="1.0">
<dict>
{entries}</dict>
</plist>
"#
    )
}

fn android_permissions_xml(plan: &ShellPlan) -> String {
    let caps = target_capabilities(plan, Target::Android);
    let body = android_permission_lines(&caps);
    format!(
        r#"<manifest xmlns:android="http://schemas.android.com/apk/res/android">
{body}
</manifest>
"#
    )
}

fn android_permission_lines(caps: &[String]) -> String {
    let mut permissions = Vec::new();
    if caps
        .iter()
        .any(|c| c == "notify/show" || c == "notify/push")
    {
        permissions.push("android.permission.POST_NOTIFICATIONS");
    }
    if caps.iter().any(|c| is_network_capability(c)) {
        permissions.push("android.permission.INTERNET");
    }
    if caps.iter().any(|c| is_contacts_capability(c)) {
        permissions.push("android.permission.READ_CONTACTS");
    }
    if caps.iter().any(|c| is_calendar_capability(c)) {
        permissions.push("android.permission.READ_CALENDAR");
    }
    permissions
        .into_iter()
        .map(|p| format!(r#"  <uses-permission android:name="{p}" />"#))
        .collect::<Vec<_>>()
        .join("\n")
}

fn is_network_capability(capability: &str) -> bool {
    matches!(
        capability,
        "http/fetch" | "net/fetch" | "net/connect" | "ledger/append"
    ) || capability.starts_with("http/")
        || capability.starts_with("net/")
}

fn is_http_fetch_capability(capability: &str) -> bool {
    matches!(capability, "http/fetch" | "net/fetch") || capability.starts_with("http/")
}

fn is_clipboard_capability(capability: &str) -> bool {
    matches!(
        capability,
        "clipboard/read" | "clipboard/write" | "clipboard/read-text" | "clipboard/write-text"
    ) || capability.starts_with("clipboard/")
}

fn is_keychain_capability(capability: &str) -> bool {
    matches!(
        capability,
        "keychain/read" | "keychain/write" | "keychain/read-text" | "keychain/write-text"
    ) || capability.starts_with("keychain/")
}

fn is_contacts_capability(capability: &str) -> bool {
    matches!(capability, "contacts/read" | "contacts/list") || capability.starts_with("contacts/")
}

fn is_calendar_capability(capability: &str) -> bool {
    matches!(capability, "calendar/read" | "calendar/list-events")
        || capability.starts_with("calendar/")
}

fn macos_notarize_script(plan: &ShellPlan) -> String {
    let zip_name = format!("{}.zip", safe_path_segment(&plan.app_name));
    let app_name = format!("{}.app", safe_path_segment(&plan.app_name));
    format!(
        r#"#!/bin/sh
set -eu

APP_BUNDLE="${{1:-target/kotoba-shell/build/{app_name}}}"
ZIP_PATH="${{2:-target/kotoba-shell/release/{zip_name}}}"

ditto -c -k --keepParent "$APP_BUNDLE" "$ZIP_PATH"

echo "Created $ZIP_PATH"
echo "Submit with:"
echo "  xcrun notarytool submit \"$ZIP_PATH\" --keychain-profile <profile> --wait"
echo "Then staple with:"
echo "  xcrun stapler staple \"$APP_BUNDLE\""
"#,
        app_name = app_name,
        zip_name = zip_name
    )
}

fn signing_plan_json(plan: &ShellPlan, target: Target) -> Result<String> {
    let manifest = serde_json::json!({
        "schema": "kotoba-shell.signing-plan.v0",
        "appId": plan.app_id,
        "appName": plan.app_name,
        "target": target.as_str(),
        "version": "0.1.0",
        "artifacts": match target {
            Target::Macos => serde_json::json!({
                "bundle": format!("target/kotoba-shell/build/{}.app", safe_path_segment(&plan.app_name)),
                "entitlements": "kotoba-shell.entitlements",
                "signedArchive": format!("{}.zip", safe_path_segment(&plan.app_name)),
            }),
            Target::Ios => serde_json::json!({
                "xcodeProject": format!("target/kotoba-shell/build/ios/{}", safe_path_segment(&plan.app_name)),
                "exportOptions": "xcode-export-options.plist",
                "archive": format!("{}.xcarchive", safe_path_segment(&plan.app_name)),
                "ipa": format!("{}.ipa", safe_path_segment(&plan.app_name)),
            }),
            Target::Android => serde_json::json!({
                "gradleProject": format!("target/kotoba-shell/build/android/{}", safe_path_segment(&plan.app_name)),
                "aab": "app/build/outputs/bundle/release/app-release.aab",
                "signedAab": format!("{}-release-signed.aab", safe_path_segment(&plan.app_name)),
            }),
            Target::Windows => serde_json::json!({
                "project": format!("target/kotoba-shell/build/windows/{}", safe_path_segment(&plan.app_name)),
                "executable": format!("target/kotoba-shell/build/windows/{}/dist/{}.exe", safe_path_segment(&plan.app_name), safe_path_segment(&plan.app_name)),
                "archive": format!("{}.zip", safe_path_segment(&plan.app_name)),
                "signedExecutable": format!("{}-signed.exe", safe_path_segment(&plan.app_name)),
            }),
        },
        "environment": match target {
            Target::Macos => serde_json::json!({
                "KOTOBA_APPLE_CODESIGN_IDENTITY": "Developer ID Application: ...",
                "KOTOBA_NOTARY_PROFILE": "notarytool keychain profile"
            }),
            Target::Ios => serde_json::json!({
                "KOTOBA_APPLE_TEAM_ID": "Apple Developer Team ID",
                "KOTOBA_IOS_SIGNING_STYLE": "automatic or manual"
            }),
            Target::Android => serde_json::json!({
                "KOTOBA_ANDROID_KEYSTORE": "path to upload keystore",
                "KOTOBA_ANDROID_KEY_ALIAS": "upload key alias",
                "KOTOBA_ANDROID_KEYSTORE_PASS": "keystore password",
                "KOTOBA_ANDROID_KEY_PASS": "key password"
            }),
            Target::Windows => serde_json::json!({
                "KOTOBA_WINDOWS_CERT_PATH": "path to Authenticode PFX/P12 certificate",
                "KOTOBA_WINDOWS_CERT_PASS": "certificate password",
                "KOTOBA_WINDOWS_TIMESTAMP_URL": "timestamp URL",
                "KOTOBA_WINDOWS_DOWNLOAD_URL": "stable HTTPS download URL for SmartScreen reputation"
            }),
        },
        "gates": [
            "kotoba shell verify",
            "store disclosure metadata review",
            "aiueos shell surface review",
            "updater manifest signature review"
        ]
    });
    serde_json::to_string_pretty(&manifest).map_err(Into::into)
}

fn evidence_profile_json(plan: &ShellPlan, target: Target) -> Result<String> {
    let release_profile = match target {
        Target::Android => "android-release",
        Target::Ios | Target::Macos | Target::Windows => "store-release",
    };
    let selfhost_projection = selfhost_shell_evidence_profile_spec()?;
    let manifest = serde_json::json!({
        "schema": "kotoba-shell.evidence-profile.v0",
        "appId": plan.app_id,
        "appName": plan.app_name,
        "target": target.as_str(),
        "canonicalFormat": "edn",
        "jsonRole": "interop",
        "selfhostProjection": selfhost_projection,
        "profiles": {
            "ci": evidence_profile_requirements("ci").unwrap_or_default(),
            release_profile: release_evidence_profile_requirements(target)
        },
        "commands": {
            "ci": "kotoba shell evidence-check <evidence-dir> --profile ci --evidence <summary.json>",
            "coverage": "kotoba shell coverage --json --evidence <coverage-evidence.json>",
            "coverageCheck": "kotoba shell coverage-check --min-functional 70 --min-release-maturity 45 --evidence <coverage-check-evidence.json>",
            "providerContract": format!("kotoba shell provider-contract-check {} --target {} --provider-oracle-manifest <release-dir>/kototama-provider-surface-policy.edn --evidence <provider-contract-evidence.json>", plan.manifest_path.display(), target.as_str()),
            "pluginContract": format!("kotoba shell plugin-check --target {} --evidence <plugin-contract-evidence.json> <release-dir>/kotoba-shell-plugins.json", target.as_str()),
            "pluginSdk": format!("kotoba shell plugin-sdk-check --target {} --evidence <plugin-sdk-ready-evidence.json> <release-dir>/kotoba-shell-plugin-sdk.json", target.as_str()),
            "pluginLoad": format!("kotoba shell plugin-load-check --target {} --evidence <plugin-load-ready-evidence.json> <release-dir>/kotoba-shell-plugin-bundles.json", target.as_str()),
            "compatibility": format!("kotoba shell compatibility-check --target {} --evidence <compatibility-ready-evidence.json> <release-dir>/kotoba-shell-compatibility.json", target.as_str()),
            "compatibilityMigration": format!("kotoba shell compatibility-migration-check --target {} --previous <previous-release-dir>/kotoba-shell-compatibility.json --current <release-dir>/kotoba-shell-compatibility.json --evidence <compatibility-migration-ready-evidence.json>", target.as_str()),
            "appSurface": format!("kotoba shell surface-check --target {} --provider-oracle-manifest <release-dir>/kototama-provider-surface-policy.edn --evidence <app-surface-ready-evidence.json> <release-dir>/kotoba-shell-app-surface.json", target.as_str()),
            "appSurfaceParity": "kotoba shell surface-parity-check --require-target macos --require-target ios --require-target android --require-target windows --provider-oracle-manifest <release-dir>/kototama-provider-surface-policy.edn --evidence <app-surface-parity-ready-evidence.json> <macos-release-dir>/kotoba-shell-app-surface.json <ios-release-dir>/kotoba-shell-app-surface.json <android-release-dir>/kotoba-shell-app-surface.json <windows-release-dir>/kotoba-shell-app-surface.json",
            "doctor": format!("kotoba shell doctor-check --target {} --probe --evidence <{}-runtime-doctor-evidence.json>", target.as_str(), target.as_str()),
            "runtimeMatrix": "kotoba shell runtime-matrix-check --require-target ios --require-target android --min-distinct-runtimes 3 --evidence <runtime-matrix-ready-evidence.json> <runtime-ready-evidence.json>...",
            "deviceFarm": "kotoba shell device-farm-check --require-target ios --require-target android --min-distinct-runtimes 2 --provider <device-farm-provider> --run-url <https-device-farm-run-url> --runtime-matrix-evidence <runtime-matrix-ready-evidence.json> --evidence <device-farm-ready-evidence.json>",
            "windowsRuntimeContract": "kotoba shell windows-runtime-contract-check <windows-project-dir> --evidence <windows-runtime-contract-ready-evidence.json>",
            "kototamaWasmCheck": "kotoba shell kototama-wasm-check <release-dir>/kototama-selfhost-analyzer.edn --evidence <kototama-wasm-ready-evidence.edn>",
            "kototamaAppComponentsCheck": "kotoba shell kototama-app-components-check <release-dir>/kototama-app-components.edn --evidence <kototama-app-components-ready-evidence.edn>",
            "selfhostProfileCheck": "kotoba shell selfhost-profile-check <release-dir>/kotoba-shell-evidence-profile.edn --profile-oracle-manifest <release-dir>/kototama-shell-evidence-profile.edn --evidence <selfhost-profile-ready-evidence.edn>",
            "liveAdapterSupervisor": format!("kotoba shell supervisor-check {} --target {} --run --adapter-manifest <release-dir>/kotoba-shell-host-adapters.json --kototama-app-components <release-dir>/kototama-app-components.edn --component <host-bound-component> --evidence <live-adapter-supervisor-evidence.json>", plan.manifest_path.display(), target.as_str()),
            "adapterSupervisor": format!("kotoba shell adapter-supervisor-check --target {} --adapter-evidence <hosted-adapter-evidence.json> --supervisor-evidence <live-adapter-supervisor-evidence.json> --evidence <adapter-supervisor-ready-evidence.json>", target.as_str()),
            "updaterChannel": format!("kotoba shell updater-channel-check --target {} --evidence <updater-channel-ready-evidence.json> <release-dir>/kotoba-shell-updater-channel.json", target.as_str()),
            "updaterUi": format!("kotoba shell updater-ui-check --target {} --evidence <updater-ui-ready-evidence.json> <release-dir>/kotoba-shell-updater-ui.json", target.as_str()),
            "updaterBundle": format!("kotoba shell updater-bundle-check --target {} --updater-evidence <updater-ready-evidence.json> --evidence <updater-bundle-ready-evidence.json>", target.as_str()),
            "updaterInstall": format!("kotoba shell updater-install-check --target {} --updater-evidence <updater-ready-evidence.json> --staging-dir <updater-install-stage> --evidence <updater-install-ready-evidence.json>", target.as_str()),
            "updaterFeed": format!("kotoba shell updater-feed-check --target {} --updater-evidence <updater-ready-evidence.json> --feed-file <release-dir>/kotoba-shell-updater-manifest.json --feed-url <https-updater-feed-url> --evidence <updater-feed-ready-evidence.json>", target.as_str()),
            "ledgerReplay": format!("kotoba shell ledger-replay-check --target {} --source <ledger/events.jsonl> --replica <ledger-replica/events.jsonl> --evidence <ledger-replay-ready-evidence.json>", target.as_str()),
            "ledgerRemote": format!("kotoba shell ledger-remote-check --target {} --source <ledger/events.jsonl> --endpoint <https-ledger-replica-endpoint> --hosted --probe --evidence <ledger-remote-ready-evidence.json>", target.as_str()),
            "release": format!("kotoba shell evidence-check <evidence-dir> --profile {release_profile} --evidence <summary.json>")
        },
        "statusSemantics": {
            "Passed": "all required evidence for the selected profile passed",
            "Skipped": "no failures and no required evidence missing, but at least one non-required evidence was skipped",
            "Failed": "a required evidence file is missing, failed, or skipped"
        }
    });
    serde_json::to_string_pretty(&manifest).map_err(Into::into)
}

fn selfhost_shell_evidence_profile_spec() -> Result<serde_json::Value> {
    let edn = kotoba_edn::parse(kotoba_clj::selfhost::SHELL_EVIDENCE_PROFILE_SPEC)
        .context("parse Kotoba selfhost shell evidence profile spec")?;
    let json = edn_to_json(&edn);
    require_json_string(
        &json,
        "schema",
        kotoba_clj::selfhost::SHELL_EVIDENCE_PROFILE_ABI,
        &mut Vec::new(),
    )?;
    Ok(json)
}

fn macos_sign_script(plan: &ShellPlan) -> String {
    let app_name = format!("{}.app", safe_path_segment(&plan.app_name));
    format!(
        r#"#!/bin/sh
set -eu

APP_BUNDLE="${{1:-target/kotoba-shell/build/{app_name}}}"
IDENTITY="${{KOTOBA_APPLE_CODESIGN_IDENTITY:?set KOTOBA_APPLE_CODESIGN_IDENTITY}}"
ENTITLEMENTS="${{2:-kotoba-shell.entitlements}}"

codesign --force --deep --options runtime --entitlements "$ENTITLEMENTS" --sign "$IDENTITY" "$APP_BUNDLE"
codesign --verify --deep --strict --verbose=2 "$APP_BUNDLE"
"#,
        app_name = app_name
    )
}

fn ios_sign_script(plan: &ShellPlan) -> String {
    let project = format!(
        "target/kotoba-shell/build/ios/{}",
        safe_path_segment(&plan.app_name)
    );
    let archive = format!("{}.xcarchive", safe_path_segment(&plan.app_name));
    format!(
        r#"#!/bin/sh
set -eu

PROJECT_DIR="${{1:-{project}}}"
ARCHIVE_PATH="${{2:-target/kotoba-shell/release/{archive}}}"
EXPORT_DIR="${{3:-target/kotoba-shell/release/ios-export}}"
EXPORT_OPTIONS="${{4:-xcode-export-options.plist}}"

xcodebuild archive -project "$PROJECT_DIR" -scheme "{scheme}" -archivePath "$ARCHIVE_PATH"
xcodebuild -exportArchive -archivePath "$ARCHIVE_PATH" -exportOptionsPlist "$EXPORT_OPTIONS" -exportPath "$EXPORT_DIR"
"#,
        project = project,
        archive = archive,
        scheme = safe_path_segment(&plan.app_name)
    )
}

fn android_sign_script(plan: &ShellPlan) -> String {
    let project = format!(
        "target/kotoba-shell/build/android/{}",
        safe_path_segment(&plan.app_name)
    );
    format!(
        r#"#!/bin/sh
set -eu

PROJECT_DIR="${{1:-{project}}}"
KEYSTORE="${{KOTOBA_ANDROID_KEYSTORE:?set KOTOBA_ANDROID_KEYSTORE}}"
KEY_ALIAS="${{KOTOBA_ANDROID_KEY_ALIAS:?set KOTOBA_ANDROID_KEY_ALIAS}}"
STORE_PASS="${{KOTOBA_ANDROID_KEYSTORE_PASS:?set KOTOBA_ANDROID_KEYSTORE_PASS}}"
KEY_PASS="${{KOTOBA_ANDROID_KEY_PASS:?set KOTOBA_ANDROID_KEY_PASS}}"
GRADLE="${{KOTOBA_GRADLE:-./gradlew}}"

if [ ! -x "$PROJECT_DIR/gradlew" ] && [ "$GRADLE" = "./gradlew" ]; then
  GRADLE="gradle"
fi

(cd "$PROJECT_DIR" && "$GRADLE" bundleRelease)

AAB="$PROJECT_DIR/app/build/outputs/bundle/release/app-release.aab"
SIGNED_AAB="${{2:-$PROJECT_DIR/app-release-signed.aab}}"

jarsigner -keystore "$KEYSTORE" -storepass "$STORE_PASS" -keypass "$KEY_PASS" "$AAB" "$KEY_ALIAS"
cp "$AAB" "$SIGNED_AAB"
"#,
        project = project
    )
}

fn ios_submit_script(plan: &ShellPlan) -> String {
    let ipa = format!(
        "target/kotoba-shell/release/ios-export/{}.ipa",
        safe_path_segment(&plan.app_name)
    );
    format!(
        r#"#!/bin/sh
set -eu

IPA_PATH="${{1:-{ipa}}}"
KEY_ID="${{KOTOBA_APP_STORE_CONNECT_KEY_ID:?set KOTOBA_APP_STORE_CONNECT_KEY_ID}}"
ISSUER_ID="${{KOTOBA_APP_STORE_CONNECT_ISSUER_ID:?set KOTOBA_APP_STORE_CONNECT_ISSUER_ID}}"
API_KEY_PATH="${{KOTOBA_APP_STORE_CONNECT_API_KEY:?set KOTOBA_APP_STORE_CONNECT_API_KEY}}"

if [ ! -f "$IPA_PATH" ]; then
  echo "IPA does not exist: $IPA_PATH" >&2
  exit 2
fi

xcrun altool --upload-app \
  --type ios \
  --file "$IPA_PATH" \
  --apiKey "$KEY_ID" \
  --apiIssuer "$ISSUER_ID" \
  --apiKeyPath "$API_KEY_PATH"
"#,
        ipa = ipa
    )
}

fn android_submit_script(plan: &ShellPlan) -> String {
    let aab = format!(
        "target/kotoba-shell/build/android/{}/app-release-signed.aab",
        safe_path_segment(&plan.app_name)
    );
    format!(
        r#"#!/bin/sh
set -eu

AAB_PATH="${{1:-{aab}}}"
SERVICE_ACCOUNT_JSON="${{KOTOBA_PLAY_SERVICE_ACCOUNT_JSON:?set KOTOBA_PLAY_SERVICE_ACCOUNT_JSON}}"
PACKAGE_NAME="${{KOTOBA_ANDROID_PACKAGE_NAME:-{package}}}"
TRACK="${{KOTOBA_PLAY_TRACK:-internal}}"
COMMIT="${{KOTOBA_PLAY_COMMIT:-false}}"

if [ ! -f "$AAB_PATH" ]; then
  echo "AAB does not exist: $AAB_PATH" >&2
  exit 2
fi
if ! command -v gcloud >/dev/null 2>&1; then
  echo "gcloud is required to mint an Android Publisher API access token" >&2
  exit 2
fi

gcloud auth activate-service-account --key-file "$SERVICE_ACCOUNT_JSON" >/dev/null
TOKEN="$(gcloud auth print-access-token)"
API_ROOT="https://androidpublisher.googleapis.com/androidpublisher/v3/applications/$PACKAGE_NAME"
UPLOAD_ROOT="https://androidpublisher.googleapis.com/upload/androidpublisher/v3/applications/$PACKAGE_NAME"

EDIT_JSON="$(curl --fail --silent --show-error -X POST \
  -H "authorization: Bearer $TOKEN" \
  -H "content-type: application/json" \
  "$API_ROOT/edits")"
EDIT_ID="$(printf "%s" "$EDIT_JSON" | python3 -c 'import json,sys; print(json.load(sys.stdin)["id"])')"

BUNDLE_JSON="$(curl --fail --silent --show-error -X POST \
  -H "authorization: Bearer $TOKEN" \
  -H "content-type: application/octet-stream" \
  --data-binary "@$AAB_PATH" \
  "$UPLOAD_ROOT/edits/$EDIT_ID/bundles?uploadType=media")"
VERSION_CODE="$(printf "%s" "$BUNDLE_JSON" | python3 -c 'import json,sys; print(json.load(sys.stdin)["versionCode"])')"

curl --fail --silent --show-error -X PUT \
  -H "authorization: Bearer $TOKEN" \
  -H "content-type: application/json" \
  --data "{{\"releases\":[{{\"versionCodes\":[\"$VERSION_CODE\"],\"status\":\"draft\"}}]}}" \
  "$API_ROOT/edits/$EDIT_ID/tracks/$TRACK" >/dev/null

if [ "$COMMIT" = "true" ]; then
  curl --fail --silent --show-error -X POST \
    -H "authorization: Bearer $TOKEN" \
    "$API_ROOT/edits/$EDIT_ID:commit" >/dev/null
  echo "Uploaded and committed $AAB_PATH to $PACKAGE_NAME track $TRACK versionCode $VERSION_CODE"
else
  echo "Uploaded $AAB_PATH to draft edit $EDIT_ID for $PACKAGE_NAME track $TRACK versionCode $VERSION_CODE"
  echo "Set KOTOBA_PLAY_COMMIT=true to commit the edit."
fi
"#,
        aab = aab,
        package = plan.app_id
    )
}

fn windows_sign_script(plan: &ShellPlan) -> String {
    let exe_name = format!("{}.exe", safe_path_segment(&plan.app_name));
    format!(
        r#"#!/bin/sh
set -eu

ARTIFACT="${{1:-target/kotoba-shell/build/windows/{app}/dist/{exe_name}}}"
OUTPUT="${{2:-$ARTIFACT}}"
CERT_PATH="${{KOTOBA_WINDOWS_CERT_PATH:?set KOTOBA_WINDOWS_CERT_PATH}}"
CERT_PASS="${{KOTOBA_WINDOWS_CERT_PASS:?set KOTOBA_WINDOWS_CERT_PASS}}"
TIMESTAMP_URL="${{KOTOBA_WINDOWS_TIMESTAMP_URL:-http://timestamp.digicert.com}}"

if [ "$OUTPUT" != "$ARTIFACT" ]; then
  cp "$ARTIFACT" "$OUTPUT"
fi

if command -v signtool.exe >/dev/null 2>&1; then
  signtool.exe sign /fd SHA256 /tr "$TIMESTAMP_URL" /td SHA256 /f "$CERT_PATH" /p "$CERT_PASS" "$OUTPUT"
elif command -v signtool >/dev/null 2>&1; then
  signtool sign /fd SHA256 /tr "$TIMESTAMP_URL" /td SHA256 /f "$CERT_PATH" /p "$CERT_PASS" "$OUTPUT"
elif command -v osslsigncode >/dev/null 2>&1; then
  TMP="$OUTPUT.signed"
  osslsigncode sign -pkcs12 "$CERT_PATH" -pass "$CERT_PASS" -n "{name}" -t "$TIMESTAMP_URL" -in "$OUTPUT" -out "$TMP"
  mv "$TMP" "$OUTPUT"
else
  echo "signtool.exe, signtool, or osslsigncode is required for Authenticode signing" >&2
  exit 2
fi

echo "signed: $OUTPUT"
"#,
        app = safe_path_segment(&plan.app_name),
        exe_name = exe_name,
        name = plan.app_name
    )
}

fn windows_smartscreen_script(plan: &ShellPlan) -> String {
    let archive = format!("{}.zip", safe_path_segment(&plan.app_name));
    format!(
        r#"#!/bin/sh
set -eu

ARTIFACT="${{1:-target/kotoba-shell/release/{archive}}}"
DOWNLOAD_URL="${{KOTOBA_WINDOWS_DOWNLOAD_URL:?set KOTOBA_WINDOWS_DOWNLOAD_URL}}"

test -f "$ARTIFACT"
case "$DOWNLOAD_URL" in
  https://*) ;;
  *) echo "KOTOBA_WINDOWS_DOWNLOAD_URL must be HTTPS for SmartScreen reputation" >&2; exit 2 ;;
esac

echo "SmartScreen has no notarization equivalent."
echo "Release gate evidence to collect:"
echo "  publisher: same Authenticode subject across releases"
echo "  artifact:  $ARTIFACT"
echo "  url:       $DOWNLOAD_URL"
echo "  channel:   stable HTTPS domain, no rotating unsigned mirrors"
echo "  telemetry: first-run support reports for Windows protected your PC warnings"
"#,
        archive = archive
    )
}

fn release_checklist(plan: &ShellPlan, target: Target) -> String {
    let caps = target_capabilities(plan, target);
    let target_name = target.as_str();
    format!(
        r#"# {name} {target_name} Release Checklist

Generated from `app.kotoba.edn`.

## Required gates

- [ ] `kotoba shell check app.kotoba.edn`
- [ ] `kotoba shell build app.kotoba.edn --target {target_name}`
- [ ] `kotoba shell verify --target {target_name} <artifact-or-project>`
- [ ] `kotoba shell broker-check app.kotoba.edn --target {target_name}`
- [ ] `kotoba shell broker-check app.kotoba.edn --target {target_name} --command <capability-command> --audit-log <audit.jsonl>`
- [ ] `kotoba shell supervisor-check app.kotoba.edn --target {target_name} --run --arg <i64>` for pure safe components
- [ ] `kotoba shell supervisor-check app.kotoba.edn --target {target_name} --run --auth-grant <resource:ability> --arg <i64>` for auth host-bound safe components
- [ ] `kotoba shell supervisor-check app.kotoba.edn --target {target_name} --run --component <kqe-component>` for kqe mutate host-bound safe components
- [ ] `kotoba shell supervisor-check app.kotoba.edn --target {target_name} --run --component <kqe-component> --kqe-quad <graph,subject,predicate,object>` for kqe read/query host-bound safe components
- [ ] `kotoba shell supervisor-check app.kotoba.edn --target {target_name} --run --component <llm-component> --llm-echo` for llm host-bound safe components
- [ ] `kotoba shell adapter-check --target {target_name} --probe --smoke <release-dir>/kotoba-shell-host-adapters.json`
- [ ] `kotoba shell adapter-check --target {target_name} --hosted --probe --smoke --evidence <hosted-adapter-evidence.json> <release-dir>/kotoba-shell-host-adapters.json`
- [ ] `kotoba shell supervisor-check app.kotoba.edn --target {target_name} --run --adapter-manifest <release-dir>/kotoba-shell-host-adapters.json --kototama-app-components <release-dir>/kototama-app-components.edn --component <host-bound-component> --evidence <evidence.json>` for live production adapter-backed safe components
- [ ] `kotoba shell adapter-supervisor-check --target {target_name} --adapter-evidence <hosted-adapter-evidence.json> --supervisor-evidence <evidence.json> --evidence <adapter-supervisor-ready-evidence.json>`
- [ ] `kotoba shell plugin-check --target {target_name} --evidence <plugin-contract-evidence.json> <release-dir>/kotoba-shell-plugins.json`
- [ ] `kotoba shell plugin-sdk-check --target {target_name} --evidence <plugin-sdk-ready-evidence.json> <release-dir>/kotoba-shell-plugin-sdk.json`
- [ ] `kotoba shell plugin-load-check --target {target_name} --evidence <plugin-load-ready-evidence.json> <release-dir>/kotoba-shell-plugin-bundles.json`
- [ ] `kotoba shell compatibility-check --target {target_name} --evidence <compatibility-ready-evidence.json> <release-dir>/kotoba-shell-compatibility.json`
- [ ] `kotoba shell compatibility-migration-check --target {target_name} --previous <previous-release-dir>/kotoba-shell-compatibility.json --current <release-dir>/kotoba-shell-compatibility.json --evidence <compatibility-migration-ready-evidence.json>`
- [ ] `kotoba shell provider-contract-check app.kotoba.edn --target {target_name} --provider-oracle-manifest <release-dir>/kototama-provider-surface-policy.edn --evidence <provider-contract-evidence.json>`
- [ ] `kotoba shell surface-check --target {target_name} --provider-oracle-manifest <release-dir>/kototama-provider-surface-policy.edn --evidence <app-surface-ready-evidence.json> <release-dir>/kotoba-shell-app-surface.json`
- [ ] `kotoba shell surface-parity-check --provider-oracle-manifest <release-dir>/kototama-provider-surface-policy.edn --evidence <app-surface-parity-ready-evidence.json> <target-release-dir>/kotoba-shell-app-surface.json ...`
- [ ] `kotoba shell doctor-check --target {target_name} --probe --evidence <{target_name}-runtime-doctor-evidence.json>`
- [ ] `kotoba shell windows-runtime-contract-check <windows-project-dir> --evidence <windows-runtime-contract-ready-evidence.json>` for Windows WebView2 launch/readiness contract promotion
- [ ] `kotoba shell sdk-check --target {target_name} --evidence <sdk-evidence.json> <generated-project>` when native SDK tools are available
- [ ] `kotoba shell runtime-check --target {target_name} --evidence <runtime-evidence.json> <generated-project>` when a device/simulator is available
- [ ] `kotoba shell runtime-release-check --target {target_name} --doctor-evidence <{target_name}-runtime-doctor-evidence.json> --runtime-evidence <runtime-evidence.json> --evidence <{target_name}-runtime-ready-evidence.json>` for mobile release promotion
- [ ] `kotoba shell release-check --target {target_name} --evidence <release-metadata-ready-evidence.json> <release-dir>`
- [ ] `kotoba shell signing-check --target {target_name} --execute --evidence <signing-evidence.json> <release-dir>` when production signing credentials are available
- [ ] `kotoba shell credential-execution-check --target {target_name} --kind signing --source-evidence <signing-evidence.json> --evidence <signing-executed-evidence.json>`
- [ ] `kotoba shell submission-check --target {target_name} --execute --evidence <submission-evidence.json> <release-dir>` when notarization/store credentials are available
- [ ] `kotoba shell credential-execution-check --target {target_name} --kind submission --source-evidence <submission-evidence.json> --evidence <submission-executed-evidence.json>`
- [ ] `kotoba shell coverage --json --evidence <coverage-evidence.json>`
- [ ] `kotoba shell coverage-check --min-functional 70 --min-release-maturity 45 --evidence <coverage-check-evidence.json>`
- [ ] `kotoba shell kototama-wasm-check <release-dir>/kototama-selfhost-analyzer.edn --evidence <kototama-wasm-ready-evidence.edn>`
- [ ] `kotoba shell kototama-app-components-check <release-dir>/kototama-app-components.edn --evidence <kototama-app-components-ready-evidence.edn>`
- [ ] Review `kotoba-shell-evidence-profile.edn`
- [ ] `kotoba shell selfhost-profile-check <release-dir>/kotoba-shell-evidence-profile.edn --profile-oracle-manifest <release-dir>/kototama-shell-evidence-profile.edn --evidence <selfhost-profile-ready-evidence.edn>`
- [ ] `kotoba shell evidence-check <evidence-dir> --profile-file <release-dir>/kotoba-shell-evidence-profile.edn --profile release --evidence <summary.edn>`
- [ ] `kotoba shell updater-finalize --target {target_name} <release-dir>/kotoba-shell-updater-manifest.json --artifact <artifact> --url <url> --signature-file <signature>`
- [ ] `kotoba shell updater-check --target {target_name} --evidence <updater-ready-evidence.json> <release-dir>/kotoba-shell-updater-manifest.json`
- [ ] `kotoba shell updater-channel-check --target {target_name} --evidence <updater-channel-ready-evidence.json> <release-dir>/kotoba-shell-updater-channel.json`
- [ ] `kotoba shell updater-ui-check --target {target_name} --evidence <updater-ui-ready-evidence.json> <release-dir>/kotoba-shell-updater-ui.json`
- [ ] `kotoba shell updater-bundle-check --target {target_name} --updater-evidence <updater-ready-evidence.json> --evidence <updater-bundle-ready-evidence.json>`
- [ ] `kotoba shell updater-install-check --target {target_name} --updater-evidence <updater-ready-evidence.json> --staging-dir <updater-install-stage> --evidence <updater-install-ready-evidence.json>`
- [ ] `kotoba shell updater-publication-check --target {target_name} --updater-evidence <updater-ready-evidence.json> --evidence <updater-published-evidence.json>`
- [ ] `kotoba shell updater-feed-check --target {target_name} --updater-evidence <updater-ready-evidence.json> --feed-file <release-dir>/kotoba-shell-updater-manifest.json --feed-url <https-updater-feed-url> --evidence <updater-feed-ready-evidence.json>`
- [ ] Review `kotoba-shell-release.json`
- [ ] Review `kotoba-shell-permissions.json`
- [ ] Review `aiueos-shell-surface.json`
- [ ] Confirm safe Kotoba component policies are minimal and accepted
- [ ] Confirm store permission disclosures match native capabilities

## Target capabilities

{caps}

## Remaining manual gates

- Passing SDK compiler/device build
- Production signing identity
- Store submission account credentials
- Notarization or store review upload
- Updater channel URL and signature material
"#,
        name = plan.app_name,
        target_name = target_name,
        caps = caps
            .iter()
            .map(|c| format!("- `{c}`"))
            .collect::<Vec<_>>()
            .join("\n")
    )
}

fn aiueos_portable_plan_json(plan: &ShellPlan, target: Target) -> Result<String> {
    let target_triple = match target {
        Target::Macos => "aarch64-apple-darwin",
        Target::Windows => "x86_64-pc-windows-msvc",
        Target::Ios | Target::Android => "unsupported-mobile-target",
    };
    let archive_ext = match target {
        Target::Windows => "zip",
        _ => "zip",
    };
    let manifest = serde_json::json!({
        "schema": "aiueos.portable-plan.v0",
        "appId": plan.app_id,
        "appName": plan.app_name,
        "target": target.as_str(),
        "targetTriple": target_triple,
        "source": {
            "env": "AIUEOS_DIR",
            "defaultRelativeToKotoba": "../aiueos"
        },
        "flavors": {
            "core": {
                "cargoArgs": ["build", "--release", "--locked", "--no-default-features"],
                "purpose": "verify/inspect/check/audit without embedded wasm-runtime",
                "archive": format!("{}-aiueos-core-{target}.{}", safe_path_segment(&plan.app_name), archive_ext, target = target.as_str())
            },
            "runner": {
                "cargoArgs": ["build", "--release", "--locked"],
                "purpose": "run/up Wasm components with embedded wasm-runtime; no global wasmtime or Node install",
                "archive": format!("{}-aiueos-runner-{target}.{}", safe_path_segment(&plan.app_name), archive_ext, target = target.as_str())
            }
        },
        "security": match target {
            Target::Macos => serde_json::json!({
                "required": ["codesign", "notarytool", "stapler"],
                "gate": "Developer ID signing + notarization + staple"
            }),
            Target::Windows => serde_json::json!({
                "required": ["Authenticode signature", "timestamp", "stable HTTPS download URL"],
                "gate": "SmartScreen reputation evidence"
            }),
            Target::Ios | Target::Android => serde_json::json!({
                "required": [],
                "gate": "not generated for mobile targets"
            }),
        }
    });
    serde_json::to_string_pretty(&manifest).map_err(Into::into)
}

fn aiueos_portable_build_script(plan: &ShellPlan, target: Target, runner: bool) -> String {
    let target_triple = match target {
        Target::Macos => "aarch64-apple-darwin",
        Target::Windows => "x86_64-pc-windows-msvc",
        Target::Ios | Target::Android => "unsupported-mobile-target",
    };
    let flavor = if runner { "runner" } else { "core" };
    let feature_args = if runner {
        "[]"
    } else {
        "[\"--no-default-features\"]"
    };
    let exe = if target == Target::Windows {
        "aiueos.exe"
    } else {
        "aiueos"
    };
    let template = r##"#!/usr/bin/env bb
(require '[babashka.fs :as fs]
         '[babashka.process :refer [shell]]
         '[clojure.java.io :as io]
         '[clojure.string :as str])

(def target-default "__TARGET_TRIPLE__")
(def flavor "__FLAVOR__")
(def app "__APP__")
(def exe "__EXE__")
(def feature-args __FEATURE_ARGS__)

(defn env [k default]
  (let [v (System/getenv k)]
    (if (str/blank? v) default v)))

(def script-dir (fs/parent (fs/absolutize *file*)))
(def git-root
  (let [result (shell {:out :string :err :string :continue true}
                      "git" "-C" (str script-dir) "rev-parse" "--show-toplevel")]
    (when (zero? (:exit result))
      (str/trim (:out result)))))
(def kotoba-dir (env "KOTOBA_DIR" (or git-root (str (fs/absolutize ".")))))
(def aiueos-dir (fs/path (env "AIUEOS_DIR" (str (fs/path kotoba-dir ".." "aiueos")))))
(def target (env "AIUEOS_TARGET" target-default))
(def out-root (fs/path (env "KOTOBA_AIUEOS_DIST" "target/kotoba-shell/aiueos-portable")))

(when-not (fs/regular-file? (fs/path aiueos-dir "Cargo.toml"))
  (binding [*out* *err*]
    (println "AIUEOS_DIR does not point to an aiueos checkout:" (str aiueos-dir)))
  (System/exit 2))

(apply shell {:dir (str aiueos-dir)}
       (concat ["cargo" "build" "--release" "--locked" "--target" target] feature-args))

(def dist (fs/path out-root (str app "-aiueos-" flavor "-" target)))
(when (fs/exists? dist)
  (fs/delete-tree dist))
(fs/create-dirs (fs/path dist "bin"))
(fs/create-dirs (fs/path dist "app"))
(fs/create-dirs (fs/path dist "state"))
(fs/copy (fs/path aiueos-dir "target" target "release" exe)
         (fs/path dist "bin" exe)
         {:replace-existing true})

(spit (str (fs/path dist "README.md"))
      (str "# " app " aiueos " flavor "\n\n"
           "Target: " target "\n"
           "Flavor: " flavor "\n\n"
           "core: verify/inspect/check/audit without embedded wasm-runtime.\n"
           "runner: run/up Wasm components with embedded wasm-runtime.\n"))

(def archive-name (str app "-aiueos-" flavor "-" target ".zip"))
(fs/create-dirs out-root)
(shell {:dir (str out-root)} "zip" "-qr" archive-name (fs/file-name dist))
(println (str (fs/path out-root archive-name)))
"##;
    template
        .replace("__TARGET_TRIPLE__", target_triple)
        .replace("__FLAVOR__", flavor)
        .replace("__APP__", &safe_path_segment(&plan.app_name))
        .replace("__FEATURE_ARGS__", feature_args)
        .replace("__EXE__", exe)
}

fn updater_manifest_json(plan: &ShellPlan, target: Target) -> Result<String> {
    let manifest = serde_json::json!({
        "schema": "kotoba-shell.updater.v0",
        "appId": plan.app_id,
        "appName": plan.app_name,
        "target": target.as_str(),
        "version": "0.1.0",
        "channel": "dev",
        "artifact": {
            "fileName": match target {
                Target::Macos => format!("{}.zip", safe_path_segment(&plan.app_name)),
                Target::Ios => format!("{}.ipa", safe_path_segment(&plan.app_name)),
                Target::Android => format!("{}.aab", safe_path_segment(&plan.app_name)),
                Target::Windows => format!("{}.zip", safe_path_segment(&plan.app_name)),
            },
            "sha256": serde_json::Value::Null,
            "signature": serde_json::Value::Null,
            "url": serde_json::Value::Null,
        },
        "requirements": {
            "verifyBeforeInstall": true,
            "aiueosSurfaceContract": "aiueos-shell-surface.json",
            "permissionsContract": "kotoba-shell-permissions.json"
        }
    });
    serde_json::to_string_pretty(&manifest).map_err(Into::into)
}

fn apple_store_metadata_json(plan: &ShellPlan, target: Target) -> Result<String> {
    let caps = target_capabilities(plan, target);
    let manifest = serde_json::json!({
        "schema": "kotoba-shell.apple-store.v0",
        "appId": plan.app_id,
        "appName": plan.app_name,
        "target": target.as_str(),
        "bundleId": plan.app_id,
        "version": "0.1.0",
        "reviewNotes": {
            "capabilityModel": "kotoba-shell capabilities are declared in app.kotoba.edn and exported in kotoba-shell-permissions.json",
            "aiueosSurface": "aiueos-shell-surface.json",
            "safeCljAdmission": "safe components are admitted before packaging"
        },
        "privacy": {
            "usesNetwork": caps.iter().any(|c| is_network_capability(c)),
            "usesClipboard": caps.iter().any(|c| is_clipboard_capability(c)),
            "usesContacts": caps.iter().any(|c| is_contacts_capability(c)),
            "usesCalendar": caps.iter().any(|c| is_calendar_capability(c)),
            "usesNotifications": caps.iter().any(|c| c == "notify/show"),
            "usesKeychain": caps.iter().any(|c| is_keychain_capability(c))
        }
    });
    serde_json::to_string_pretty(&manifest).map_err(Into::into)
}

