    #[test]
    fn app_surface_parity_check_requires_matching_bridge_and_provider_commands() {
        let root = unique_test_dir("app-surface-parity-check");
        std::fs::create_dir_all(&root).unwrap();
        let manifest = parse_manifest(
            r#"
            {:kotoba.app/id "jp.co.gftd.surface"
             :kotoba.app/name "surface"
             :ui {:kind :cljs :entry "src/app.cljs"}
             :capabilities {:clipboard/read {:platforms #{:macos :ios :android :windows}}
                            :clipboard/write {:platforms #{:macos :ios :android :windows}}
                            :notify/show {:platforms #{:macos :ios :android :windows}}}
             :targets #{:macos :ios :android :windows}}
            "#,
        )
        .unwrap();
        let plan = plan_manifest(root.join("app.kotoba.edn"), &root, manifest).unwrap();
        let macos = root.join("macos-app-surface.json");
        let ios = root.join("ios-app-surface.json");
        let android = root.join("android-app-surface.json");
        let windows = root.join("windows-app-surface.json");
        std::fs::write(
            &macos,
            app_surface_manifest_json(&plan, Target::Macos).unwrap(),
        )
        .unwrap();
        std::fs::write(&ios, app_surface_manifest_json(&plan, Target::Ios).unwrap()).unwrap();
        std::fs::write(
            &android,
            app_surface_manifest_json(&plan, Target::Android).unwrap(),
        )
        .unwrap();
        std::fs::write(
            &windows,
            app_surface_manifest_json(&plan, Target::Windows).unwrap(),
        )
        .unwrap();
        let required = [Target::Macos, Target::Ios, Target::Android, Target::Windows];
        let passed = app_surface_parity_check_manifests(
            &[macos.clone(), ios.clone(), android.clone(), windows.clone()],
            &required,
        )
        .unwrap();
        assert_eq!(passed.schema, "kotoba-shell.app-surface-parity-check.v0");
        assert_eq!(passed.status, SdkCheckStatus::Passed);
        assert!(passed
            .checks
            .contains(&"required-target:windows".to_string()));
        assert!(passed
            .checks
            .contains(&"bridge:macos:window.kotobaShell.invoke".to_string()));
        assert!(passed
            .checks
            .contains(&"provider-surface-oracle:compiled-component".to_string()));
        assert!(passed
            .checks
            .contains(&"provider-surface-oracle:provider-contract-score:81302".to_string()));
        assert!(passed.commands.contains(&"clipboard/read-text".to_string()));
        assert!(passed
            .commands
            .contains(&"clipboard/write-text".to_string()));
        assert!(passed.commands.contains(&"notify/show".to_string()));

        let missing_windows = app_surface_parity_check_manifests(
            &[macos.clone(), ios.clone(), android.clone()],
            &required,
        )
        .unwrap();
        assert_eq!(missing_windows.status, SdkCheckStatus::Failed);
        assert!(missing_windows
            .missing
            .contains(&"required app surface target is missing: windows".to_string()));

        let mut bad_json = read_evidence_json(&android).unwrap();
        if let Some(providers) = bad_json
            .pointer_mut("/capabilityBindings/providers")
            .and_then(|value| value.as_array_mut())
        {
            providers.pop();
        }
        std::fs::write(&android, serde_json::to_string_pretty(&bad_json).unwrap()).unwrap();
        let failed =
            app_surface_parity_check_manifests(&[macos, ios, android, windows], &required).unwrap();
        assert_eq!(failed.status, SdkCheckStatus::Failed);
        assert!(failed
            .missing
            .iter()
            .any(|missing| missing.contains("command set differs")));

        let _ = std::fs::remove_dir_all(root);
    }

