    #[test]
    fn updater_feed_check_requires_matching_feed_body() {
        let root = unique_test_dir("updater-feed-evidence");
        std::fs::create_dir_all(&root).unwrap();
        let manifest = root.join("kotoba-shell-updater-manifest.json");
        let manifest_json = serde_json::json!({
            "schema": "kotoba-shell.updater.v0",
            "appId": "jp.co.gftd.demo",
            "target": "android",
            "version": "0.1.0",
            "channel": "stable",
            "requirements": {
                "verifyBeforeInstall": true,
                "aiueosSurfaceContract": "aiueos-shell-surface.json",
                "permissionsContract": "kotoba-shell-permissions.json"
            },
            "artifact": {
                "fileName": "app.aab",
                "sha256": "aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa",
                "signature": "sig",
                "url": "https://updates.gftd.co.jp/app.aab"
            }
        });
        std::fs::write(
            &manifest,
            serde_json::to_string_pretty(&manifest_json).unwrap(),
        )
        .unwrap();
        let evidence = root.join("updater-ready-evidence.json");
        std::fs::write(
            &evidence,
            format!(
                r#"{{"schema":"kotoba-shell.updater-check.v0","target":"android","manifest":{},"status":"Passed","checks":[],"missing":[],"detail":"ready"}}"#,
                serde_json::to_string(&manifest.display().to_string()).unwrap()
            ),
        )
        .unwrap();

        let passed = updater_feed_evidence_check(
            Target::Android,
            &evidence,
            Some(&manifest),
            None,
            Duration::from_secs(1),
        )
        .unwrap();
        assert_eq!(passed.schema, "kotoba-shell.updater-feed-check.v0");
        assert_eq!(passed.status, SdkCheckStatus::Passed);
        assert!(passed
            .checks
            .contains(&"updater-feed:file:/artifact/sha256:matches".to_string()));

        let bad_feed = root.join("bad-feed.json");
        let mut bad_json = manifest_json;
        bad_json["artifact"]["sha256"] =
            serde_json::json!("bbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbb");
        std::fs::write(&bad_feed, serde_json::to_string_pretty(&bad_json).unwrap()).unwrap();
        let failed = updater_feed_evidence_check(
            Target::Android,
            &evidence,
            Some(&bad_feed),
            None,
            Duration::from_secs(1),
        )
        .unwrap();
        assert_eq!(failed.status, SdkCheckStatus::Failed);
        assert!(failed
            .missing
            .iter()
            .any(|missing| missing.contains("/artifact/sha256")));

        let _ = std::fs::remove_dir_all(root);
    }

