                r#"{{"schema":"kotoba-shell.updater.v0","target":"android","requirements":{{"verifyBeforeInstall":true,"aiueosSurfaceContract":"aiueos-shell-surface.json","permissionsContract":"kotoba-shell-permissions.json"}},"artifact":{{"fileName":"app.aab","sha256":"{sha}","signature":"sig","url":"https://updates.gftd.co.jp/app.aab"}}}}"#
