    #[test]
    fn runtime_release_evidence_check_rejects_dry_run_runtime() {
        let root = unique_test_dir("runtime-release-evidence");
        std::fs::create_dir_all(&root).unwrap();
        let doctor = root.join("android-runtime-doctor-evidence.json");
        let runtime = root.join("android-runtime-evidence.json");
        std::fs::write(
            &doctor,
            r#"{"schema":"kotoba-shell.runtime-doctor.v0","target":"android","status":"Passed","checks":["adb"],"missing":[],"remediation":[],"remediation_commands":[],"detail":"doctor ready","command":[],"stdout":"","stderr":""}"#,
        )
        .unwrap();
        std::fs::write(
            &runtime,
            r#"{"schema":"kotoba-shell.runtime-check.v0","target":"android","project_dir":".","status":"Skipped","command":[],"detail":"runtime check dry-run requested with zero timeout","stdout":"","stderr":""}"#,
        )
        .unwrap();
        let failed = runtime_release_evidence_check(Target::Android, &doctor, &runtime).unwrap();
        assert_eq!(failed.status, SdkCheckStatus::Failed);
        assert!(failed
            .missing
            .contains(&"runtime status is Skipped, expected Passed".to_string()));
        assert!(failed
            .missing
            .contains(&"runtime evidence is a dry-run".to_string()));

        std::fs::write(
            &runtime,
            r#"{"schema":"kotoba-shell.runtime-check.v0","target":"android","project_dir":".","status":"Passed","command":["/bin/sh","-c","launch"],"detail":"SDK command exited with status exit status: 0","stdout":"kotoba-shell-runtime:ready-log\nKOTOBA_SHELL_READY","stderr":""}"#,
        )
        .unwrap();
        let passed = runtime_release_evidence_check(Target::Android, &doctor, &runtime).unwrap();
        assert_eq!(passed.status, SdkCheckStatus::Passed);
        assert!(passed.checks.contains(&"runtime:ready-marker".to_string()));

        let macos_doctor = root.join("macos-runtime-doctor-evidence.json");
        let macos_runtime = root.join("macos-runtime-evidence.json");
        std::fs::write(
            &macos_doctor,
            r#"{"schema":"kotoba-shell.runtime-doctor.v0","target":"macos","status":"Passed","checks":["swift"],"missing":[],"remediation":[],"remediation_commands":[],"detail":"doctor ready","command":[],"stdout":"","stderr":""}"#,
        )
        .unwrap();
        std::fs::write(
            &macos_runtime,
            r#"{"schema":"kotoba-shell.runtime-check.v0","target":"macos","project_dir":".","status":"Passed","command":["/bin/sh","-c","launch"],"detail":"SDK command exited with status exit status: 0","stdout":"KOTOBA_SHELL_READY macos app","stderr":""}"#,
        )
        .unwrap();
        let macos_failed =
            runtime_release_evidence_check(Target::Macos, &macos_doctor, &macos_runtime).unwrap();
        assert_eq!(macos_failed.status, SdkCheckStatus::Failed);
        assert!(macos_failed
            .missing
            .iter()
            .any(|missing| missing.contains("KOTOBA_SHELL_SURFACE_READY")));
        std::fs::write(
            &macos_runtime,
            r#"{"schema":"kotoba-shell.runtime-check.v0","target":"macos","project_dir":".","status":"Passed","command":["/bin/sh","-c","launch"],"detail":"SDK command exited with status exit status: 0","stdout":"KOTOBA_SHELL_READY macos app\nKOTOBA_SHELL_SURFACE_READY macos app menu tray lifecycle","stderr":""}"#,
        )
        .unwrap();
        let macos_passed =
            runtime_release_evidence_check(Target::Macos, &macos_doctor, &macos_runtime).unwrap();
        assert_eq!(macos_passed.status, SdkCheckStatus::Passed);
        assert!(macos_passed
            .checks
            .contains(&"runtime:app-surface-ready-marker".to_string()));

        let _ = std::fs::remove_dir_all(root);
    }

    #[test]
    fn credential_execution_evidence_check_rejects_ready_only_reports() {
        let root = unique_test_dir("credential-execution-evidence");
        std::fs::create_dir_all(&root).unwrap();
        let signing = root.join("signing-ready-evidence.json");
        std::fs::write(
            &signing,
            r#"{"schema":"kotoba-shell.signing-check.v0","target":"android","dir":".","status":"Passed","checks":[],"missing_credentials":[],"command":[],"detail":"credential-backed signing execution is ready; use --execute to run the target signing helper","stdout":"","stderr":""}"#,
        )
        .unwrap();
        let failed = credential_execution_evidence_check(
            Target::Android,
            CredentialExecutionKind::Signing,
            &signing,
        )
        .unwrap();
        assert_eq!(failed.status, SdkCheckStatus::Failed);
        assert!(failed
            .missing
            .contains(&"signing evidence has no executed command".to_string()));
        assert!(failed
            .missing
            .contains(&"signing evidence is not an executed helper run".to_string()));

        std::fs::write(
            &signing,
            r#"{"schema":"kotoba-shell.signing-check.v0","target":"android","dir":".","status":"Passed","checks":[],"missing_credentials":[],"command":["./sign-android.sh","app.aab"],"detail":"signing command exited with status exit status: 0","stdout":"signed","stderr":""}"#,
        )
        .unwrap();
        let passed = credential_execution_evidence_check(
            Target::Android,
            CredentialExecutionKind::Signing,
            &signing,
        )
        .unwrap();
        assert_eq!(passed.status, SdkCheckStatus::Passed);
        assert!(passed
            .checks
            .contains(&"signing:executed-helper".to_string()));

        let _ = std::fs::remove_dir_all(root);
    }

    #[test]
    fn credential_execution_evidence_check_links_artifact_to_command() {
        let root = unique_test_dir("credential-execution-artifact");
        std::fs::create_dir_all(&root).unwrap();
        let artifact = root.join("app-release.aab");
        std::fs::write(&artifact, "signed").unwrap();
        let other_artifact = root.join("other-release.aab");
        std::fs::write(&other_artifact, "other").unwrap();
        let signing = root.join("signing-executed-source.json");
        std::fs::write(
            &signing,
            format!(
                r#"{{"schema":"kotoba-shell.signing-check.v0","target":"android","dir":".","status":"Passed","checks":[],"missing_credentials":[],"command":["./sign-android.sh","{}"],"detail":"signing command exited with status exit status: 0","stdout":"signed","stderr":""}}"#,
                artifact.display()
            ),
        )
        .unwrap();
        let passed = credential_execution_evidence_check_with_artifacts(
            Target::Android,
            CredentialExecutionKind::Signing,
            &signing,
            Some(&artifact),
            None,
        )
        .unwrap();
        assert_eq!(passed.status, SdkCheckStatus::Passed);
        assert_eq!(passed.artifact.as_deref(), Some(artifact.as_path()));
        assert!(passed
            .checks
            .iter()
            .any(|check| check.starts_with("signing:artifact:exists:")));
        assert!(passed
            .checks
            .iter()
            .any(|check| check.starts_with("signing:artifact:command-arg:")));

        let failed = credential_execution_evidence_check_with_artifacts(
            Target::Android,
            CredentialExecutionKind::Signing,
            &signing,
            Some(&other_artifact),
            None,
        )
        .unwrap();
        assert_eq!(failed.status, SdkCheckStatus::Failed);
        assert!(failed
            .missing
            .iter()
            .any(|missing| missing.contains("command does not reference artifact")));

        let _ = std::fs::remove_dir_all(root);
    }

    #[test]
    fn plugin_load_check_requires_signed_hashed_manifest_gated_bundles() {
        let root = unique_test_dir("plugin-load-evidence");
        std::fs::create_dir_all(&root).unwrap();
        let manifest = parse_manifest(
            r#"
            {:kotoba.app/id "jp.co.gftd.demo"
             :kotoba.app/name "demo"
             :capabilities {:ledger/append {:platforms #{:android}}}
             :targets #{:android}}
            "#,
        )
        .unwrap();
        let plan = plan_manifest(root.join("app.kotoba.edn"), &root, manifest).unwrap();
        let bundles = root.join("kotoba-shell-plugin-bundles.json");
        write_plugin_bundle_artifacts(&root).unwrap();
        std::fs::write(
            &bundles,
            plugin_bundle_manifest_json(&plan, Target::Android, &root).unwrap(),
        )
        .unwrap();
        let passed = plugin_load_check_manifest(Target::Android, &bundles).unwrap();
        assert_eq!(passed.schema, "kotoba-shell.plugin-load-check.v0");
        assert_eq!(passed.status, SdkCheckStatus::Passed);
        assert!(passed.commands.contains(&"example/echo".to_string()));
        assert!(passed
            .checks
            .iter()
            .any(|check| check.contains("artifact:file:")));
        assert!(passed
            .checks
            .contains(&"bundles[0]:artifact:signatureFile".to_string()));
        assert!(passed
            .checks
            .contains(&"bundles[0]:sandbox:wasmtime-compile".to_string()));
        assert!(passed
            .checks
            .contains(&"bundles[0]:sandbox:wasmtime-instantiate".to_string()));
        assert!(passed
            .checks
            .contains(&"bundles[0]:sandbox:imports:1".to_string()));
        assert!(passed
            .checks
            .contains(&"bundles[0]:sandbox:exports:1".to_string()));
        assert!(passed
            .checks
            .contains(&"bundles[0]:sandbox:host-import:env.kotoba_host_audit".to_string()));
        assert!(passed
            .checks
            .contains(&"bundles[0]:sandbox:command:example/echo".to_string()));
        assert!(passed
            .checks
            .contains(&"bundles[0]:sandbox:export:example_echo".to_string()));
        assert!(passed
            .checks
            .contains(&"bundles[0]:sandbox:invoke:example_echo:41".to_string()));
        assert!(passed
            .checks
            .contains(&"bundles[0]:sandbox:host-audit-calls:1".to_string()));

        std::fs::write(
            root.join("plugins/external-example-echo/plugin.wasm"),
            b"not wasm",
        )
        .unwrap();
        let bad_wasm = plugin_load_check_manifest(Target::Android, &bundles).unwrap();
        assert_eq!(bad_wasm.status, SdkCheckStatus::Failed);
        assert!(bad_wasm
            .missing
            .iter()
            .any(|missing| missing.contains("sha256 mismatch")));

        write_plugin_bundle_artifacts(&root).unwrap();
        std::fs::write(
            &bundles,
            r#"{"schema":"kotoba-shell.plugin-bundles.v0","target":"android","loader":{"enabled":true,"mode":"manifest-gated","abiVersion":"kotoba-shell-plugin-abi-0","pluginManifestSchema":"kotoba-shell.external-plugin.v0","requireSignature":false,"requireSha256":true,"permissionModel":"allow-all"},"bundles":[{"schema":"kotoba-shell.external-plugin.v0","id":"external/bad","version":"0.1.0","abiVersion":"kotoba-shell-plugin-abi-0","targets":["android"],"commands":["bad"],"permission":{"mode":"allow-all"},"artifact":{"fileName":"bad.wasm","sha256":"bad","signature":""}}]}"#,
        )
        .unwrap();
        let failed = plugin_load_check_manifest(Target::Android, &bundles).unwrap();
        assert_eq!(failed.status, SdkCheckStatus::Failed);
        assert!(failed
            .missing
            .iter()
            .any(|missing| missing.contains("requireSignature")));
        assert!(failed
            .missing
            .iter()
            .any(|missing| missing.contains("permission")));
        assert!(failed
            .missing
            .iter()
            .any(|missing| missing.contains("sha256")));

        let _ = std::fs::remove_dir_all(root);
    }

    #[test]
    fn adapter_supervisor_evidence_check_requires_hosted_smoke_and_live_events() {
        let root = unique_test_dir("adapter-supervisor-evidence");
        std::fs::create_dir_all(&root).unwrap();
        let adapter = root.join("hosted-adapter-ready-evidence.json");
        let supervisor = root.join("live-adapter-supervisor-evidence.json");
        std::fs::write(
            &adapter,
            r#"{"schema":"kotoba-shell.adapter-check.v0","target":"android","status":"Passed","checks":["adapter:llm:hosted:https:updates.example.invalid","adapter:llm:probe:ok","adapter:llm:smoke:ok"],"missing":[],"detail":"adapter ready"}"#,
        )
        .unwrap();
        std::fs::write(
            &supervisor,
            format!(
                r#"{{"schema":"kotoba-shell.supervisor-check.v0","target":"android","app_id":"jp.co.gftd.demo","status":"Passed","checks":[],"components":[],"dry_run":{{"component":"llm-agent","function":"reply-len","args":[],"status":"Passed","wasm_source":"kototama artifact /release/kototama/components/llm-agent.wasm","admission_gate":"selfhost/kotoba","analyzer_abi":"{}","analyzer_component_sha256":"3333333333333333333333333333333333333333333333333333333333333333","artifact_sha256":"4444444444444444444444444444444444444444444444444444444444444444","source_sha256":"5555555555555555555555555555555555555555555555555555555555555555","policy_sha256":"6666666666666666666666666666666666666666666666666666666666666666","result":9,"host_events":[{{"provider":"llm","operation":"infer","graph":"live-adapter","subject":"modelA","predicate":"prompt","object":"live:pong"}}],"detail":"ok"}},"detail":"supervisor ready"}}"#,
                kotoba_clj::selfhost::SAFE_ANALYZER_ABI
            ),
        )
        .unwrap();

        let report =
            adapter_supervisor_evidence_check(Target::Android, &adapter, &supervisor).unwrap();
        assert_eq!(report.status, SdkCheckStatus::Passed);
        assert!(report
            .checks
            .contains(&"supervisor:host-events:1".to_string()));
        assert!(report
            .checks
            .contains(&"supervisor:dry-run:kototama-artifact".to_string()));
        assert!(report.checks.contains(&format!(
            "supervisor:dry-run:selfhost-analyzer-abi:{}",
            kotoba_clj::selfhost::SAFE_ANALYZER_ABI
        )));
        assert!(report
            .checks
            .contains(&"supervisor:dry-run:selfhost-analyzer-component-sha256".to_string()));
        assert!(report
            .checks
            .contains(&"supervisor:dry-run:artifact-sha256".to_string()));
        assert!(report
            .checks
            .contains(&"supervisor:dry-run:source-sha256".to_string()));
        assert!(report
            .checks
            .contains(&"supervisor:dry-run:policy-sha256".to_string()));

        std::fs::write(
            &adapter,
            r#"{"schema":"kotoba-shell.adapter-check.v0","target":"android","status":"Passed","checks":["adapter:llm:hosted:https:updates.example.invalid"],"missing":[],"detail":"adapter incomplete"}"#,
        )
        .unwrap();
        let failed =
            adapter_supervisor_evidence_check(Target::Android, &adapter, &supervisor).unwrap();
        assert_eq!(failed.status, SdkCheckStatus::Failed);
        assert!(failed
            .missing
            .contains(&"adapter evidence missing probe: check".to_string()));
        assert!(failed
            .missing
            .contains(&"adapter evidence missing smoke: check".to_string()));

        std::fs::write(
            &adapter,
            r#"{"schema":"kotoba-shell.adapter-check.v0","target":"android","status":"Passed","checks":["adapter:llm:hosted:https:updates.example.invalid","adapter:llm:probe:ok","adapter:llm:smoke:ok"],"missing":[],"detail":"adapter ready"}"#,
        )
        .unwrap();
        std::fs::write(
            &supervisor,
            r#"{"schema":"kotoba-shell.supervisor-check.v0","target":"android","app_id":"jp.co.gftd.demo","status":"Passed","checks":[],"components":[],"dry_run":{"component":"llm-agent","function":"reply-len","args":[],"status":"Passed","wasm_source":"source compile src/llm.kotoba","result":9,"host_events":[{"provider":"llm","operation":"infer","graph":"live-adapter","subject":"modelA","predicate":"prompt","object":"live:pong"}],"detail":"ok"},"detail":"supervisor ready"}"#,
        )
        .unwrap();
        let source_compile_failed =
            adapter_supervisor_evidence_check(Target::Android, &adapter, &supervisor).unwrap();
        assert_eq!(source_compile_failed.status, SdkCheckStatus::Failed);
        assert!(source_compile_failed
            .missing
            .iter()
            .any(|entry| entry.contains("expected kototama artifact")));
        assert!(source_compile_failed
            .missing
            .iter()
            .any(|entry| entry.contains("dry_run.admission_gate")));
        assert!(source_compile_failed
            .missing
            .iter()
            .any(|entry| entry.contains("dry_run.analyzer_abi")));
        assert!(source_compile_failed
            .missing
            .iter()
            .any(|entry| entry.contains("dry_run.analyzer_component_sha256")));
        assert!(source_compile_failed
            .missing
            .iter()
            .any(|entry| entry.contains("dry_run.artifact_sha256")));
        assert!(source_compile_failed
            .missing
            .iter()
            .any(|entry| entry.contains("dry_run.source_sha256")));
        assert!(source_compile_failed
            .missing
            .iter()
            .any(|entry| entry.contains("dry_run.policy_sha256")));

        let _ = std::fs::remove_dir_all(root);
    }

