    #[test]
    fn supervisor_dry_run_prefers_shipped_kototama_artifact_when_manifest_is_provided() {
        let root = unique_test_dir("supervisor-kototama-artifact");
        std::fs::create_dir_all(root.join("src")).unwrap();
        std::fs::create_dir_all(root.join("release/kototama/components")).unwrap();
        let source = root.join("src/policy.kotoba");
        std::fs::write(&source, "(defn run [n] (+ n 1))").unwrap();
        let manifest = parse_manifest(
            r#"
            {:kotoba.app/id "jp.co.gftd.demo"
             :kotoba.app/name "demo"
             :components [{:id :policy
                           :source "src/policy.kotoba"
                           :safe true
                           :exports [run]
                           :imports []}]
             :capabilities {:notify/show {:platforms #{:macos :ios :android}}}
             :targets #{:macos :ios :android}}
            "#,
        )
        .unwrap();
        let plan = plan_manifest(root.join("app.kotoba.edn"), &root, manifest).unwrap();
        let body = std::fs::read_to_string(&source).unwrap();
        let policy = kotoba_clj::minimal_policy(&body).unwrap();
        let policy_edn = policy.to_edn();
        let wasm = kotoba_clj::compile_safe_kotoba_with_prelude(&body, &policy).unwrap();
        let wasm_sha256 = sha256_bytes_hex(&wasm);
        let source_sha256 = sha256_bytes_hex(body.as_bytes());
        let policy_sha256 = sha256_bytes_hex(policy_edn.as_bytes());
        let artifact_rel = PathBuf::from("kototama/components/policy.wasm");
        let artifact = root.join("release").join(&artifact_rel);
        std::fs::write(&artifact, &wasm).unwrap();
        let analyzer_component = kotoba_clj::selfhost::analyzer_component().unwrap();
        let analyzer_component_sha256 = sha256_bytes_hex(&analyzer_component);
        std::fs::write(
            root.join("release/kototama-selfhost-analyzer.component.wasm"),
            &analyzer_component,
        )
        .unwrap();
        let analyzer_manifest = kototama_component_manifest_json(
            "kototama-selfhost-analyzer.component.wasm",
            &analyzer_component,
        );
        std::fs::write(
            root.join("release/kototama-selfhost-analyzer.edn"),
            evidence_edn_string(&analyzer_manifest).unwrap(),
        )
        .unwrap();
        let app_contract_component =
            kotoba_clj::selfhost::app_components_contract_oracle_wasm().unwrap();
        std::fs::write(
            root.join("release/kototama-app-components-contract.component.wasm"),
            &app_contract_component,
        )
        .unwrap();
        let app_contract_manifest = kototama_component_manifest_json_with_source(
            "kototama-app-components-contract.component.wasm",
            &app_contract_component,
            "kotoba-clj/selfhost/app_components_contract.kotoba",
        );
        std::fs::write(
            root.join("release/kototama-app-components-contract.edn"),
            evidence_edn_string(&app_contract_manifest).unwrap(),
        )
        .unwrap();
        let app_component_entry = serde_json::json!({
            "id": "policy",
            "source": source.display().to_string(),
            "artifact": artifact_rel.display().to_string(),
            "admissionGate": "selfhost/kotoba",
            "analyzerAbi": kotoba_clj::selfhost::SAFE_ANALYZER_ABI,
            "bytes": wasm.len(),
            "sha256": wasm_sha256,
            "sourceSha256": source_sha256,
            "policySha256": policy_sha256,
            "capabilityImports": [],
            "exports": ["run"],
            "policy": policy_edn,
        });
        let app_components_vec = vec![app_component_entry];
        let app_components_digest = kototama_app_component_contract_digest(&app_components_vec);
        let app_components = serde_json::json!({
            "schema": "kotoba-shell.kototama-app-components.v0",
            "layer": "kotoba wasm / safe Kotoba",
            "canonicalFormat": "edn",
            "jsonRole": "interop",
            "admissionGate": "selfhost/kotoba",
            "analyzerAbi": kotoba_clj::selfhost::SAFE_ANALYZER_ABI,
            "analyzerComponent": "kototama-selfhost-analyzer.component.wasm",
            "analyzerComponentSha256": analyzer_component_sha256,
            "componentCount": 1,
            "componentContractDigest": app_components_digest,
            "components": app_components_vec,
            "checks": ["selfhost-admission-gate", "selfhost-analyzer-abi"],
        });
        let app_components_manifest = root.join("release/kototama-app-components.edn");
        std::fs::write(
            &app_components_manifest,
            evidence_edn_string(&app_components).unwrap(),
        )
        .unwrap();

        let report = supervisor_check_plan(
            &plan,
            Target::Android,
            Some(ComponentDryRunRequest {
                component: Some("policy".to_string()),
                function: Some("run".to_string()),
                args: vec![41],
                fuel: 1_000_000,
                kototama_app_components_manifest: Some(app_components_manifest),
                host_adapter_manifest: None,
                adapter_timeout_seconds: 10,
                auth_grants: Vec::new(),
                kqe_snapshot: Vec::new(),
                llm_echo: false,
                llm_responses: Vec::new(),
            }),
        )
        .unwrap();
        let dry_run = report.dry_run.unwrap();
        assert_eq!(dry_run.status, SdkCheckStatus::Passed);
        assert_eq!(dry_run.result, Some(42));
        assert!(dry_run.wasm_source.contains("kototama artifact"));
        assert_eq!(dry_run.admission_gate.as_deref(), Some("selfhost/kotoba"));
        assert_eq!(
            dry_run.analyzer_abi.as_deref(),
            Some(kotoba_clj::selfhost::SAFE_ANALYZER_ABI)
        );
        assert!(dry_run
            .analyzer_component_sha256
            .as_deref()
            .is_some_and(is_sha256_hex));
        assert_eq!(
            dry_run.analyzer_component_sha256.as_deref(),
            Some(analyzer_component_sha256.as_str())
        );
        assert_eq!(
            dry_run.artifact_sha256.as_deref(),
            Some(wasm_sha256.as_str())
        );
        assert_eq!(
            dry_run.source_sha256.as_deref(),
            Some(source_sha256.as_str())
        );
        assert_eq!(
            dry_run.policy_sha256.as_deref(),
            Some(policy_sha256.as_str())
        );

        let mut stale_analyzer = app_components.clone();
        stale_analyzer["analyzerComponentSha256"] = serde_json::Value::String(
            "ffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffff".to_string(),
        );
        let stale_analyzer_manifest = root.join("release/stale-analyzer-components.edn");
        std::fs::write(
            &stale_analyzer_manifest,
            evidence_edn_string(&stale_analyzer).unwrap(),
        )
        .unwrap();
        let stale_analyzer_report =
            kototama_app_components_check_manifest(&stale_analyzer_manifest).unwrap();
        assert_eq!(stale_analyzer_report.status, SdkCheckStatus::Failed);
        assert!(stale_analyzer_report
            .missing
            .iter()
            .any(|missing| missing.contains("analyzerComponentSha256 mismatch")));

        let mut stale_policy = app_components.clone();
        stale_policy["components"][0]["policy"] =
            serde_json::Value::String("{:graph-read []}".to_string());
        let stale_policy_manifest = root.join("release/stale-policy-components.edn");
        std::fs::write(
            &stale_policy_manifest,
            evidence_edn_string(&stale_policy).unwrap(),
        )
        .unwrap();
        let stale_policy_report =
            kototama_app_components_check_manifest(&stale_policy_manifest).unwrap();
        assert_eq!(stale_policy_report.status, SdkCheckStatus::Failed);
        assert!(stale_policy_report
            .missing
            .iter()
            .any(|missing| missing.contains("policy does not match selfhost minimal policy")));

        let forged_rel = PathBuf::from("kototama/components/forged-policy.wasm");
        let forged_artifact = root.join("release").join(&forged_rel);
        let forged_wasm = b"\0asm\x01\0\0\0";
        std::fs::write(&forged_artifact, forged_wasm).unwrap();
        let mut forged_artifact_manifest = app_components.clone();
        forged_artifact_manifest["components"][0]["artifact"] =
            serde_json::Value::String(forged_rel.display().to_string());
        forged_artifact_manifest["components"][0]["sha256"] =
            serde_json::Value::String(sha256_bytes_hex(forged_wasm));
        let forged_manifest = root.join("release/forged-artifact-components.edn");
        std::fs::write(
            &forged_manifest,
            evidence_edn_string(&forged_artifact_manifest).unwrap(),
        )
        .unwrap();
        let forged_report = kototama_app_components_check_manifest(&forged_manifest).unwrap();
        assert_eq!(forged_report.status, SdkCheckStatus::Failed);
        assert!(forged_report
            .missing
            .iter()
            .any(|missing| missing.contains("selfhost reproducible compile")));

        std::fs::write(&source, "(defn run [n] (+ n 1000))").unwrap();
        let stale_manifest = kototama_app_components_check_manifest(
            root.join("release/kototama-app-components.edn"),
        )
        .unwrap();
        assert_eq!(stale_manifest.status, SdkCheckStatus::Failed);
        assert!(stale_manifest
            .missing
            .iter()
            .any(|missing| missing.contains("sourceSha256 mismatch")));
        let stale = supervisor_check_plan(
            &plan,
            Target::Android,
            Some(ComponentDryRunRequest {
                component: Some("policy".to_string()),
                function: Some("run".to_string()),
                args: vec![41],
                fuel: 1_000_000,
                kototama_app_components_manifest: Some(
                    root.join("release/kototama-app-components.edn"),
                ),
                host_adapter_manifest: None,
                adapter_timeout_seconds: 10,
                auth_grants: Vec::new(),
                kqe_snapshot: Vec::new(),
                llm_echo: false,
                llm_responses: Vec::new(),
            }),
        )
        .expect_err("stale source must not be accepted as shipped kototama evidence");
        assert!(stale
            .to_string()
            .contains("kototama app components manifest"));

        let _ = std::fs::remove_dir_all(root);
    }

